-- Poems batch 118
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('11ace67e-7146-4c49-ac8f-d98f0ae72bf0','依韻和玉汝舟中見懷','梅堯臣','宋','宋诗','song-poetry','','[]','遥聞出舟望，始愛川原廣。',48,'全唐诗/poet.song.13000.json','["遥聞出舟望，始愛川原廣。", "春冰未破時，旋拉寒篙響。", "鳴雁似相隨，遠日聊一仰。", "能知狀物工，把筆獨見想。"]'),
('479cb342-bec7-42ce-8ba1-9047a9921f05','同道損持國訪孔旼處士','梅堯臣','宋','宋诗','song-poetry','','[]','高廬當大道，節士不肯過。',60,'全唐诗/poet.song.13000.json','["高廬當大道，節士不肯過。", "窮巷獨秉德，車馬一何多。", "勢力走諛諂，禮義服委佗。", "是以被褐人，長甘北山阿。", "曰今豈有愧，漁上有行歌。"]'),
('651edcd3-3008-49c9-8255-7a4c74a65b7d','二月十四夜霜','梅堯臣','宋','宋诗','song-poetry','','[]','欣欣東園杏，忽值春飛霜。',72,'全唐诗/poet.song.13000.json','["欣欣東園杏，忽值春飛霜。", "粲然彼繁英，萎若出沸湯。", "既能與之榮，而復使之傷。", "向來肅殺時，已共百卉黄。", "今同草吐心，不似草心長。", "天理固難測，誰要必其常。"]'),
('515023f4-b2d0-409a-928e-a4bfbe37f14a','送謝師直南陽上墳','梅堯臣','宋','宋诗','song-poetry','','[]','躍馬清明前，行將拜孤壠。',48,'全唐诗/poet.song.13000.json','["躍馬清明前，行將拜孤壠。", "松吹送悲聲，緣纓淚如湧。", "三歲宰南方，奠斝阻親捧。", "山下獨徘徊，雨來雲蓊蓊。"]'),
('5afbc8ec-cb84-4d12-8475-020aba4cbaa2','累日文符沓至悵然有感三首  其一','陸游','宋','宋诗','song-poetry','','[]','豪氣人言苦不除，固應屏迹向江湖。',64,'全唐诗/poet.song.130000.json','["豪氣人言苦不除，固應屏迹向江湖。", "封侯萬里獨心在，餬口四方何事無。", "薄俗更堪開眼看，老翁寧辦折腰趨。", "鼠肝蟲臂今無擇，付與乾坤造化爐。"]'),
('6cf98d35-1f10-4d4d-a4e5-f5da8a5452e9','累日文符沓至悵然有感三首  其二','陸游','宋','宋诗','song-poetry','','[]','白首逢人只累欷，今雖未是昨真非。',64,'全唐诗/poet.song.130000.json','["白首逢人只累欷，今雖未是昨真非。", "文章才盡欲焚稿，仕宦興闌當拂衣。", "浪出自應爲後戒，放言那計墮危機。", "遼天華表蒼茫裏，千載何人識令威。"]'),
('e3b137d9-eecd-402e-a52b-e30f2bd5e744','累日文符沓至悵然有感三首  其三','陸游','宋','宋诗','song-poetry','','[]','三十年爲一世人，孤城夢斷洛陽塵。',64,'全唐诗/poet.song.130000.json','["三十年爲一世人，孤城夢斷洛陽塵。", "強顔懶復看人面，何地真堪著此身。", "白骨久埋金谷友，黄花尚醉葛天民。", "嚴光釣瀨雖亡恙，除却江山萬事新。"]'),
('4beb6c3e-c56f-4606-9a0b-0457051db3b0','大風','陸游','宋','宋诗','song-poetry','','[]','初聞澒洞怒濤翻，徐聽驂驔戰馬奔。',32,'全唐诗/poet.song.130000.json','["初聞澒洞怒濤翻，徐聽驂驔戰馬奔。", "紙帳蒲團坐清夜，恍如身在若耶村。"]'),
('38231678-2f34-4e6f-ae23-20beb063ace3','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','退食淡無事，一窗寛有餘。',48,'全唐诗/poet.song.130000.json','["退食淡無事，一窗寛有餘。", "重尋總角夢，却對短檠書。", "功業雖蹉跌，光陰且破除。", "更須求半偈，回向此心初。"]'),
('dfa956ca-d587-40a3-87db-1e250d9201f9','再用前韵不以次','陸游','宋','宋诗','song-poetry','','[]','壯心雖迫老，吏責未妨書。',48,'全唐诗/poet.song.130000.json','["壯心雖迫老，吏責未妨書。", "言議思公瑾，英雄陋本初。", "移燈近床榻，聽雨落堦除。", "回首山南戍，流年一紀餘。"]'),
('33f4bd85-d67d-4d2b-ae62-336365a14013','思歸','陸游','宋','宋诗','song-poetry','','[]','短髮今年雪滿巾，一杯且醉瓮中春。',64,'全唐诗/poet.song.130000.json','["短髮今年雪滿巾，一杯且醉瓮中春。", "定無術致長生藥，那得愁供有限身。", "碎枕不求名利夢，挽河盡洗簿書塵。", "江湖意決君知否，致主唐虞自有人。"]'),
('c331ed19-5132-474b-a3aa-54bd10b2ccdc','喜小兒病愈二首  其一','陸游','宋','宋诗','song-poetry','','[]','喜見吾家玉雪兒，今朝竹馬遶廊嬉。',32,'全唐诗/poet.song.130000.json','["喜見吾家玉雪兒，今朝竹馬遶廊嬉。", "也知笠澤家風在，十歲能吟病起詩。"]'),
('c0eb4e5c-17a2-4935-b0d2-229dde296c3b','喜小兒病愈二首  其二','陸游','宋','宋诗','song-poetry','','[]','一床共置朝回笏，百屋常堆用剩錢。',32,'全唐诗/poet.song.130000.json','["一床共置朝回笏，百屋常堆用剩錢。", "何似吾家好兒子，吟哦相伴短檠前。"]'),
('9b483671-f6c4-4a3b-9bc3-be041b1b15cc','初冬風雨驟寒作短歌','陸游','宋','宋诗','song-poetry','','[]','東園日淡雲容薄，綸巾朝暮闌干角。',128,'全唐诗/poet.song.130000.json','["東園日淡雲容薄，綸巾朝暮闌干角。", "北風動地萬木號，不料一寒如此惡。", "豈惟半夜雨打窗，便恐朙朝雪平壑。", "綠酒雖漓亦復醉，皁貂己弊猶堪著。", "所嗟此身老益窮，蹭蹬無功上麟閣。", "久從漁艇寄江湖，坐看烟塵暗幽朔。", "萬鞭枯胔憤未平，纛下老酋何足縛。", "要及今年墮指寒，夜擁雕戈度窮漠。"]'),
('ed01c1a3-ca85-4fc4-b887-bc72ba84a818','余年二十時嘗作菊枕詩頗傳於人今秋偶復采菊縫枕囊悽然有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','采得黄花作枕囊，曲屏深幌閟幽香。',32,'全唐诗/poet.song.130000.json','["采得黄花作枕囊，曲屏深幌閟幽香。", "喚回四十三年夢，燈暗無人說斷腸。"]'),
('7f5bb24a-5264-421b-9b36-1c831d3f5e53','余年二十時嘗作菊枕詩頗傳於人今秋偶復采菊縫枕囊悽然有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','少日曾題菊枕詩，蠧編殘稿鎖蛛絲。',32,'全唐诗/poet.song.130000.json','["少日曾題菊枕詩，蠧編殘稿鎖蛛絲。", "人間萬事消磨盡，只有清香似舊時。"]'),
('51abbcc4-73cf-4e1e-873c-c1059e3b6956','陶淵明云三徑就荒松菊猶存蓋以菊配松也余讀而感之因賦此詩','陸游','宋','宋诗','song-poetry','','[]','菊花如端人，獨立凌冰霜。',72,'全唐诗/poet.song.130000.json','["菊花如端人，獨立凌冰霜。", "名紀先秦書，功標列仙方。", "紛紛零落中，見此數枝黄。", "高情守幽貞，大節凜介剛。", "乃知淵明意，不爲汎酒觴。", "折嗅三嘆息，歲晚彌芬芳。"]'),
('25409b7f-ce3d-4176-8afb-50e3402affe6','蕎麥初熟刈者滿野喜而有作','陸游','宋','宋诗','song-poetry','','[]','城南城北如鋪雪，原野家家種蕎麥。',96,'全唐诗/poet.song.130000.json','["城南城北如鋪雪，原野家家種蕎麥。", "霜晴收斂少在家，餅餌今冬不憂窄。", "胡麻壓油油更香，油新餅美爭先嘗。", "獵歸熾火燎雉兔，相呼置酒喜欲狂。", "陌上行歌忘惡歲，小婦紅粧髻簪穗。", "詔書寛大與天通，逐熟淮南幾誤計。"]'),
('8c6c8c8e-abb7-4318-bc3d-e6170a51a5ea','有自蜀来者因感舊遊作短歌','陸游','宋','宋诗','song-poetry','','[]','錦城如海行不極，馬迹重重車轂擊。',128,'全唐诗/poet.song.130000.json','["錦城如海行不極，馬迹重重車轂擊。", "家住城西三十年，聞說城東未曾識。", "看花走馬宿中路，經月酒徒無覓處。", "露香風暖海棠開，碧雞坊中倘相遇。", "放翁憔悴鬢成絲，空有西遊千首詩。", "今朝雨霽上危榭，意氣頗如年少時。", "持杯欲作消愁計，酒未著人愁已醉。", "不成題句寫幽情，一幅鮫綃空寄泪。"]'),
('b47375ba-a415-43aa-bc2e-c0844d0a0812','東吳女兒曲','陸游','宋','宋诗','song-poetry','','[]','東吳女兒語如鶯，十三不肯學吹笙。',64,'全唐诗/poet.song.130000.json','["東吳女兒語如鶯，十三不肯學吹笙。", "鏡奩初喜穉蠶出，窗眼已看雙繭成。", "庭空日暖花自舞，簾卷巢乾燕新乳。", "阿弟貪書下學遲，獨揀詩章教鸚鵡。"]'),
('1aab6ab6-d71e-4f68-872d-3acf08a49473','雨夕','陸游','宋','宋诗','song-poetry','','[]','歲旱連夏秋，客袂厭塵土。',72,'全唐诗/poet.song.130000.json','["歲旱連夏秋，客袂厭塵土。", "欣然成一笑，愛此清夜雨。", "瓦檠墮燈燼，銅椀起香縷。", "心清病良已，境寂句欲吐。", "東溪久枯涸，想像素蛟舞。", "分喜到溝池，遊魚命儔侶。"]'),
('3815e302-ff60-46da-9b29-6500f6b67309','晚遊東園','陸游','宋','宋诗','song-poetry','','[]','藥瓢藜杖合施行，獨往山林已歃盟。',64,'全唐诗/poet.song.130000.json','["藥瓢藜杖合施行，獨往山林已歃盟。", "傍水斷雲含暮色，拂簷高竹借秋聲。", "癡人自作浮生夢，腐骨那須後世名。", "莫笑吟哦無闕日，老来未盡獨詩情。"]'),
('91cb5431-2f90-4a5d-8141-074b2ed483f6','小雨','陸游','宋','宋诗','song-poetry','','[]','小雨暗林塘，寒聲遶畫廊。',24,'全唐诗/poet.song.130000.json','["小雨暗林塘，寒聲遶畫廊。", "事須求暫假，宜睡稱燒香。"]'),
('d674cb90-9fc6-492b-a116-29622a03feac','初寒在告有感三首  其一','陸游','宋','宋诗','song-poetry','','[]','掃地燒香興未闌，一年佳處是初寒。',64,'全唐诗/poet.song.130000.json','["掃地燒香興未闌，一年佳處是初寒。", "銀毫地綠茶膏嫩，玉斗絲紅墨瀋寛。", "俗事不教来眼境，閑愁那許上眉端。", "數櫺留得西窗日，更取丹經展卷看。"]'),
('1c23f15f-a44e-41b4-a485-55b6a6561c58','初寒在告有感三首  其二','陸游','宋','宋诗','song-poetry','','[]','豪舉當年氣吐虹，即今憔悴一衰翁。',64,'全唐诗/poet.song.130000.json','["豪舉當年氣吐虹，即今憔悴一衰翁。", "寄懷本自俗塵外，移病何妨寒雨中。", "香暖候知銀葉透，酒清看似玉船空。", "故人吳蜀音塵斷，安得相攜一笑同。"]'),
('ee79557d-a2ff-4c2b-a342-f12d11f7e5a3','初寒在告有感三首  其三','陸游','宋','宋诗','song-poetry','','[]','横林吹葉水生洲，身落窮山古睦州。',64,'全唐诗/poet.song.130000.json','["横林吹葉水生洲，身落窮山古睦州。", "到枕雨聲酣旅夢，背窗燈影動清愁。", "氣衝星斗有孤劍，力挽棟梁無萬牛。", "未滅匈奴身已老，此生虛負幄中籌。"]'),
('c96dfb27-211f-493b-b3fc-f8d598b60509','馬上作','陸游','宋','宋诗','song-poetry','','[]','白髮憑鞍一老翁，出門漏鼓尚鼕鼕。',64,'全唐诗/poet.song.130000.json','["白髮憑鞍一老翁，出門漏鼓尚鼕鼕。", "凄涼旅思傳呼裏，零落新詩假寐中。", "正苦文移来陸續，何由笠釣入空濛。", "浮生正自少如意，付與秋風吹斷蓬。"]'),
('b261046a-76e8-4f6c-8e6f-3b902144f492','冬夜聞角聲二首  其一','陸游','宋','宋诗','song-poetry','','[]','嫋嫋清笳入雪雲，白頭老守臥中軍。',32,'全唐诗/poet.song.130000.json','["嫋嫋清笳入雪雲，白頭老守臥中軍。", "自憐到死懷遺恨，不向居延塞外聞。"]'),
('76f2de6b-d222-4727-a2d6-da07aa51c919','冬夜聞角聲二首  其二','陸游','宋','宋诗','song-poetry','','[]','憶在梁州夜雪深，落梅聲裏玉關心。',32,'全唐诗/poet.song.130000.json','["憶在梁州夜雪深，落梅聲裏玉關心。", "山城老去功名忤，臥對寒燈泪滿襟。"]'),
('59afed75-9a69-4962-95ec-829c0d8c2756','塞上曲','陸游','宋','宋诗','song-poetry','','[]','茫茫大磧吁可嗟，暮春積雪草未芽。',96,'全唐诗/poet.song.130000.json','["茫茫大磧吁可嗟，暮春積雪草未芽。", "明月如霜照白骨，惡風卷地吹黄沙。", "駞鳴喜見泉脉出，雁起低傍寒雲斜。", "窮荒萬里無斥堠，天地自古重中華。", "青氊紅錦雙奚車，上有姫人抱琵琶。", "何時漠北王庭靖，千年萬年朝漢家。"]'),
('b43af530-69c9-4c46-a1cd-51ec306d9ef7','荆州歌','陸游','宋','宋诗','song-poetry','','[]','楚江鱗鱗綠如釀，衘尾江邊繫朱舫。',96,'全唐诗/poet.song.130000.json','["楚江鱗鱗綠如釀，衘尾江邊繫朱舫。", "東征打鼓挂高帆，西上湯猪聨百丈。", "伏波古廟占好風，武昌白帝在眼中。", "倚樓女兒笑迎客，清歌未盡千觴空。", "沙頭巷陌三千家，烟雨冥冥開橘花。", "峽人住多楚人少，土鐺爭響茱茰茶。"]'),
('90cc92ff-4bfe-40c0-bc60-96f5035e5825','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','挑燈夜讀書，油涸意未已。',120,'全唐诗/poet.song.130000.json','["挑燈夜讀書，油涸意未已。", "亦知夜既分，未忍捨之起。", "人生各有好，吾癖正如此。", "所求衣食足，安穩住鄉里。", "茆屋三四間，充棟貯經史。", "四傍設几案，坐倦時徙倚。", "無聲九韶奏，有味八珍美。", "寢飰籖帙間，自適以須死。", "豈惟畢吾身，尚可傳兒子。", "此心何時遂，感嘆歲月駛。"]'),
('1143e76a-adb6-4bc0-9c7c-e8c1f07f03d9','寓嘆二首  其一','陸游','宋','宋诗','song-poetry','','[]','江上霜風透弊袍，區區無奈簿書勞。',64,'全唐诗/poet.song.130000.json','["江上霜風透弊袍，區區無奈簿書勞。", "衰遲始憶壯遊樂，仕宦更知歸臥高。", "人怪羊裘忘富貴，我從牛儈得賢豪。", "俗間問訊真成懶，有手惟堪把蟹螯。"]'),
('f53433dc-daad-4bfe-8420-c44de7e82c4e','寓嘆二首  其二','陸游','宋','宋诗','song-poetry','','[]','劍外歸耕夢不通，公車上疏路何從。',64,'全唐诗/poet.song.130000.json','["劍外歸耕夢不通，公車上疏路何從。", "有心求縮地萬里，無羽可朝天九重。", "狂誦新詩驅瘧鬼，醉吹横笛舞神龍。", "明當采藥玉霄去，他日君看冰雪容。"]'),
('6e553648-5b68-459b-972a-5fadadc5437e','燕堂東偏一室頗深暖盡日率困於吏牘比夜乃得讀書其間戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','衮衮流年往，匆匆短景過。',48,'全唐诗/poet.song.130000.json','["衮衮流年往，匆匆短景過。", "簾深上燈早，地窄貯香多。", "書盡還重讀，詩成更自哦。", "向令無此處，將奈旅愁何。"]'),
('60f53ccb-a0b1-40df-8908-171f9989ccae','燕堂東偏一室頗深暖盡日率困於吏牘比夜乃得讀書其間戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','賦性無他好，開編喜欲迷。',48,'全唐诗/poet.song.130000.json','["賦性無他好，開編喜欲迷。", "鼕鼕傳夜漏，喔喔待晨雞。", "油減玉蟲暗，灰深紅獸低。", "悠然撫書嘆，無術濟黔黎。"]'),
('91488fcf-3ad1-475d-a23e-e36506a9e5a8','燕堂東偏一室頗深暖盡日率困於吏牘比夜乃得讀書其間戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','永夜東齋裏，人聲靜不譁。',48,'全唐诗/poet.song.130000.json','["永夜東齋裏，人聲靜不譁。", "衣篝起香穗，書几落燈花。", "爐暖聽寒雨，窗明送曉鵶。", "文章空自苦，白首不名家。"]'),
('ccb609a0-f7e3-422e-bd6a-335ff78f4c62','懷鏡中故廬','陸游','宋','宋诗','song-poetry','','[]','臨水依山偶占家，數間茆屋半欹斜。',64,'全唐诗/poet.song.130000.json','["臨水依山偶占家，數間茆屋半欹斜。", "雲邊腰斧入秦望，雨外舞蓑歸若耶。", "從宦只思乘下澤，忤人常悔讀南華。", "病来更怯還鄉夢，頻鬻簾泉試露芽。"]'),
('0a8e29e8-971b-4785-b8d8-ab0a988e4dae','書感','陸游','宋','宋诗','song-poetry','','[]','丈夫本願脫世鞿，丹成晝日凌空飛。',128,'全唐诗/poet.song.130000.json','["丈夫本願脫世鞿，丹成晝日凌空飛。", "纓冠佩玉朝紫微，白銀宫闕瞻巍巍。", "不然萬里將天威，提兵直解邊城圍。", "苜蓿滿川天馬肥，掩取不遣一騎歸。", "苦心文章亦未非，與此二事同一機。", "寥寥千載見亦稀，莊屈己死吾疇依。", "哀哉窮子百家衣，豈識萬斛傾珠璣。", "欲洗薄蝕還光輝，熟睨無力空歔欷。"]'),
('49324a51-1243-4e0a-803b-d662c5bb5f19','對酒','陸游','宋','宋诗','song-poetry','','[]','新酥鵝兒黄，珍橘金彈香。',72,'全唐诗/poet.song.130000.json','["新酥鵝兒黄，珍橘金彈香。", "天公憐寂寞，勞我以一觴。", "胸中萬卷書，老不施毫芒。", "持酒一澆之，與汝俱深藏。", "生當老窮巷，死埋南山岡。", "古来共如此，已矣庸何傷。"]'),
('30415467-edc2-41f5-b16c-f829949f689c','夢歸','陸游','宋','宋诗','song-poetry','','[]','老去無餘念，時時夢弊廬。',48,'全唐诗/poet.song.130000.json','["老去無餘念，時時夢弊廬。", "細傾新釀酒，盡讀舊藏書。", "雲崦鉏畬粟，烟畦挽野蔬。", "從渠造物巧，賦芧戲群狙。"]'),
('c4933ecd-d609-47a3-89d2-2933e2e53e5e','蜀使歸寄青城上官道人','陸游','宋','宋诗','song-poetry','','[]','輕别青城十二年，至今客枕夢林泉。',64,'全唐诗/poet.song.130000.json','["輕别青城十二年，至今客枕夢林泉。", "一杯松屑齋前進，兩卷丹經肘後傳。", "欲與公爲塵外侣，幾時身上峽中舩。", "世間牛蟻何勞問，輸與雲窗一粲然。"]'),
('ec7a574d-0606-4c4f-86de-c0d90856a3f7','寄城都籧道人','陸游','宋','宋诗','song-poetry','','[]','賣藥錦城中，燒丹雪山麓。',96,'全唐诗/poet.song.130000.json','["賣藥錦城中，燒丹雪山麓。", "石竇取鵝管，玉床收箭鏃。", "紫雲晨覆鼎，白虹夜穿屋。", "鬼神嚴厲守，沆瀣勤沐浴。", "此士真可人，高簡遺世俗。", "江頭十年别，顔色炯在目。", "使来每寄聲，喜我淡無欲。", "靈劑何必多，分餉一黍足。"]'),
('d8e7db5a-ef87-4432-8fef-928ec71dca6d','寄卭州宋道人','陸游','宋','宋诗','song-poetry','','[]','鴨翎鋪前遇秋雨，獨與宋生棲逆旅。',128,'全唐诗/poet.song.130000.json','["鴨翎鋪前遇秋雨，獨與宋生棲逆旅。", "坐門戃怳見老仙，劇談氣欲凌天宇。", "袖中出劍秋水流，血點斑斑新報仇。", "我醉高歌宋生舞，洗盡人間千古愁。", "老仙約我遊太華，是夕當醉蓮峰下。", "語終冉冉已雲霄，萬里秋風吹鶴駕。", "我今伶俜踐衰境，不如宋生棄家猛。", "西望臨卭一慨然，青松偃盡丹爐冷。"]'),
('b9d833f4-3e08-4010-9da8-85224841695a','小齋壁間張王子喬梅子真李八百許旌陽及近時得道諸仙像每焚香對之因賦長句','陸游','宋','宋诗','song-poetry','','[]','山城作吏老堪羞，衫色塵昏鬢色秋。',64,'全唐诗/poet.song.130000.json','["山城作吏老堪羞，衫色塵昏鬢色秋。", "斂版那供新貴使，閉門聊與數公遊。", "至人不死閱千劫，大海無窮環九州。", "安得相攜從此逝，醉騎丹鳳下玄洲。"]'),
('68cce608-306a-4002-8759-7374b902a59f','芳草曲','陸游','宋','宋诗','song-poetry','','[]','蜀山深處逢孤驛，缺甃頹垣芳草碧。',96,'全唐诗/poet.song.130000.json','["蜀山深處逢孤驛，缺甃頹垣芳草碧。", "家在江南妻子病，離鄉半歲無消息。", "長安城門西去路，細靄斜陽芳草暮。", "尊前一曲渭城歌，馬蹄萬里交河戍。", "人生誤計覓封侯，芳草愁人春復秋。", "只願東行至滄海，路窮草斷始無愁。"]'),
('499952d4-7a57-4332-ba6d-ddb26328e967','烏龍廟','陸游','宋','宋诗','song-poetry','','[]','江邊蒼龍背負天，蟠踞千載常蜿蜒。',64,'全唐诗/poet.song.130000.json','["江邊蒼龍背負天，蟠踞千載常蜿蜒。", "其前横闢爲大川，高城鼓角聲隱然。", "龍廟於山家於淵，世爲吾州作豐年。", "老守雖愧筆如椽，潔齋試賦迎神篇。"]'),
('aaf73f97-cfe0-44ae-acf1-591c777a219c','寒夜移疾二首  其一','陸游','宋','宋诗','song-poetry','','[]','南山北山高嶙峋，朝雨暮雨斷江津。',64,'全唐诗/poet.song.130000.json','["南山北山高嶙峋，朝雨暮雨斷江津。", "時人正作市朝夢，老子已成雲水身。", "希世強顔心自愧，閉門謝病客生嗔。", "天公何日與一飽，短艇湘湖自采蓴。"]'),
('72cac6cc-af76-4b4b-8a2d-02bef280c1b1','寒夜移疾二首  其二','陸游','宋','宋诗','song-poetry','','[]','走遍天涯白髮生，晚叨微祿臥山城。',64,'全唐诗/poet.song.130000.json','["走遍天涯白髮生，晚叨微祿臥山城。", "知章自識狂供奉，士季那容醉步兵。", "斸藥有時攜短鑱，奏書無路請長纓。", "此心擬說還休去，付與空堦夜雨聲。"]'),
('7e2dd3a5-03ab-4bf0-aaca-1a0338c22067','寒夜讀書三首  其一','陸游','宋','宋诗','song-poetry','','[]','北窗暖焰滿爐紅，夜半濤翻古檜風。',32,'全唐诗/poet.song.130000.json','["北窗暖焰滿爐紅，夜半濤翻古檜風。", "老死愛書心不厭，来生恐墮蠧魚中。"]'),
('f3283a25-5ec9-4fb0-a964-73df6908dc32','寒夜讀書三首  其二','陸游','宋','宋诗','song-poetry','','[]','韋編屢絕鐵硯穿，口誦手鈔那計年。',32,'全唐诗/poet.song.130000.json','["韋編屢絕鐵硯穿，口誦手鈔那計年。", "不是愛書即欲死，任從人笑作書顛。"]'),
('1a94b6d5-feaa-4e2b-9816-b1a5055ca761','寒夜讀書三首  其三','陸游','宋','宋诗','song-poetry','','[]','憶昨從戎出渭濱，秋風金鼓震咸秦。',32,'全唐诗/poet.song.130000.json','["憶昨從戎出渭濱，秋風金鼓震咸秦。", "鳶肩竟欠封侯相，三尺檠邊老此身。"]'),
('d473f67f-8078-4a6c-a046-18f40db1fe27','有爲予言烏龍高嶮不可到處有僧巖居不知其年予每登千峰榭望之慨然爲作二詩  其一','陸游','宋','宋诗','song-poetry','','[]','樵子向予說，有僧巢翠微。',48,'全唐诗/poet.song.130000.json','["樵子向予說，有僧巢翠微。", "巖扉雲共宿，錫杖鶴同飛。", "日暮松明火，天寒槲葉衣。", "棄官從此逝，非子尚誰歸。"]'),
('9cfa7173-de8a-47c5-b04b-71f6a22fd6d6','有爲予言烏龍高嶮不可到處有僧巖居不知其年予每登千峰榭望之慨然爲作二詩  其二','陸游','宋','宋诗','song-poetry','','[]','嶮絕無微徑，淙潺有細流。',48,'全唐诗/poet.song.130000.json','["嶮絕無微徑，淙潺有細流。", "寒巖依作屋，墮毳拾爲裘。", "木客求相識，毛人約共遊。", "百年如一瞬，塵世幾公侯。"]'),
('1dc301bc-9e96-418c-9384-8d6397c9112f','楊庭秀寄南海集二首  其一','陸游','宋','宋诗','song-poetry','','[]','俗子與人隔塵劫，何啻相逢風馬牛。',32,'全唐诗/poet.song.130000.json','["俗子與人隔塵劫，何啻相逢風馬牛。", "夜讀楊卿南海句，始知天下有高流。"]'),
('4cf9d20a-cdbc-478f-88f0-47d2061312c5','楊庭秀寄南海集二首  其二','陸游','宋','宋诗','song-poetry','','[]','飛卿數闋嶠南曲，不許劉郎誇竹枝。',32,'全唐诗/poet.song.130000.json','["飛卿數闋嶠南曲，不許劉郎誇竹枝。", "四百年来無復繼，如今始有此翁詩。"]'),
('22038d46-d4a2-42bb-aed5-aa2c695c7f56','夜坐示桑甥十韵','陸游','宋','宋诗','song-poetry','','[]','好詩如靈丹，不雜羶葷腸。',120,'全唐诗/poet.song.130000.json','["好詩如靈丹，不雜羶葷腸。", "子誠欲得之，潔齋祓不祥。", "食飲屑白玉，沐浴春蘭芳。", "蛟龍起久蟄，鴻鵠參高翔。", "縱横開武庫，浩蕩發太倉。", "大巧謝雕琢，至剛反摧藏。", "一技均道妙，佻心詎能當。", "結纓與易簀，至死猶自強。", "東山七月篇，萬古真文章。", "天下有精識，吾言豈荒唐。"]'),
('e5a08002-3ce3-4177-9157-4ab4e42e8659','夢回','陸游','宋','宋诗','song-poetry','','[]','病骨便衾暖，羈懷怯夢回。',48,'全唐诗/poet.song.130000.json','["病骨便衾暖，羈懷怯夢回。", "鐘殘燈燼落，香冷雨聲来。", "老抱憂時志，狂非濟世材。", "明朝入冬假，燒兔薦新醅。"]'),
('1c3867ab-3eea-490e-9aeb-9b8a50466fc1','醉中草書因戲作此詩','陸游','宋','宋诗','song-poetry','','[]','賜休暫解簿書圍，醉草今年頗入微。',64,'全唐诗/poet.song.130000.json','["賜休暫解簿書圍，醉草今年頗入微。", "手挹凍醪秋露重，卷翻狂墨瘦蛟飛。", "臨池勤苦今安有，漏壁工夫古亦稀。", "穉子問翁新悟處，欲言直恐泄天機。"]'),
('167b3091-a908-4203-b340-e0204e566e39','閑步至鞠場值小雪','陸游','宋','宋诗','song-poetry','','[]','倒盡床頭酒半罌，笑呼笻杖共閑行。',64,'全唐诗/poet.song.130000.json','["倒盡床頭酒半罌，笑呼笻杖共閑行。", "梅花照水爲誰瘦，雪片倚風如許輕。", "孟德遇冬思射獵，廣文垂老謝才名。", "歸来跨火西窗下，獨數城樓長短更。"]'),
('7377622a-4be7-4305-b287-80c3e9395ad8','張季長學士自興元遣人来因詢梁益間事悵然有感','陸游','宋','宋诗','song-poetry','','[]','長記殘春入蜀時，嘉陵江上雨霏微。',64,'全唐诗/poet.song.130000.json','["長記殘春入蜀時，嘉陵江上雨霏微。", "垂頭驢瘦悲鈴馱，截道狐奔脫獵圍。", "曉度市橋花欲語，晚投山驛石能飛。", "杜鵑言語元無據，悔作東吴萬里歸。"]'),
('cb5635c6-bb93-4ef0-ae1e-c8b7b70174f9','東齋夜興','陸游','宋','宋诗','song-poetry','','[]','山城殘角伴疏鐘，擁褐頽然一病翁。',64,'全唐诗/poet.song.130000.json','["山城殘角伴疏鐘，擁褐頽然一病翁。", "紙帳燈明蹙龜甲，銅瓶火熟起松風。", "雨来尤覺睡味美，酒後不知愁思空。", "忽憶江湖泊船夜，號鳴避弋閙群鴻。"]'),
('2878c267-cc6a-4c43-b542-29fd8671fcb7','烏龍雪','陸游','宋','宋诗','song-poetry','','[]','烏龍如真龍，妥尾臥江磧。',120,'全唐诗/poet.song.130000.json','["烏龍如真龍，妥尾臥江磧。", "時時登樓望，爪尾略可識。", "今朝事大異，千嶂忽如失。", "遥知重雲外，已有雪數尺。", "頗念采薇人，清坐焉得食。", "裹飯欲問之，矯首空峭壁。", "念昔故山時，僵臥風雪夕。", "靜聞長松折，聲若裂巨石。", "天晴視巖澗，鳥獸死如積。", "清夢不可尋，撫楯三太息。"]'),
('94956f1a-575b-4464-a1df-640289605621','曉出東城馬上作','陸游','宋','宋诗','song-poetry','','[]','曉出東城數幟紅，蒙茸狐貉擁衰翁。',64,'全唐诗/poet.song.130000.json','["曉出東城數幟紅，蒙茸狐貉擁衰翁。", "郊墟歉歲蕭條後，風雪窮冬慘淡中。", "耐辱己慚非士節，端憂未辦濟民窮。", "誕欺成俗真當懼，誰挽天河一洗空。"]'),
('4f38db02-24f0-4478-a479-cc82c5cb178e','與建子振孫登千峰榭觀烏龍雪','陸游','宋','宋诗','song-poetry','','[]','二穉慧堪憐，猶賒志學年。',48,'全唐诗/poet.song.130000.json','["二穉慧堪憐，猶賒志學年。", "能抛竹騕褭，来看玉蜿蜒。", "百念寛身後，餘生慰眼前。", "善和書幸在，它日要人傳。"]'),
('f5804380-a45a-4ea2-b58c-b3950762b30d','述懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','尺寸雖無補縣官，此心炯炯實如丹。',64,'全唐诗/poet.song.130000.json','["尺寸雖無補縣官，此心炯炯實如丹。", "羯胡未滅敢愛死，尊酒在前終鮮歡。", "亞父抱忠撞玉斗，虞人守節待皮冠。", "縱言老病摧頽甚，壯氣猶憑後代看。"]'),
('7fbe4258-75e4-4f28-a007-28d2c72d0689','述懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','謗譽紛紛笑殺儂，此身本自等虚空。',64,'全唐诗/poet.song.130000.json','["謗譽紛紛笑殺儂，此身本自等虚空。", "大鵬境界纖塵裏，曠劫年光掣電中。", "翻動烟霞長鑱在，招呼風月一尊同。", "是凡是聖誰能測，試問西鄰織屨翁。"]'),
('c6f3556f-f50e-4154-8d77-88318bdb810e','到嚴十五晦朔郡釀不佳求於都下既不時至欲借書讀之而寓公多秘不肯出無以度日殊惘惘也','陸游','宋','宋诗','song-poetry','','[]','桐君放隱兩經秋，小院孤燈夜夜愁。',64,'全唐诗/poet.song.130000.json','["桐君放隱兩經秋，小院孤燈夜夜愁。", "名酒過於求趙璧，異書渾似借荆州。", "溪山勝處真難到，風月佳時事不休。", "安得連車載郫釀，金鞭重作浣花遊。"]'),
('f2a721e9-1267-4efd-be1f-5aaa7754a174','雨中獨酌','陸游','宋','宋诗','song-poetry','','[]','僻郡荒山下，高齋寒雨中。',48,'全唐诗/poet.song.130000.json','["僻郡荒山下，高齋寒雨中。", "微波生酒綠，短焰擁爐紅。", "學廢悲身老，民窮祝歲豐。", "厨人羞雉兔，更憶喚鄰翁。"]'),
('604cfffb-6450-4aed-ab00-1c60865ef5d6','被酒徑臥比覺已五鼓矣','陸游','宋','宋诗','song-poetry','','[]','俗事驅人挽不回，經年無地濯氛埃。',64,'全唐诗/poet.song.130000.json','["俗事驅人挽不回，經年無地濯氛埃。", "酒酣稍覺客愁破，睡覺忽聞山雨来。", "窗外樹寒無鳥宿，壺中水暖有梅開。", "五更欲起先惆悵，燭下文書已作堆。"]'),
('3989b013-081f-428f-8b83-71030bac5bf9','燈下讀玄真子漁歌因懷山陰故隱追擬五首  其一','陸游','宋','宋诗','song-poetry','','[]','石帆山下雨空濛，三扇香新翠箬篷。',32,'全唐诗/poet.song.130000.json','["石帆山下雨空濛，三扇香新翠箬篷。", "蘋葉綠，蓼花紅。", "回首功名一夢中。"]'),
('6642e74c-81d7-4c27-8af0-ef9b98654234','燈下讀玄真子漁歌因懷山陰故隱追擬五首  其二','陸游','宋','宋诗','song-poetry','','[]','晴山滴翠水挼藍，聚散漁舟兩復三。',32,'全唐诗/poet.song.130000.json','["晴山滴翠水挼藍，聚散漁舟兩復三。", "横埭北，斷橋南，側起船篷便作帆。"]'),
('396c4bd4-2b20-4aec-be01-655e4651230d','燈下讀玄真子漁歌因懷山陰故隱追擬五首  其三','陸游','宋','宋诗','song-poetry','','[]','鏡湖俯仰兩青天，萬頃玻瓈一葉舩。',32,'全唐诗/poet.song.130000.json','["鏡湖俯仰兩青天，萬頃玻瓈一葉舩。", "拈棹舞，擁蓑眠，不作天仙作水仙。"]'),
('fd48a6a2-255e-42ba-bd66-3b375df2a0b2','燈下讀玄真子漁歌因懷山陰故隱追擬五首  其四','陸游','宋','宋诗','song-poetry','','[]','湘湖烟雨長蓴絲，菰米新炊滑上匙。',32,'全唐诗/poet.song.130000.json','["湘湖烟雨長蓴絲，菰米新炊滑上匙。", "雲散後，月斜時，潮落舟横醉不知。"]'),
('f97f8158-79fb-4402-96d2-5f0900c34b6b','燈下讀玄真子漁歌因懷山陰故隱追擬五首  其五','陸游','宋','宋诗','song-poetry','','[]','長安拜免幾公卿，漁父横眠醉未醒。',32,'全唐诗/poet.song.130000.json','["長安拜免幾公卿，漁父横眠醉未醒。", "烟艇小，釣車腥，遥指梅山一點青。"]'),
('da312389-dfff-4169-9669-d987eb923424','送客至望雲門外','陸游','宋','宋诗','song-poetry','','[]','冬溫頻作雨，晨冷頓催晴。',48,'全唐诗/poet.song.130000.json','["冬溫頻作雨，晨冷頓催晴。", "嫰日滿江驛，淡烟籠郡城。", "憂民懷凛凛，謀已耻營營。", "投檄真須決，鄰翁約耦耕。"]'),
('0cda1365-8068-40c4-8833-8a575e143729','題城南堂二首  其一','陸游','宋','宋诗','song-poetry','','[]','山林恨與親友别，朝市不堪車馬喧。',32,'全唐诗/poet.song.130000.json','["山林恨與親友别，朝市不堪車馬喧。", "陳子調高無俗客，一廛却要近修門。"]'),
('b86c9ebc-bd26-483f-bff1-a25c9d239278','題城南堂二首  其二','陸游','宋','宋诗','song-poetry','','[]','借問城南老居士，新年樂事復何如。',32,'全唐诗/poet.song.130000.json','["借問城南老居士，新年樂事復何如。", "春寒催喚客嘗酒，夜靜臥聽兒讀書。"]'),
('4ab34e57-81d2-4f34-b633-ba830986489d','故山葛仙翁丹井有偃松覆其上夭矯可愛寄題','陸游','宋','宋诗','song-poetry','','[]','葛翁煉丹一千年，翁去丹飛餘此泉。',96,'全唐诗/poet.song.130000.json','["葛翁煉丹一千年，翁去丹飛餘此泉。", "炯如古鏡不拂拭，俯聽缺甃時鏘然。", "老龍受命護泉臥，蜿蜒直恐從天墮。", "人言神物老愈靈，夜半聲酣風雨過。", "放翁還山亦何有，閉門吟嘯龍爲友。", "客来相對聊曲肱，但酌此泉勝酌酒。"]'),
('b74e8e93-d003-4c57-9ebc-64a606247cbd','估客樂','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江浩浩蛟龍淵，浪花正白蹴半天。',144,'全唐诗/poet.song.130000.json','["長江浩浩蛟龍淵，浪花正白蹴半天。", "軻峨大艑望如豆，駭視未定已至前。", "帆席雲垂大隄外，纜索雷響高城邊。", "牛車轔轔載寶貨，磊落照市人爭傳。", "倡樓呼盧擲百萬，旗亭買酒價十千。", "公卿姓氏不曾問，安知孰秉中書權。", "儒生辛苦望一飽，趦趄光範祈哀憐。", "齒揺髮脫竟莫顧，詩書滿腹身蕭然。", "自看賦命如紙薄，始知估客人間樂。"]'),
('8f9451ed-5ce6-4246-ac34-f2c5e7312083','楚宫行','陸游','宋','宋诗','song-poetry','','[]','漢水方城一何壯，大路竝馳車百兩。',96,'全唐诗/poet.song.130000.json','["漢水方城一何壯，大路竝馳車百兩。", "軍書插羽擁修門，楚王正醉章華上。", "璇題藻井窮丹青，玉笙寶瑟聲冥冥。", "忽聞命駕遊七澤，萬騎動地如雷霆。", "清晨射獵至中夜，蒼兕玄熊紛可藉。", "國中壯士力已殫，秦虜東来遣誰射。"]'),
('1538a4dc-1bd9-4b36-ade6-f0a9f00a33d9','妾命薄','陸游','宋','宋诗','song-poetry','','[]','妾命薄，早入天家侍帷幄。',76,'全唐诗/poet.song.130000.json','["妾命薄，早入天家侍帷幄。", "君王勤儉省宴游，寶柱朱弦塵漠漠。", "日長别殿承恩稀，旰昃猶聞親萬機。", "宫中雖無珠玉賜，塞上不見烟塵飛。", "不須悲傷妾命薄，命薄却令天下樂。"]'),
('a0f336d7-cb9a-4db0-bbbf-6421f4197762','晚登千峰榭','陸游','宋','宋诗','song-poetry','','[]','只道文書無了日，也能擺撥上層臺。',64,'全唐诗/poet.song.130000.json','["只道文書無了日，也能擺撥上層臺。", "窗明山雪暮方作，露白野梅寒未開。", "老病真慚天下士，窮愁強覆掌中杯。", "兒曹莫怪憑闌久，得句何妨秉燭回。"]'),
('d6bda57c-b7cb-42c4-a6b0-6ee8647d904f','晝睡','陸游','宋','宋诗','song-poetry','','[]','書獄徴租自笑忙，暫歸聊得憩匡床。',64,'全唐诗/poet.song.130000.json','["書獄徴租自笑忙，暫歸聊得憩匡床。", "屏圖夜雨孤舟句，枕带秋風九日香。", "一卷蠧書棲倦手，數聲殘角報斜陽。", "清泉浴罷西窗靜，更覺茶甌氣味長。"]'),
('caea63c6-f552-4236-84fb-c77313ad833f','胸次鬱鬱偶取枯筆作狂草遂成長句','陸游','宋','宋诗','song-poetry','','[]','酒隱人間六十年，晚途斂板自傷憐。',64,'全唐诗/poet.song.130000.json','["酒隱人間六十年，晚途斂板自傷憐。", "莊周聊寄漆園吏，梅福終爲吴市仙。", "方外酒徒盟尚在，囊中劍術老當傳。", "此心鬱屈何由豁，聊遣龍蛇落蜀牋。"]'),
('0d151844-43a3-463b-a0b0-6da8916c89e8','休日與客燕語既去聽小兒誦書因復作草數紙','陸游','宋','宋诗','song-poetry','','[]','賜沐家居謝掾曹，暫將蕭散慰勤勞。',64,'全唐诗/poet.song.130000.json','["賜沐家居謝掾曹，暫將蕭散慰勤勞。", "琅琅應節兒書熟，亹亹生風客論高。", "玉屑名牋来濯錦，風漪奇石出臨洮。", "託盟翰墨吾安敢，揮灑淋漓自足豪。"]'),
('2f531f71-dfc2-4c4d-b392-54a462701bfb','青城大面山中有二隱士一曰譙先生定字天授建炎初以經行召至揚州欲留之講筵不可拜通直郎直秘閣致仕今百三十餘歲巢居嶮絕人不能到而先生數年輒一出至山前人有見之者其一曰姚太尉平仲字希晏靖康初在圍城中夜將死士攻賊營不利騎駿騾逸去建炎初所在揭牓以觀察使召之竟不出淳熙甲午乙未間乃或見之於丈人觀道院亦年近九十紫髯長委地喜作草書蓋皆得道於山中云偶成五字二首託上官道人寄之 寄譙先生','陸游','宋','宋诗','song-poetry','','[]','寄謝譙夫子，今年一出無。',48,'全唐诗/poet.song.130000.json','["寄謝譙夫子，今年一出無。", "萬緣隨夢斷，百念與形枯。", "雲護巢松谷，神呵煆藥爐。", "憑高應念我，白首學徴租。"]'),
('67027c6a-be5a-4eae-81b9-f34d049c1076','青城大面山中有二隱士一曰譙先生定字天授建炎初以經行召至揚州欲留之講筵不可拜通直郎直秘閣致仕今百三十餘歲巢居嶮絕人不能到而先生數年輒一出至山前人有見之者其一曰姚太尉平仲字希晏靖康初在圍城中夜將死士攻賊營不利騎駿騾逸去建炎初所在揭牓以觀察使召之竟不出淳熙甲午乙未間乃或見之於丈人觀道院亦年近九十紫髯長委地喜作草書蓋皆得道於山中云偶成五字二首託上官道人寄之 寄姚太尉','陸游','宋','宋诗','song-poetry','','[]','太尉關河傑，飛騰亦遇時。',48,'全唐诗/poet.song.130000.json','["太尉關河傑，飛騰亦遇時。", "中原方蕩覆，大計易差池。", "素壁龍蛇字，空山熊豹姿。", "烟雲千萬疊，求訪固難知。"]'),
('c825ce86-7001-4226-b0ad-e0fff329309b','累日多事不復能觀書感嘆作此詩','陸游','宋','宋诗','song-poetry','','[]','我生無它長，所得靜而簡。',120,'全唐诗/poet.song.130000.json','["我生無它長，所得靜而簡。", "出仕三十年，不殖一金產。", "四方到爲家，所向不容揀。", "南遊極巨海，西戍掠危棧。", "爲州亦何好，且復占仕版。", "俸不給淖糜，况敢事酒琖。", "晨興坐堂上，符檄高𡾰嵼。", "藏書三萬軸，一字不到眼。", "胸中積磊塊，嘆息誰爲鏟。", "浮生固如此，正可付一莞。"]'),
('205702f3-6bde-4569-a8e0-b287390b9929','北窗','陸游','宋','宋诗','song-poetry','','[]','雲開見山雪，院靜聞松風。',24,'全唐诗/poet.song.130000.json','["雲開見山雪，院靜聞松風。", "吏去曲肱臥，疑非塵世中。"]'),
('c8646a0f-8326-4afe-b991-5b40778b8ecf','讀范文正瀟灑桐廬郡詩戲書','陸游','宋','宋诗','song-poetry','','[]','桐廬朝暮苦匆匆，瀟灑寧能與昔同。',64,'全唐诗/poet.song.130000.json','["桐廬朝暮苦匆匆，瀟灑寧能與昔同。", "堆案文書生眼黑，入京車馬漲塵紅。", "逢迎風月麯生事，彈壓江山毛頴功。", "二子年来俱掃迹，頽然堪笑一衰翁。"]'),
('10164fc6-7517-41ef-8b24-b5d3370de92d','笥中偶得去年二月都下數詩','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昨佩魚符入鳳城，春風處處聽鶯聲。',64,'全唐诗/poet.song.130000.json','["昨佩魚符入鳳城，春風處處聽鶯聲。", "欲尋舊友半爲鬼，重到西湖疑隔生。", "浮世正如投六簙，野人何意慕三旌。", "嚴州戍滿真當老，猶幸爲民死太平。"]'),
('5a44cc3b-7234-41a6-a70b-2e0fa05088ae','感寓','陸游','宋','宋诗','song-poetry','','[]','人生堂堂七尺身，本與聖哲均稱人。',96,'全唐诗/poet.song.130000.json','["人生堂堂七尺身，本與聖哲均稱人。", "唐虞乃可讓天下，光被萬世常如新。", "哀哉末俗去古遠，斵喪太朴澆全淳。", "豆羮簞食輒動色，攘竊乃至忘君親。", "錙銖必先計利害，詎肯冒死求成仁。", "不欺當從一念始，自古孝子爲忠臣。"]'),
('bb35dd92-4a5b-4449-962d-139f5ce929ce','征婦怨効唐人作','陸游','宋','宋诗','song-poetry','','[]','萬里安西久宿師，東風吹草又離離。',64,'全唐诗/poet.song.130000.json','["萬里安西久宿師，東風吹草又離離。", "玉壺貯滿傷春泪，錦字挑成寄遠詩。", "擊虜將軍方戰急，押衣敕使尚歸遲。", "粧臺寶鏡塵昏盡，髮似飛蓬自不知。"]'),
('cf4ebe44-89d6-41c6-be17-b16e4aff6576','雪','陸游','宋','宋诗','song-poetry','','[]','瘴癘家家一洗無，更欣餘潤沃焦枯。',64,'全唐诗/poet.song.130000.json','["瘴癘家家一洗無，更欣餘潤沃焦枯。", "花壺夜凍先除水，衣焙朝寒久覆爐。", "松頂積高時自墮，竹枝壓重欲相扶。", "雲開正值春風早，却看晴光滿九衢。"]'),
('00df2ac9-f20d-4f86-acf7-0faedcf8766c','寒夜','陸游','宋','宋诗','song-poetry','','[]','我老畏作病，杯酒久不持。',72,'全唐诗/poet.song.130000.json','["我老畏作病，杯酒久不持。", "讀書寒雨中，比夕頗思之。", "呼童欲洗酌，顧以病自疑。", "清坐嘆寂寞，痛飲愁淋漓。", "三爵醒醉間，此理當徐思。", "一掬琴高魚，且復伴吾兒。"]'),
('8c793ceb-99e9-4d0a-98bd-d7be5b05d446','縱筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','凍研笑臞儒，雕弓隱獵徒。',48,'全唐诗/poet.song.130000.json','["凍研笑臞儒，雕弓隱獵徒。", "不成平趙魏，正可老江湖。", "憔悴頭雖秃，輪囷膽尚粗。", "咸陽呼五白，何遽不能盧。"]'),
('06aa6307-f029-4fba-85ae-1c58b3c79ab8','縱筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','故國吾宗廟，群羌我虜讎。',48,'全唐诗/poet.song.130000.json','["故國吾宗廟，群羌我虜讎。", "但應堅此念，寧假用它謀。", "望駕遺民老，忘兵志士憂。", "何時聞遣將，往護北平秋。"]'),
('0865009f-bd09-49f7-b785-1f4e64bb3fa0','歲晚盤尊索然戲書','陸游','宋','宋诗','song-poetry','','[]','經年薄宦客桐廬，市邑蕭然一物無。',64,'全唐诗/poet.song.130000.json','["經年薄宦客桐廬，市邑蕭然一物無。", "名酒不来惟飲濕，長魚難覓且焚枯。", "支離鶴骨寒添瘦，宛轉龜腸夜自呼。", "更與兒曹同一笑，燈前短褐拆天吳。"]'),
('2b467072-a919-47e9-9233-ae0b4e49dfe6','立春前四日謝雪方拜天慶庭中雪復作','陸游','宋','宋诗','song-poetry','','[]','珮玉珊珊謁衆真，竟煩一雪慰疲民。',64,'全唐诗/poet.song.130000.json','["珮玉珊珊謁衆真，竟煩一雪慰疲民。", "未看舞鶴隨飛蓋，先喜飄花集拜茵。", "耕壟土膏千耦出，市樓酒賤萬家春。", "使君老去悲才盡，詩句難追節物新。"]'),
('90798c92-6cd6-4062-b5e3-3dd6b45a4454','桐江行','陸游','宋','宋诗','song-poetry','','[]','我来桐江今幾時，面骨崢嶸鬢如雪。',128,'全唐诗/poet.song.130000.json','["我来桐江今幾時，面骨崢嶸鬢如雪。", "怒嗔不復有端緒，讒謗何曾容辨說。", "十年山棲却火食，釀桂餐芝自芳潔。", "作官一飽仰紅腐，坐對盤飱常嘔噎。", "雪晴宿戒南山遊，剩要賦詠臨清流。", "將行復輟却退坐，臺符吏牘令人愁。", "胸中崔嵬向誰吐，獨立憑高時自語。", "文章當以氣爲主，無怪今人不如古。"]'),
('0047e4bd-b1f9-4032-99df-caf4ecc38893','屢雪二麥可望喜而作歌','陸游','宋','宋诗','song-poetry','','[]','苦寒勿怨天雨雪，雪来遺我明年麥。',128,'全唐诗/poet.song.130000.json','["苦寒勿怨天雨雪，雪来遺我明年麥。", "三月翠浪舞東風，四月黄雲暗南陌。", "坐看比屋騰歡聲，已覺有司寛吏責。", "腰鎌丁壯傾閭里，拾穗兒童動千百。", "玉塵出䃺飛屋梁，銀絲入釜須寛湯。", "寒醅發劑炊餅裂，新麻壓油寒具香。", "大婦下機廢晨織，小姑佐庖忘晚粧。", "老翁飽食笑捫腹，林下擊壤歌時康。"]'),
('f3d27cb1-cb3a-448e-950d-8526cb9d1bb8','丁未除夕前二日休假感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','挂冠神武莫躊躇，家具何妨載鹿車。',64,'全唐诗/poet.song.130000.json','["挂冠神武莫躊躇，家具何妨載鹿車。", "怨謗相乘真市虎，技能已盡似黔驢。", "黄金散後猶耽酒，白髮生来更愛書。", "新歲定尋林下約，一觴一詠未成疏。"]'),
('3d383123-7cc7-42f3-9447-cbe681764daa','丁未除夕前二日休假感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','夢寄梅村竹塢間，不堪客裏見春還。',64,'全唐诗/poet.song.130000.json','["夢寄梅村竹塢間，不堪客裏見春還。", "潮生水欲通南澗，雪霽雲猶冒北山。", "病思過年應小減，官身得假未全閑。", "變名吳市男兒事，末路低回自笑孱。"]'),
('40286248-6054-4f0f-8af2-1bf605a4bea3','假中閉戸終日偶得絕句三首  其一','陸游','宋','宋诗','song-poetry','','[]','雨聲滴滴暮未已，苔暈重重寒更添。',32,'全唐诗/poet.song.130000.json','["雨聲滴滴暮未已，苔暈重重寒更添。", "知是使君初睡起，清香一綫透疏簾。"]'),
('952e5a04-874c-4d85-b3da-6994c3131b57','假中閉戸終日偶得絕句三首  其二','陸游','宋','宋诗','song-poetry','','[]','老夫昔是青城客，酒肉淋漓豈本心。',32,'全唐诗/poet.song.130000.json','["老夫昔是青城客，酒肉淋漓豈本心。", "還我山家本来面，數拳春筍薦孤斟。"]'),
('a32bbb62-6d95-43a7-9620-197d8af9bc8e','假中閉戸終日偶得絕句三首  其三','陸游','宋','宋诗','song-poetry','','[]','官身常欠讀書債，祿米不供沽酒資。',32,'全唐诗/poet.song.130000.json','["官身常欠讀書債，祿米不供沽酒資。", "剩喜今朝寂無事，焚香閑看玉谿詩。"]'),
('bff8ffcc-58ce-4733-832d-5d55feb6091f','除夜雪二首  其一','陸游','宋','宋诗','song-poetry','','[]','只怪重衾不禦寒，起看急雪玉花乾。',32,'全唐诗/poet.song.130000.json','["只怪重衾不禦寒，起看急雪玉花乾。", "遲明欲謁虚皇殿，廐馬蒙氊立夜闌。"]'),
('5df540da-a554-4570-8ed1-13b98d270374','除夜雪二首  其二','陸游','宋','宋诗','song-poetry','','["\u5199\u96ea", "\u6625\u8282", "\u96ea"]','北風吹雪四更初，嘉瑞天教及歲除。',32,'全唐诗/poet.song.130000.json','["北風吹雪四更初，嘉瑞天教及歲除。", "半盞屠蘇猶未舉，燈前小草寫桃符。"]'),
('431bde02-9ede-4e0a-98fa-5a62f2b0ecb9','戊申元日','陸游','宋','宋诗','song-poetry','','[]','白頭身世嘆羈孤，一念兒時泪已濡。',64,'全唐诗/poet.song.130000.json','["白頭身世嘆羈孤，一念兒時泪已濡。", "尚記爭先書欝壘，豈知落後舉屠蘇。", "杯盤草草思鄰舍，車馬紛紛厭九衢。", "六十年非心自了，挂冠猶足補東隅。"]'),
('0489afab-ad00-4439-9629-a0fe71d8865d','初春感懷','陸游','宋','宋诗','song-poetry','','[]','關河謝遠遊，歲月迫歸休。',48,'全唐诗/poet.song.130000.json','["關河謝遠遊，歲月迫歸休。", "敢恨驥伏櫪，但思狐首丘。", "雪明窗誤曉，霜點鬢驚秋。", "羈旅饒愁思，誰憐季子裘。"]'),
('480d4f8d-fb70-4ba7-9190-97989800f590','閉閤','陸游','宋','宋诗','song-poetry','','[]','閉閤孤城賸放慵，桐江清絕勝吴松。',64,'全唐诗/poet.song.130000.json','["閉閤孤城賸放慵，桐江清絕勝吴松。", "雲收忽見北山雪，月落正聞西寺鐘。", "世味老来無奈薄，土思病後不勝濃。", "蓴羮豈止方羊酪，輕許平生笑士龍。"]'),
('d93f72f1-14aa-46a8-8059-f0c6dc2947b2','潺湲閣小立','陸游','宋','宋诗','song-poetry','','[]','飽食何曾補縣官，潺湲閣上倚闌干。',64,'全唐诗/poet.song.130000.json','["飽食何曾補縣官，潺湲閣上倚闌干。", "水紋靴皺風初緊，花色鞓紅露未乾。", "薄酒愁邊供醉醒，故人夢裏話悲歡。", "孤城正在山窮處，過社今朝尚爾寒。"]'),
('449bf25d-8c84-463e-834c-c1586613288f','睡起至園中','陸游','宋','宋诗','song-poetry','','[]','欲挂衣冠萬事輕，不妨小住向山城。',64,'全唐诗/poet.song.130000.json','["欲挂衣冠萬事輕，不妨小住向山城。", "緑尊耐久常相伴，雪鬢纔生便放行。", "拂枕時時覓幽夢，倚闌日日聽新鶯。", "夕陽更有欣然處，来看青郊雨後耕。"]'),
('167bab85-bf6b-42f8-89a5-994740e14ff2','上書乞祠','陸游','宋','宋诗','song-poetry','','[]','上書又乞奉祠歸，夢到湖邊自叩扉。',64,'全唐诗/poet.song.130000.json','["上書又乞奉祠歸，夢到湖邊自叩扉。", "此去敢辭依馬磨，向来真慣擁牛衣。", "致身途遠年齡暮，報國心存氣力微。", "誓墓那因一懷祖，人間處處是危機。"]'),
('0f53a1b5-d491-4e47-9bef-3a396a55e175','春殘','陸游','宋','宋诗','song-poetry','','[]','老堕空山裏，春殘白日長。',48,'全唐诗/poet.song.130000.json','["老堕空山裏，春殘白日長。", "庸醫司性命，俗子議文章。", "燭映一池墨，風飄半篆香。", "箇中有佳處，袖手看人忙。"]'),
('0502eefe-94e3-44fb-af19-0ce9abb47053','三月二十日晚酌','陸游','宋','宋诗','song-poetry','','[]','暫因賜沐作閑身，太息纔餘一日春。',64,'全唐诗/poet.song.130000.json','["暫因賜沐作閑身，太息纔餘一日春。", "委地落花新著雨，穿簾歸燕不生人。", "衛青此日怪長揖，王翰當年謀卜鄰。", "商略晚窗須小醉，朱櫻青店正嘗新。"]'),
('4460538d-d69d-4be3-835a-dd2c60fa748a','次前韵','陸游','宋','宋诗','song-poetry','','[]','烏帽紅塵過去身，荒山野水又經春。',64,'全唐诗/poet.song.130000.json','["烏帽紅塵過去身，荒山野水又經春。", "殘年欲盡初聞道，薄宦宜休不問人。", "一局枯棋忘日月，數斟濁酒約比鄰。", "石帆山下菱歌斷，未嘆臨風白髮新。"]'),
('d26c534b-6c8d-4277-a413-46655c49e942','北窗閑詠','陸游','宋','宋诗','song-poetry','','[]','陰陰緑樹雨餘香，半捲疏簾置一床。',64,'全唐诗/poet.song.130000.json','["陰陰緑樹雨餘香，半捲疏簾置一床。", "得禄僅償賒酒劵，思歸新草乞祠章。", "古琴百衲彈清散，名帖雙鈎榻硬黄。", "夜出灞亭雖跌宕，也勝歸作老馮唐。"]'),
('120e74e9-5b1b-4e32-a7f2-b587912182ed','休日留園中至暮乃歸','陸游','宋','宋诗','song-poetry','','[]','儘道官身屬太倉，未妨寄傲向林塘。',64,'全唐诗/poet.song.130000.json','["儘道官身屬太倉，未妨寄傲向林塘。", "緑波春漲群魚樂，清露晨流蔓草香。", "閑試名弓来射圃，醉盤驕馬出毬場。", "長城萬里知誰許，看鏡空悲兩鬢霜。"]'),
('ac5ee9b9-2907-4366-96a2-7ccdb39a1ef0','北窗病起','陸游','宋','宋诗','song-poetry','','[]','一饑可忍萬緣輕，況復幽窗疾漸平。',64,'全唐诗/poet.song.130000.json','["一饑可忍萬緣輕，況復幽窗疾漸平。", "更事天公終賞識，欺人鬼子漫縱横。", "道邊塵起頻障扇，門外波清剩濯纓。", "不爲褊心憎薄俗，客星祠下是歸程。"]'),
('ca5c12da-bcf6-42bc-8423-4a5e02da9d31','自東津泛舟至桐溪','陸游','宋','宋诗','song-poetry','','[]','潮生東西津，雨暗上下塔。',72,'全唐诗/poet.song.130000.json','["潮生東西津，雨暗上下塔。", "蕭蕭亂菰蒲，拍拍起鳬鴨。", "吾船雖褊小，尚可著一榻。", "溪風吹醉頬，高枕墮紗帢。", "南山浮濕翠，偃蹇呼不答。", "安得青蓮公，傑句爲彈壓。"]'),
('a3831853-07eb-4778-a408-2b80fdaef26f','迓客至大浪灘上','陸游','宋','宋诗','song-poetry','','[]','小壟瓜蔓緑，短籬梅子黄。',96,'全唐诗/poet.song.130000.json','["小壟瓜蔓緑，短籬梅子黄。", "曉風掠水来，吹我醉面涼。", "平生蕭散意，未覺将迎忙。", "溪山供一笑，客主可相忘。", "寧當倒手版，聊復據胡床。", "太平豈無象，麥飯家家香。", "我歸亦何有，養氣猶軒昻。", "那因五斗陳，坐變百鍊剛。"]'),
('9af7495c-ea40-4122-9a3f-1d69ad46e2a3','郊行','陸游','宋','宋诗','song-poetry','','[]','小雨東郊氣象新，蕭蕭清吹爽衣巾。',64,'全唐诗/poet.song.130000.json','["小雨東郊氣象新，蕭蕭清吹爽衣巾。", "並谿密竹巧藏寺，夹道新麻高沒人。", "老厭簿書愁欲睡，病疏杯酌渇生塵。", "桐君山路無多遠，元自知津莫問津。"]'),
('256c6763-cd22-433d-a2f1-c36cdf4a048a','夏雨','陸游','宋','宋诗','song-poetry','','[]','東風吹雨溪上来，北山出雲以應之。',96,'全唐诗/poet.song.130000.json','["東風吹雨溪上来，北山出雲以應之。", "嚴州城中三日雨，朝莫點滴無休時。", "向来秧底乾欲裂，白水漫漫俄盈陂。", "豚肩覆豆巫醉飽，龍骨挂壁農遨嬉。", "今年蠶麥收數倍，繭大如瓮麥兩岐。", "西成在眼又如此，還鄉鼓腹歌淳熙。"]'),
('bc1df307-8470-4a38-ac6f-9e1f69a64351','雨中作','陸游','宋','宋诗','song-poetry','','[]','礎潤雲生五月中，山城細雨晚空濛。',64,'全唐诗/poet.song.130000.json','["礎潤雲生五月中，山城細雨晚空濛。", "讀書雖恨此身老，把酒尚思吾輩同。", "積潤畫圖昏素壁，漬香衣幘覆熏籠。", "新晴不用占鍾鼓，卧聽林梢淅淅風。"]'),
('876a385d-8cac-4c68-93ce-d038af99e09c','醉題','陸游','宋','宋诗','song-poetry','','[]','不學空門不學仙，清樽隨處且陶然。',64,'全唐诗/poet.song.130000.json','["不學空門不學仙，清樽隨處且陶然。", "人情正可付一笑，生世元知無百年。", "白首難陪東閤客，清風自足北窗眠。", "歸耕只要無人問，安用文章海內傳。"]'),
('2f20a4e9-493a-4d58-b1af-e3a9cfdb7a56','有懷青城霧中道友','陸游','宋','宋诗','song-poetry','','[]','雪谷孤松自鬱然，紛紛朝菌但堪憐。',64,'全唐诗/poet.song.130000.json','["雪谷孤松自鬱然，紛紛朝菌但堪憐。", "坐更拂石芥城劫，時說開皇龍漢年。", "淡煮藜羮天送供，閑拖藤杖地行仙。", "共看王室中興後，更約長安一醉眠。"]'),
('c68b90c7-1cd7-4dfd-b068-3fd03640c541','梅雨初晴迓客東郊','陸游','宋','宋诗','song-poetry','','[]','霽色澄鮮已斷梅，江郊隠隠尚輕雷。',64,'全唐诗/poet.song.130000.json','["霽色澄鮮已斷梅，江郊隠隠尚輕雷。", "層巒正對孤城落，健席遥看大艑来。", "幼婦髻鬟簮早稻，近村坊店賣新醅。", "吾行在處皆詩本，錦段雖殘試剪裁。"]'),
('b4e454cc-1e27-4949-af93-328cf557581d','晚歸','陸游','宋','宋诗','song-poetry','','[]','暑雨初晴日，江皋欲莫天。',48,'全唐诗/poet.song.130000.json','["暑雨初晴日，江皋欲莫天。", "鴉棲沙際樹，人喚渡頭船。", "病骨羸将折，昏眸困欲眠。", "市橋燈火閙，且復喜豐年。"]'),
('2505a608-8b4f-4858-8bdf-a1d498eb0623','休日登千峰榭遇大風雨氣象甚偉','陸游','宋','宋诗','song-poetry','','[]','今日逢休沐，憑高且暫閑。',48,'全唐诗/poet.song.130000.json','["今日逢休沐，憑高且暫閑。", "風聲初捲野，雨氣已呑山。", "疾病臨觴懶，塵埃得句慳。", "西征忽在眼，河勢抱函關。"]'),
('ac974259-1090-493f-838d-d682d29125fe','雨中獨坐','陸游','宋','宋诗','song-poetry','','[]','馬目山頭雨脚昏，龍津橋下浪花翻。',32,'全唐诗/poet.song.130000.json','["馬目山頭雨脚昏，龍津橋下浪花翻。", "年豐郡僻無公事，一炷清香晝掩門。"]'),
('8679d942-7dcd-4441-afec-12ece67ce6a1','舊識姜邦傑於亡友韓无咎許近屢寄詩来且以无咎平日倡和見示讀之悵然作此詩附卷末','陸游','宋','宋诗','song-poetry','','[]','故人玉骨已生苔，邂逅逢君亦樂哉。',64,'全唐诗/poet.song.130000.json','["故人玉骨已生苔，邂逅逢君亦樂哉。", "湖寺繫舟無夢去，京塵馳騎有詩来。", "醉中不敢教兒誦，看處常須浴手開。", "久矣世間無健筆，相期力幹萬鈞回。"]'),
('f5931a40-1419-466d-b514-a744e7a68866','釣臺見送客罷還舟熟睡至覺度寺','陸游','宋','宋诗','song-poetry','','[]','抽身簿書中，兹日睡頗足。',96,'全唐诗/poet.song.130000.json','["抽身簿書中，兹日睡頗足。", "縹緲桐君山，可喜忽在目。", "紛紛衆客散，杳杳一笻獨。", "昔如脫淵魚，今如走山鹿。", "詩情森欲動，茶鼎煎正熟。", "安眠簟八尺，仰看帆十幅。", "逍遥富春飯，放浪漁浦宿。", "送老水雲鄉，羮藜勿思肉。"]'),
('fe82e30c-b88b-422b-b4be-1e588730ce9c','泛富春江','陸游','宋','宋诗','song-poetry','','[]','雙櫓揺江疊鼓催，伯符故國喜重来。',64,'全唐诗/poet.song.130000.json','["雙櫓揺江疊鼓催，伯符故國喜重来。", "秋山斷處望漁浦，曉日昇時離釣臺。", "官路已悲捐歲月，客衣仍悔犯風埃。", "還家正及雞豚社，剩伴鄰翁笑口開。"]'),
('d5622df4-9def-40a9-b2a0-7d989eb43bb9','宿漁浦','陸游','宋','宋诗','song-poetry','','[]','東歸剡曲只三程，旅泊還如萬里行。',64,'全唐诗/poet.song.130000.json','["東歸剡曲只三程，旅泊還如萬里行。", "燈影動揺風不定，船聲鞺鞳浪初生。", "曳裾非復白頭事，瞑目那求青史名。", "歸去若爲消暮境，一蓑烟雨學春耕。"]'),
('b3143177-427e-4121-b8de-04b3e150c0fe','泝小江飯舟中','陸游','宋','宋诗','song-poetry','','[]','老作孤舟客，秋濤漲小江。',48,'全唐诗/poet.song.130000.json','["老作孤舟客，秋濤漲小江。", "林昏見飛燐，村近有驚尨。", "天濶三更月，篷低一尺窗。", "魚飱雖草草，聊喜到吾邦。"]'),
('5ba13555-a499-478b-929c-3eabe0541f58','乞祠久未報','陸游','宋','宋诗','song-poetry','','[]','聖朝未許領樷祠，擁褐清羸不自支。',64,'全唐诗/poet.song.130000.json','["聖朝未許領樷祠，擁褐清羸不自支。", "鄧禹有靈應笑拙，周公無夢固知衰。", "得閑要及身安日，到死應無睡足時。", "七百日来塵滿抱，今朝湔祓有新詩。"]'),
('cc9fba7e-e5bc-4a8b-b9ce-65801ee8d676','七月十日到故山削瓜瀹茗翛然自適','陸游','宋','宋诗','song-poetry','','[]','鏡湖清絕勝吳松，家占湖山第一峰。',64,'全唐诗/poet.song.130000.json','["鏡湖清絕勝吳松，家占湖山第一峰。", "瓜冷霜刀開碧玉，茶香銅碾破蒼龍。", "壮心自笑老猶在，狂態極知人不容。", "擊壤窮閻歌帝力，未妨堯舜亦親逢。"]'),
('d7e38939-202b-46e4-ae41-39c0c6e372c2','曉興','陸游','宋','宋诗','song-poetry','','[]','亂蟬嘒新秋，老木立清曉。',96,'全唐诗/poet.song.130000.json','["亂蟬嘒新秋，老木立清曉。", "我亦岸綸巾，寄傲萬物表。", "大千藏粒粟，浩劫過飛鳥。", "癡子居其間，利欲自纒繞。", "可憐榮進意，未向盖棺了。", "浮名更嚇鬼，白堊寫丹旐。", "我於斯世事，看破自少小。", "老矣更何求，歸哉憩林沼。"]'),
('828c71d5-f119-44a5-b1a7-8de009b65128','感秋','陸游','宋','宋诗','song-poetry','','[]','會稽八月秋始涼，梧桐葉落覆井床。',99,'全唐诗/poet.song.130000.json','["會稽八月秋始涼，梧桐葉落覆井床。", "月明縞樹遶驚鵲，露下濕草啼寒螀。", "丈夫行年過六十，日月雖短志意長。", "匣中寶劍作雷吼，神物那得終摧藏。", "君不見昔時東都宗大尹，義感百萬虎與狼。", "疾危尚念起擊賊，大呼過河身已僵。"]'),
('73a664ec-18bb-447f-b4c9-e4b9d433022e','秋夜有感','陸游','宋','宋诗','song-poetry','','[]','候蟲何唧唧，歲晚聲出壁。',144,'全唐诗/poet.song.130000.json','["候蟲何唧唧，歲晚聲出壁。", "不惟懶婦驚，感此白頭客。", "壮年事征戍，萬里不得息。", "揚颿凌秋濤，筞馬赴山驛。", "日照蛟鼉涎，雪印豺虎迹。", "誰知七尺軀，幸脫九死厄。", "前年補畿郡，入對瞻玉色。", "報恩無死所，再拜衰泪滴。", "即今故山歸，愈嘆老境逼。", "不眠中夜起，仰視星歴歴。", "中原何時定，銅駞卧荆棘。", "滅胡恨無人，有復不易識。"]'),
('a3247871-b385-44c6-b266-827c03887f42','五鼓入城','陸游','宋','宋诗','song-poetry','','[]','道旁竹樹露如傾，带睡悠悠十里行。',32,'全唐诗/poet.song.130000.json','["道旁竹樹露如傾，带睡悠悠十里行。", "曉色未分烟尚重，壓城樓閣已崢嶸。"]'),
('2c9c676b-d4d2-4398-ac5d-22f2fcf5db87','飯罷忽鄰父来過戱作','陸游','宋','宋诗','song-poetry','','[]','旋炊香稻煮新菰，飯飽逍遥樂有餘。',64,'全唐诗/poet.song.130000.json','["旋炊香稻煮新菰，飯飽逍遥樂有餘。", "茶味森森留齒頬，香烟𩡏𩡏著圖書。", "毛皮尚在寧知我，鱗甲深藏莫問渠。", "賴有鄰翁差耐久，雨畦頻喚共攜鉏。"]'),
('ce76ef69-4e65-4720-8bd6-2ba66a55096f','秋夜讀書','陸游','宋','宋诗','song-poetry','','[]','一雨濯殘熱，秋氣忽已深。',72,'全唐诗/poet.song.130000.json','["一雨濯殘熱，秋氣忽已深。", "青燈照空廊，重露滴高林。", "危坐讀周易，會我平生心。", "夜分徐掩卷，閑弄床上琴。", "簾外初斜河，屋頭已横參。", "人生每如此，利欲安能侵。"]'),
('85f74c6a-14fd-40ce-91d4-3a3c00ab63b8','夜坐忽聞村路報曉鐵牌二首  其一','陸游','宋','宋诗','song-poetry','','[]','何人叩鐵警農耕，炊飯家家起五更。',32,'全唐诗/poet.song.130000.json','["何人叩鐵警農耕，炊飯家家起五更。", "也似早朝風雪裏，遥聽宫漏下宫城。"]'),
('bd8ca3cb-8fef-4719-989b-32978513b182','夜坐忽聞村路報曉鐵牌二首  其二','陸游','宋','宋诗','song-poetry','','[]','秋氣凄涼霧雨昏，老書生病卧孤村。',32,'全唐诗/poet.song.130000.json','["秋氣凄涼霧雨昏，老書生病卧孤村。", "五更不用元戎報，片鐵錚錚自過門。"]'),
('bb2253aa-85f9-4a28-a59c-fada7cb7c6e5','白雲自西来過書巢南窗','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','岷山千里青未了，恨隔長江不到吳。',32,'全唐诗/poet.song.130000.json','["岷山千里青未了，恨隔長江不到吳。", "羈雲冉冉吾舊識，安得挽之来坐隅。"]'),
('c50b5f10-b030-4169-a593-f419722d8415','贈竹十韵','陸游','宋','宋诗','song-poetry','','[]','放翁小築湖西偏，虛窗曲檻無炎天。',160,'全唐诗/poet.song.130000.json','["放翁小築湖西偏，虛窗曲檻無炎天。", "人間乃有真富貴，遶舍十萬碧玉椽。", "連林娟娟泫清露，高枝裊裊揺蒼烟。", "常憂俗客觸新粉，屢戒園丁傷逸鞭。", "涼生尊斚消午醉，聲撼窗扉驚晝眠。", "春殘斸土得美茁，氣壓卿相食萬錢。", "爾来作吏若墮穽，每一夢到心悽然。", "還家再見却惝怳，塵土何地從臞仙。", "囊中幸藏餐玉法，欲屏萬事相周旋。", "更當待月出東嶺，坐石泠泠揮響泉。"]'),
('03443abd-3978-4deb-962b-19be018fe4d8','雜感五首  其一','陸游','宋','宋诗','song-poetry','','[]','自古文章與命仇，功名身外更悠悠。',32,'全唐诗/poet.song.130000.json','["自古文章與命仇，功名身外更悠悠。", "一從識得元無事，窮死逢人不說愁。"]'),
('0a31a240-8083-42ae-8302-caf38bc431b1','雜感五首  其二','陸游','宋','宋诗','song-poetry','','[]','小軒幽檻雨絲絲，種竹移花及此時。',32,'全唐诗/poet.song.130000.json','["小軒幽檻雨絲絲，種竹移花及此時。", "客去解衣投卧榻，半醒半醉又成詩。"]'),
('0e42dc08-1769-42c3-8952-23c179e852e0','雜感五首  其三','陸游','宋','宋诗','song-poetry','','[]','少年意氣與春爭，朱彈金鞭處處行。',32,'全唐诗/poet.song.130000.json','["少年意氣與春爭，朱彈金鞭處處行。", "誰信即今空谷裏，旋租黄犢學躬耕。"]'),
('6d70d28f-c5cc-4277-8a6e-0425cf881b75','雜感五首  其四','陸游','宋','宋诗','song-poetry','','[]','自洗銅壺試玉醅，小軒風月爲徘徊。',32,'全唐诗/poet.song.130000.json','["自洗銅壺試玉醅，小軒風月爲徘徊。", "此心未與年俱老，猶解逢花眼暫開。"]'),
('7bb58aac-400a-4f99-8791-364185649c38','雜感五首  其五','陸游','宋','宋诗','song-poetry','','[]','側帽垂鞭小陌東，名花迎笑一枝紅。',32,'全唐诗/poet.song.130000.json','["側帽垂鞭小陌東，名花迎笑一枝紅。", "啼鶯驚斷尋春夢，惆悵新霜點鬢蓬。"]'),
('c054bee1-3e2d-48dd-9081-91b77522c374','入城寓榻開元','陸游','宋','宋诗','song-poetry','','[]','羸僮倦馬困長堤，借榻禪房日未西。',32,'全唐诗/poet.song.130000.json','["羸僮倦馬困長堤，借榻禪房日未西。", "熟睡覺来閑隠几，庭楸陰轉乳鴉啼。"]'),
('0ffeff23-fdce-416a-8324-5644ecfe3502','夜出偏門還三山','陸游','宋','宋诗','song-poetry','','[]','月行南斗邊，人歸西郊路。',72,'全唐诗/poet.song.130000.json','["月行南斗邊，人歸西郊路。", "水風吹葛衣，草露濕芒履。", "漁歌起遠汀，鬼火出破墓。", "凄清醒醉魂，荒怪入詩句。", "到家夜已半，佇立叩蓬戸。", "穉子猶讀書，一笑慰遲莫。"]'),
('e28b428f-24b6-4e10-bb7f-b1d6a5a5c965','四鼓酒醒起步庭下','陸游','宋','宋诗','song-poetry','','[]','酒解夜過半，出門步中庭。',96,'全唐诗/poet.song.130000.json','["酒解夜過半，出門步中庭。", "天高河漢白，月淡烟霧青。", "重滴竹杪露，踈見樹罅星。", "壊甃啼寒螀，深竹明孤螢。", "秋晚雖未霜，蠧葉時自零。", "四序逝不留，慨然感頽齡。", "平生茅一把，不博带萬釘。", "鴟溝謝拍拍，鴻路追冥冥。"]'),
('67014ea9-6e70-4f8a-98b4-0ce4daf0f5b0','感憤秋夜作','陸游','宋','宋诗','song-poetry','','[]','月昏當戸樹突兀，風惡滿天雲往来。',64,'全唐诗/poet.song.130000.json','["月昏當戸樹突兀，風惡滿天雲往来。", "太阿匣藏不見用，孤憤書成空自哀。", "吾輩赤心本貫日，昔人白骨今生苔。", "榮河温洛不可見，青海玉關安在哉。"]'),
('75ffb1d4-86b7-44a3-ae42-03fc8b0f19a9','反感憤','陸游','宋','宋诗','song-poetry','','[]','膊膊庭樹雞初鳴，嗈嗈天衢雁南征。',64,'全唐诗/poet.song.130000.json','["膊膊庭樹雞初鳴，嗈嗈天衢雁南征。", "百年朝露豈長久，萬事浮雲常變更。", "出處有心終有愧，聖賢無命亦無成。", "西疇雖薄可自力，雙犢且當乘雨耕。"]'),
('c6c4e012-fa25-4f3a-969f-6bc5ce998aad','東齋','陸游','宋','宋诗','song-poetry','','[]','著脚紅塵已恨深，便應畢世住山林。',64,'全唐诗/poet.song.130000.json','["著脚紅塵已恨深，便應畢世住山林。", "貴人自作宣明面，老子曾聞正始音。", "議論坐狂當永棄，簿書緣病復難任。", "東齋幽寂憑誰畫，開幔床横一素琴。"]'),
('24ae855c-985a-4a8d-a622-15f46ed93342','雨夜四鼓起坐至明','陸游','宋','宋诗','song-poetry','','[]','門巷冷如冰，生涯淡似僧。',48,'全唐诗/poet.song.130000.json','["門巷冷如冰，生涯淡似僧。", "小窗愁夜雨，孤影怯秋燈。", "林鵲棲仍起，山童喚不譍。", "悠然坐待旦，息倦倚書幐。"]'),
('1b3c5c41-2ddd-431a-b4e5-20d9c079822a','夜讀兵書','陸游','宋','宋诗','song-poetry','','[]','八月風雨夕，千載孫吴書。',96,'全唐诗/poet.song.130000.json','["八月風雨夕，千載孫吴書。", "老病雖憊甚，壮氣頗有餘。", "長纓果可請，上馬不躊躇。", "豈惟鏖皋蘭，直欲封狼居。", "萬乘久巡狩，兩京盡邱墟。", "此責在臣子，憂愧何時攄。", "南鄭築壇場，隆中顧草廬。", "邂逅未可知，旄頭方掃除。"]'),
('fdb15344-4475-47fa-a235-3be3f181facf','老嘆','陸游','宋','宋诗','song-poetry','','[]','百年逝不留，萬事本難料。',48,'全唐诗/poet.song.130000.json','["百年逝不留，萬事本難料。", "夜行鐘漏迫，但取賢達笑。", "頗疑功名事，造物付年少。", "歸休莫問人，曉鏡勤自照。"]'),
('eb17b905-82b2-4fbb-8342-879cbe6fa072','秋霽','陸游','宋','宋诗','song-poetry','','[]','灝氣明山川，霽色滿天地。',48,'全唐诗/poet.song.130000.json','["灝氣明山川，霽色滿天地。", "西風吹我衣，忽有萬里意。", "中原運當平，所要在得士。", "餘年猶幾何，棄置復棄置。"]'),
('0956e4a2-38c6-4aaf-80ab-165191324570','齋中聞急雨','陸游','宋','宋诗','song-poetry','','[]','一味疏慵養不才，飯蔬亦已罷衘杯。',32,'全唐诗/poet.song.130000.json','["一味疏慵養不才，飯蔬亦已罷衘杯。", "衡茆終日人聲絕，卧聽芭蕉報雨来。"]'),
('975eb011-6bea-41ef-be4d-68a253c07909','老病追感壮歲讀書之樂作短歌','陸游','宋','宋诗','song-poetry','','[]','少年志力强，文史富三冬。',144,'全唐诗/poet.song.130000.json','["少年志力强，文史富三冬。", "但喜寒夜永，那知睡味濃。", "庭樹風淅淅，城樓鼓鼕鼕。", "自鞭不少貸，凍坐聞晨鐘。", "探義劇攻玉，摛文笑雕龍。", "落紙筆縱横，圍坐書疊重。", "得意自吟諷，清悲答莎蛩。", "饑腸得一餅，美如紫駞峰。", "俯仰五十年，于世終不逢。", "夜半起飯牛，頹然成老農。", "束書不更讀，蠧簡流塵封。", "世無袁伯業，太息吾何從。"]'),
('41c97dfd-e883-4869-b0ce-f4469203872e','閑中戯書三首  其一','陸游','宋','宋诗','song-poetry','','[]','糲飯從来不願餘，還山喜遂此心初。',64,'全唐诗/poet.song.130000.json','["糲飯從来不願餘，還山喜遂此心初。", "挽河盡洗彈冠念，閉戸閑讐插架書。", "一榼不妨從客飲，數椽也復是吾廬。", "少游細看猶多事，安用人間下澤車。"]'),
('d56846b4-57bb-43d3-983f-c50d60592712','閑中戯書三首  其二','陸游','宋','宋诗','song-poetry','','[]','少年拜舞綴庭紳，曾見中天日月新。',64,'全唐诗/poet.song.130000.json','["少年拜舞綴庭紳，曾見中天日月新。", "金印終歸妄校尉，白頭仍是斥仙人。", "修營香火三生願，收拾風波九死身。", "豈但漁樵與爭席，海邊漚鳥亦相親。"]'),
('ba727a2c-c1e2-463d-9e60-4092b645fe8d','閑中戯書三首  其三','陸游','宋','宋诗','song-poetry','','[]','釣竿風月寄滄洲，醉髮髿髿荻葉秋。',64,'全唐诗/poet.song.130000.json','["釣竿風月寄滄洲，醉髮髿髿荻葉秋。", "仕進世誰知我懶，功名命不與人謀。", "衰遲更覺歲時速，疏賤空先天下憂。", "病骨未銷讒未已，聊須周易著床頭。"]'),
('6b5b91b9-e5ed-4757-9ce0-e94e90111510','采藥','陸游','宋','宋诗','song-poetry','','[]','篢子編成細箬新，獨穿空翠上嶙峋。',64,'全唐诗/poet.song.130000.json','["篢子編成細箬新，獨穿空翠上嶙峋。", "丹砂巖際朝暾日，狗杞雲間夜吠人。", "絡石菖蒲蒙緑髮，纒松薜荔長蒼鱗。", "金貂謁帝我未暇，且作人間千歲身。"]'),
('385593b1-b4b5-4d21-8ad8-f99a60c26b78','過猷講主桑瀆精舍','陸游','宋','宋诗','song-poetry','','[]','寂寞衡門傍水開，放翁曳杖此徘徊。',64,'全唐诗/poet.song.130000.json','["寂寞衡門傍水開，放翁曳杖此徘徊。", "林疏時見釣篷過，風急忽聞菱唱来。", "講罷繩床懸麈柄，齋餘童子供茶杯。", "解衣許我閑摩腹，又作幽窗夢一回。"]'),
('b79dbf18-29f0-4984-af3c-cffd111e411b','自桑瀆泛舟歸三山','陸游','宋','宋诗','song-poetry','','[]','端爲身閑覺日長，不嫌兒輩笑清狂。',64,'全唐诗/poet.song.130000.json','["端爲身閑覺日長，不嫌兒輩笑清狂。", "湖光瀲瀲歸舟疾，雨點霏霏醉頬涼。", "斷彴苔生人喚渡，孤村霜近稻登場。", "宦情不獨今年薄，游子從来念故鄉。"]'),
('4018edb6-4827-4c8b-97de-188c2812ae87','訪野人家','陸游','宋','宋诗','song-poetry','','[]','山入柴門穿，橋通野路長。',48,'全唐诗/poet.song.130000.json','["山入柴門穿，橋通野路長。", "群童挑燕筍，幼婦采雞桑。", "淳古非今俗，留連到夕陽。", "盤飱敢辭飽，滿箸藥苗香。"]'),
('09fb0854-2fc1-455d-9028-dfc0d7ee31e0','塞上曲四首  其一','陸游','宋','宋诗','song-poetry','','[]','秋風獵獵漢旗黄，曉陌霜清見太行。',32,'全唐诗/poet.song.130000.json','["秋風獵獵漢旗黄，曉陌霜清見太行。", "車載氊廬駞載酒，漁陽城裏作重陽。"]'),
('79acd11c-b699-4bef-8d59-d4fa0ad734aa','塞上曲四首  其二','陸游','宋','宋诗','song-poetry','','[]','将軍許國不懷歸，又見桑乾木葉飛。',32,'全唐诗/poet.song.130000.json','["将軍許國不懷歸，又見桑乾木葉飛。", "要識君王念征戍，新秋已報賜冬衣。"]'),
('4e07d47f-d6c1-413c-a20a-7d2f226bd1fc','塞上曲四首  其三','陸游','宋','宋诗','song-poetry','','[]','金鼓轟轟百里聲，繡旗寶馬照川明。',32,'全唐诗/poet.song.130000.json','["金鼓轟轟百里聲，繡旗寶馬照川明。", "王師仗義從天下，莫道南兵夜斫營。"]'),
('80b602c1-8b73-456a-a123-ff716f9633e5','塞上曲四首  其四','陸游','宋','宋诗','song-poetry','','[]','老矣猶思萬里行，翩然上馬始身輕。',32,'全唐诗/poet.song.130000.json','["老矣猶思萬里行，翩然上馬始身輕。", "玉關去路心如鐵，把酒何妨聽渭城。"]'),
('501fd587-220d-432b-bb00-bd0bc3bac8cf','硯湖','陸游','宋','宋诗','song-poetry','','[]','群山環一湖，湖水緑溶漾。',96,'全唐诗/poet.song.130000.json','["群山環一湖，湖水緑溶漾。", "微風掠窗過，亦解生細浪。", "餘流浸翠麓，倒影寫青嶂。", "自然出天工，豈復煩巧匠。", "病夫屏杯酌，不遣運酒舫。", "時時挹清泚，筆墨助豪宕。", "帖成龍蛇走，詩出雷雨壮。", "從今几硯旁，一掃蟾蜍樣。"]'),
('06bc8d19-659a-4571-8a89-1d8079d14d01','泛湖','陸游','宋','宋诗','song-poetry','','[]','筆床茶竈釣魚竿，瀲瀲平湖淡淡山。',32,'全唐诗/poet.song.130000.json','["筆床茶竈釣魚竿，瀲瀲平湖淡淡山。", "浪說枕戈心萬里，此身常在水雲間。"]'),
('0e630cb0-7f93-46e9-bb07-77bb21d3fadf','寓蓬萊館二首  其一','陸游','宋','宋诗','song-poetry','','[]','桐葉吹殘蕉葉黄，驛窗微雨送凄涼。',32,'全唐诗/poet.song.130000.json','["桐葉吹殘蕉葉黄，驛窗微雨送凄涼。", "長安許史無平素，莫恨棲棲立路旁。"]'),
('538c7b29-732d-4632-906a-847543c4551f','寓蓬萊館二首  其二','陸游','宋','宋诗','song-poetry','','[]','古驛蕭蕭獨倚闌，角聲催晚雨催寒。',32,'全唐诗/poet.song.130000.json','["古驛蕭蕭獨倚闌，角聲催晚雨催寒。", "殘年遇合應無日，猶說新豐强自寛。"]'),
('6aef89ae-b397-4008-b700-7cd16f64a12e','夜還驛舍','陸游','宋','宋诗','song-poetry','','[]','樓上鼕鼕初發更，斷雲收雨旋成晴。',64,'全唐诗/poet.song.130000.json','["樓上鼕鼕初發更，斷雲收雨旋成晴。", "市橋新漲揺燈影，驛路殘泥壮屐聲。", "闤闠變遷非曩日，情懷牢落感餘生。", "高秋病起猶能醉，剩買官醅樂太平。"]'),
('0630cac5-fe4f-44f8-8ef5-8013917c86be','舟中大醉偶賦長句','陸游','宋','宋诗','song-poetry','','[]','過江何敢號高流，偶與俗人風馬牛。',64,'全唐诗/poet.song.130000.json','["過江何敢號高流，偶與俗人風馬牛。", "畫檝新揺嚴瀨月，清尊又醉戴溪秋。", "壮心無復在千里，老氣尚能横九州。", "古寺試求三丈壁，爲君驅筆戰蛟虬。"]'),
('a4fea934-532c-4b23-9477-0ba3c155ebad','行飯至新塘夜歸','陸游','宋','宋诗','song-poetry','','[]','門前徙倚尚餘霞，湖上歸来月滿沙。',64,'全唐诗/poet.song.130000.json','["門前徙倚尚餘霞，湖上歸来月滿沙。", "雲濕一聲新到雁，林昏數點後棲鴉。", "凄迷籬落開寒菊，鄭重比鄰設夜茶。", "早議挂冠君會否，暮年心念不容差。"]'),
('9f47cf7f-79e2-4a65-b3a1-4017f4621438','雲門感舊','陸游','宋','宋诗','song-poetry','','[]','總角来逰老未忘，背人歲月去堂堂。',64,'全唐诗/poet.song.130000.json','["總角来逰老未忘，背人歲月去堂堂。", "穉松看到偃霜盖，廢寺憶曾開寶坊。", "佛几古燈寒焰短，齋厨新粟午炊香。", "興闌未忍登車去，更倚溪橋立夕陽。"]'),
('f2ad4505-6ada-42ed-aa3e-e6a584a26fa8','若耶溪上二首  其一','陸游','宋','宋诗','song-poetry','','[]','微官元不直鱸魚，何況人間足畏途。',32,'全唐诗/poet.song.130000.json','["微官元不直鱸魚，何況人間足畏途。", "今日溪頭慰心處，自尋白石養菖蒲。"]'),
('2f391b0a-71e9-42bc-8868-ceac7a11db8c','若耶溪上二首  其二','陸游','宋','宋诗','song-poetry','','[]','九月霜風吹客衣，溪頭紅葉傍人飛。',32,'全唐诗/poet.song.130000.json','["九月霜風吹客衣，溪頭紅葉傍人飛。", "村場酒薄何妨醉，菰正堪烹蟹正肥。"]'),
('dd245288-d872-4c9e-936f-e5de1d22b4df','秋雨頓寒偶書','陸游','宋','宋诗','song-poetry','','[]','羈懷不醉自昏昏，卧對青燈獨掩門。',64,'全唐诗/poet.song.130000.json','["羈懷不醉自昏昏，卧對青燈獨掩門。", "沙雁带寒来古澤，林鳩催雨暗孤村。", "數椽蟹舍償初志，九陌塵衣洗舊痕。", "自嘆一生書裏活，暮年無力濟黎元。"]'),
('75d9a990-2540-4cb3-ace8-b2489d37c525','新晴泛舟至近村偶得雙鱖而歸','陸游','宋','宋诗','song-poetry','','[]','秋風一夜老汀蘋，剡曲稽山發興新。',64,'全唐诗/poet.song.130000.json','["秋風一夜老汀蘋，剡曲稽山發興新。", "青嶂會爲身後塚，扁舟聊作畫中人。", "園林揺落知寒早，父老逢迎覺意真。", "歸舍不妨成小醉，眼明細柳貫霜鱗。"]'),
('2d93c679-9b0f-49ea-abc6-876d2ff4995c','上書乞祠輒述鄙懷','陸游','宋','宋诗','song-poetry','','[]','干禄本代耕，窮達敢自必。',216,'全唐诗/poet.song.130000.json','["干禄本代耕，窮達敢自必。", "早遇高皇帝，九品對宣室。", "妄懷犬馬心，嫠緯不暇恤。", "上恩等天地，腰領免斧鑕。", "旋屬紹興末，暘谷瞻出日。", "賤臣復何幸，便殿首造膝。", "煌煌帝堯典，推擇首秉筆。", "愚忠雖懇欵，野性實坦率。", "飄然去周行，湖海抱沉疾。", "遠逰客窮塞，亭障秋蕭瑟。", "聖君終記省，萬里忽乘馹。", "同朝久凋謝，存者不十一。", "造廷故抱暗，下殿衰涕溢。", "蹉跎又十載，憂患豈易述。", "流年不貸人，白髮日夜宻。", "冠雖未即挂，馭己不容叱。", "尚覬公朝恩，養老霑散秩。", "閉門教子孫，志願真永畢。"]'),
('dc3db5f7-95c2-4843-b0ae-ef0214e0aa79','泛湖上雲門','陸游','宋','宋诗','song-poetry','','[]','三百里湖秋渺然，是間可以著釣船。',96,'全唐诗/poet.song.130000.json','["三百里湖秋渺然，是間可以著釣船。", "浩歌莫過石帆下，爛醉夜泊樵風邊。", "茫茫沙月忽側墮，裊裊山氣時孤鶱。", "冥鴻遠舉謝斯世，白鷗自放全其天。", "幽棲幸脱市朝械，捷徑那著功名鞭。", "人生各自適意耳，稷禹巢許知誰賢。"]'),
('f43f5381-f07e-4997-a875-c28e7d396675','書嘆','陸游','宋','宋诗','song-poetry','','[]','世態秦欺楚，交情越視秦。',48,'全唐诗/poet.song.130000.json','["世態秦欺楚，交情越視秦。", "寧教待羝乳，不耐望車塵。", "書積高圍坐，花繁亂插巾。", "那須散人號，已是葛天民。"]'),
('375ac663-ec2f-477b-bc89-93b3e6e21788','枕上作','陸游','宋','宋诗','song-poetry','','[]','寒夜卧林廬，蕭然適有餘。',48,'全唐诗/poet.song.130000.json','["寒夜卧林廬，蕭然適有餘。", "蟲悲號壊壁，燈暗守殘書。", "養拙天知我，安貧老似初。", "雖非漆園吏，也作蝶蘧蘧。"]'),
('c3e79b6b-7f65-4d20-a5d9-323a8f7dd138','老病無復宦情或者疑焉作此示之','陸游','宋','宋诗','song-poetry','','[]','病思蕭條豈獨今，十年前已鬢霜侵。',64,'全唐诗/poet.song.130000.json','["病思蕭條豈獨今，十年前已鬢霜侵。", "舊交略盡形吊影，薄宦宜休口語心。", "老驥已甘當伏櫪，窮猿況是急投林。", "别君徑入亂雲去，後日相思何處尋。"]'),
('f55e4f17-aa49-4d23-a5f9-ecb8c14f9612','拄杖','陸游','宋','宋诗','song-poetry','','[]','放翁拄杖具神通，蜀棧吴山興未窮。',32,'全唐诗/poet.song.130000.json','["放翁拄杖具神通，蜀棧吴山興未窮。", "昨夜夢中行萬里，蓮華峰上聽松風。"]'),
('e8d0c0ba-ca69-40eb-a94e-4818297e99e5','北望','陸游','宋','宋诗','song-poetry','','[]','北望中原泪滿巾，黄旗空想渡河津。',32,'全唐诗/poet.song.130000.json','["北望中原泪滿巾，黄旗空想渡河津。", "丈夫窮死由来事，要是江南有此人。"]'),
('bb55bba7-7c42-4c62-a9e5-8b10a8eed371','歲晚感懷','陸游','宋','宋诗','song-poetry','','[]','利名爭奪兩皆非，生世寧殊露易晞。',64,'全唐诗/poet.song.130000.json','["利名爭奪兩皆非，生世寧殊露易晞。", "老冉冉来誰獨免，冢纍纍處會同歸。", "聽歌莫惜終三疊，縱獵何妨更一圍。", "醉卧日高呼不醒，笑人霜曉束朝衣。"]'),
('2ec6047b-a9a9-4180-91ea-bb2ea30a275b','大雨中作','陸游','宋','宋诗','song-poetry','','[]','北風撼山勢岌岌，老夫倚杖檐前立。',96,'全唐诗/poet.song.130000.json','["北風撼山勢岌岌，老夫倚杖檐前立。", "貪看白雨掠地風，飄灑不知衣盡濕。", "當年入朝甫三十，十丈邊塵叩江急。", "屬聞蠟彈遣檄書，亟壊布裳縫袴褶。", "即今白髮不可數，破屋頹垣窘風雨。", "汝生汝死問者誰，人雖不問心自悲。"]'),
('17d7d171-93a8-4bf6-9880-565ff07e12f8','繫舟平水步','陸游','宋','宋诗','song-poetry','','[]','舟尾參差野岸横，屐聲穿市得閑行。',64,'全唐诗/poet.song.130000.json','["舟尾參差野岸横，屐聲穿市得閑行。", "雨昏茆店炊烟濕，人語蓬窗績火明。", "枝上橙香初受摘，擔頭菰脆正堪烹。", "漁樵自是平生意，不爲衰遲薄宦情。"]'),
('5c017869-0e4b-4949-b535-e561b3a64a78','初到行在','陸游','宋','宋诗','song-poetry','','[]','六十之年又四年，也騎瘦馬趁朝天。',64,'全唐诗/poet.song.130000.json','["六十之年又四年，也騎瘦馬趁朝天。", "首陽柱下孰工拙，從事督郵俱聖賢。", "筆墨有時閑作戯，功名到底是無緣。", "都城處處園林好，不許山翁醉放顛。"]'),
('d988a8ad-9f22-48f9-a02a-0d33d7e6b9c1','還都','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','平生薄名宦，所願得早休。',96,'全唐诗/poet.song.130000.json','["平生薄名宦，所願得早休。", "奔走三十年，鏡中霜鬢秋。", "歸踏長安道，恍然皆舊逰。", "處處見題名，始驚歲月遒。", "西湖隔城門，放浪輸白鷗。", "當時見種柳，已足繫巨舟。", "挂冠當自決，安用從人謀。", "勿以有限身，常供無盡愁。"]'),
('a41da1c3-bbb6-4da7-bf17-71e22753e227','宿監中偶作','陸游','宋','宋诗','song-poetry','','[]','流落歸来兩鬢絲，此生真愧北山移。',64,'全唐诗/poet.song.130000.json','["流落歸来兩鬢絲，此生真愧北山移。", "數殘宫漏寒無寐，開盡梅花病不知。", "同舍破甘醒宿酒，故人折簡索新詩。", "生涯可笑清如許，枉是京塵撲馬時。"]'),
('27a845fe-f33b-4f28-9984-8a96e9a73226','四鼓出嘉會門赴南郊齋宫','陸游','宋','宋诗','song-poetry','','[]','客逰梁益半吾生，不死還能見太平。',64,'全唐诗/poet.song.130000.json','["客逰梁益半吾生，不死還能見太平。", "初喜夢魂朝帝所，更驚老眼看都城。", "九重宫闕晨霜冷，十里樓臺落月明。", "白髮蒼顔君勿笑，少年慣聽舜韶聲。"]'),
('c49978b7-ddde-4a19-acb4-982fd66128aa','題張野夫監簿大招圖','陸游','宋','宋诗','song-poetry','','[]','此生只合老漁樵，扶病誰令趁早朝。',32,'全唐诗/poet.song.130000.json','["此生只合老漁樵，扶病誰令趁早朝。", "開卷未終三太息，羈魂零落恐難招。"]'),
('d114a788-a482-4dab-95e8-b6041d7f598d','簡譚德稱監丞','陸游','宋','宋诗','song-poetry','','[]','廣都江上送舟行，泪灑春風别少城。',64,'全唐诗/poet.song.130000.json','["廣都江上送舟行，泪灑春風别少城。", "冉冉幾經新歲律，依依猶有舊交情。", "塵冠當挂彈何用，革带頻移瘦自驚。", "剩欲約公風雨夜，一燈相對話平生。"]'),
('3caf3f82-47c7-49c8-bb8c-bdb478a3e1e7','致齋監中夜與同官縱談鬼神效宛陵先生體','陸游','宋','宋诗','song-poetry','','[]','五客圍一爐，夜語窮幻怪。',144,'全唐诗/poet.song.130000.json','["五客圍一爐，夜語窮幻怪。", "或誇雷可斫，或笑鬼可賣。", "或陳混沌初，或及世界壊。", "或言修羅戰，百萬起睚眦。", "餘談恣搜抉，所出雜細大。", "風雲墮皮幘，幽坎窺鐵械。", "群號起古聚，孤泣出空廨。", "妖孤冠髑髏，掩袂弄姿態。", "空轊伏逸囚，夜半出竊嘬。", "雖云多聞益，頗犯綺語戒。", "不如姑置之，投枕休困憊。", "明當掛祠衣，僕僕愁亟拜。"]'),
('fa08b88b-c9d6-468a-88c3-b010c9c5bb84','夜歸','陸游','宋','宋诗','song-poetry','','[]','飲酒不盡觴，觀棋不竟局。',120,'全唐诗/poet.song.130000.json','["飲酒不盡觴，觀棋不竟局。", "索馬踏街鼓，仰視月挂木。", "疾馳沿河隄，不記幾坊曲。", "到家四鄰寂，往往睡已熟。", "天香餘裊裊，佛燈猶煜煜。", "中庭雖一席，緩步意亦足。", "寒犬吠荆籬，棲鵲起樷竹。", "市聲從北来，始覺非林谷。", "却尋西窗書，開卷剪殘燭。", "官閑居更遠，一笑謝羈束。"]'),
('eda7d18c-ea6d-4fc3-82f6-b9ed548ac7cd','次韵鄭唐老','陸游','宋','宋诗','song-poetry','','[]','宦逰早日闕相聞，一面那知乃爾勤。',64,'全唐诗/poet.song.130000.json','["宦逰早日闕相聞，一面那知乃爾勤。", "秋釣清灘方入夢，曉穿細仗又逢君。", "驟看落筆驚風雨，便擬同舟卧水雲。", "作意歸休還會否，暮年無力起斯文。"]'),
('fe7f982b-27cd-451b-9f2e-cdfc80914cf2','五鼓赴太社臘祭','陸游','宋','宋诗','song-poetry','','[]','霜寒裂屋瓦，月白射坊門。',48,'全唐诗/poet.song.130000.json','["霜寒裂屋瓦，月白射坊門。", "病骨愁看影，孤吟怯斷魂。", "饑鷹掣羈紲，老馬伏車轅。", "不奈清宵夢，殘蕪滿故園。"]'),
('14664033-bef5-4feb-ae63-88a08e4e23d4','己酉元日','陸游','宋','宋诗','song-poetry','','[]','夜雨解殘雪，朝陽開積陰。',48,'全唐诗/poet.song.130000.json','["夜雨解殘雪，朝陽開積陰。", "桃符呵筆寫，椒酒過花斟。", "巷柳搖風早，街泥濺馬深。", "行宫放朝賀，共識慕堯心。"]'),
('357767b3-1c30-41a5-9aa0-ac5aa6cc3f46','送潘德久使薊門','陸游','宋','宋诗','song-poetry','','[]','崑崙東分一枝渾，奔蹴砥柱經龍門。',160,'全唐诗/poet.song.130000.json','["崑崙東分一枝渾，奔蹴砥柱經龍門。", "羲皇受圖撫上古，神禹治水開中原。", "三靈實扶藝祖業，萬國共仰東都尊。", "群兒撞壊吁可嘆，顧使殘虜今逰魂。", "囙君試求出師路，孟津白馬應如故。", "不須更議繫河橋，北風正可乘冰渡。", "頗聞塞外已數盡，復道飛狐合屯戍。", "轅門倘駐拂雲祠，烽火應過明妃墓。", "君歸解鞍藉芳草，細談塞北忘予老。", "讀書飲酒待賊平，萬丈參旗方下掃。"]'),
('096bac72-43d4-4c7d-b142-805e5f7861d1','我夢','陸游','宋','宋诗','song-poetry','','[]','我夢入烟海，初日如金鎔。',96,'全唐诗/poet.song.130000.json','["我夢入烟海，初日如金鎔。", "赤手騎怒鯨，横身當渴龍。", "百日京塵中，詩料頗闕供。", "此夕復何夕，老狂洗衰慵。", "夢覺坐嘆息，杳杳三茆鍾。", "車馬動曉陌，不竟睡味濃。", "平生擊虜意，裂眥髮上衝。", "尚可乘一障，憑堞觀傳烽。"]'),
('619f96a8-3831-49eb-ba97-82c78b0620c8','晨起有感','陸游','宋','宋诗','song-poetry','','[]','痛飲可以豪，謝病可以高。',120,'全唐诗/poet.song.130000.json','["痛飲可以豪，謝病可以高。", "計之顧不審，老與世俗鏖。", "丈夫本自許，四十擁旌旄。", "上馬不回顧，賊穴窮腥臊。", "渭橋耻未雪，孰謂弓可櫜。", "此志竟悠悠，徂歲行滔滔。", "一官客長安，燭下束弊袍。", "豈惟嘆龍鍾，行恐悲焄蒿。", "吾曹議古人，後亦觀吾曹。", "浮雲易變滅，公議終堅牢。"]'),
('e594e215-8598-4976-b082-de4bfc49337b','南省宿直二首  其一','陸游','宋','宋诗','song-poetry','','[]','檐角參差散暮霞，重門鎖斷市聲譁。',64,'全唐诗/poet.song.130000.json','["檐角參差散暮霞，重門鎖斷市聲譁。", "風經緑樹鴉棲穏，月入空廊柱影斜。", "藤紙静臨新獲帖，銅瓶寒浸欲開花。", "誰知今夕幽窗夢，又榜扁舟上若耶。"]'),
('ad934c87-1de2-4390-8395-e8b42e958c92','南省宿直二首  其二','陸游','宋','宋诗','song-poetry','','[]','頹然静對北窗燈，識字農夫有髮僧。',64,'全唐诗/poet.song.130000.json','["頹然静對北窗燈，識字農夫有髮僧。", "但遣奚奴持古錦，何須侍史護青綾。", "塵埃奔走無由息，疾病侵陵不自勝。", "猶喜眼中多壮觀，時看雲海化鯤鵬。"]'),
('0c49a736-ffa7-4dd0-8a27-404aedfea6eb','夜歸磚街巷書事','陸游','宋','宋诗','song-poetry','','[]','近坊燈火如晝明，十里東風吹市聲。',96,'全唐诗/poet.song.130000.json','["近坊燈火如晝明，十里東風吹市聲。", "遠坊寂寂門盡閉，只有烟月無人行。", "誰家小樓歌惱儂，餘響縹緲縈簾櫳。", "苦心自古乏真賞，此恨略與吾曹同。", "歸来空齋卧凄冷，燈前病骨巉巉影。", "獨吟古調遣誰聽，聊與梅花分夜永。"]'),
('35b805f7-667c-4d1c-847b-0026945f03ea','馬上作','陸游','宋','宋诗','song-poetry','','[]','三十年前客帝城，城南結騎盡豪英。',64,'全唐诗/poet.song.130000.json','["三十年前客帝城，城南結騎盡豪英。", "湖山冷落悲陳迹，文字流傳付後生。", "衰老更禁新卧病，塵埃時拂舊題名。", "馬頭風捲飛花過，又得殘春一日晴。"]'),
('65e452da-431a-4ab4-b928-de55c205f9d8','行在春晚有懷故隠','陸游','宋','宋诗','song-poetry','','[]','老辱明時乞一官，逢春惆悵獨無歡。',64,'全唐诗/poet.song.130000.json','["老辱明時乞一官，逢春惆悵獨無歡。", "舊人零落北音少，市肆蕭疏民力殫。", "歸計已栽千箇竹，殘年合挂兩梁冠。", "石帆山路頻回首，箭茁蓴絲正滿槃。"]'),
('a0829a27-a100-4f91-9405-659bc6ea313e','儀曹直廬','陸游','宋','宋诗','song-poetry','','[]','春晚氣始和，微雲淡朝陽。',72,'全唐诗/poet.song.130000.json','["春晚氣始和，微雲淡朝陽。", "開軒面小庭，露漬薔薇香。", "逰絲卷欲盡，忽復百尺長。", "而我正遺事，枕藉書一床。", "讒波雖稽天，未遽妨人狂。", "惟當傾緑酒，莫待熟黄粱。"]'),
('55d27b58-8dfa-4895-9492-583592b91f22','讀書','陸游','宋','宋诗','song-poetry','','[]','兩兩星躔九九車，天津笑我醉騎驢。',64,'全唐诗/poet.song.130000.json','["兩兩星躔九九車，天津笑我醉騎驢。", "床頭正可著周易，架上何妨抽漢書。", "幸有古人同臭味，不嫌兒子似迃疏。", "頹然白髮雖堪鄙，耐事禁愁却有餘。"]'),
('1cddd6e2-e530-471f-b51f-6a3622aa7e88','小昭慶院講僧舊在都下與之相從今沒已久見畫像扵院中作詩吊之','陸游','宋','宋诗','song-poetry','','[]','曩歲曾陪夜講燈，伏犀插腦齒如冰。',32,'全唐诗/poet.song.130000.json','["曩歲曾陪夜講燈，伏犀插腦齒如冰。", "假令重見應難識，遺像癯然一老僧。"]'),
('402e6cdc-ae21-4d2d-b099-6a8dbce986d8','晨入省中偶書','陸游','宋','宋诗','song-poetry','','[]','清風拂畫簾，初日照素壁。',48,'全唐诗/poet.song.130000.json','["清風拂畫簾，初日照素壁。", "花枝蝶小憩，草葉露時滴。", "房櫳闃無人，溝水聲激激。", "摩挲語枯笻，伴我住幽寂。"]'),
('6fa81c8f-14ea-45d7-b634-3c3a7c899f28','春晚','陸游','宋','宋诗','song-poetry','','[]','今年病過春，得健春欲盡。',72,'全唐诗/poet.song.130000.json','["今年病過春，得健春欲盡。", "更堪風雨横，紅濕棲緑潤。", "一笑本自難，造物復爾吝。", "榆荚堆平堦，柳絮飛作陣。", "塵埃生破榼，霜雪滿衰鬢。", "平生慕陶謝，著語終不近。"]'),
('14a27e15-c76c-45c7-8c38-04ded88ce34d','觀潮','陸游','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江平無風面如鏡，日午樓船帆影正。',96,'全唐诗/poet.song.130000.json','["江平無風面如鏡，日午樓船帆影正。", "忽看千尺涌濤頭，頗動老子乘桴興。", "濤頭洶洶雷山傾，江流却作鏡面平。", "向来壮觀雖一快，不如帆映青山行。", "嗟余往来不知數，慣見買符官發渡。", "雲根小築幸可歸，勿爲浮名老行路。"]'),
('00765341-12ce-44cb-9823-f62af7d86c46','新晴馬上','陸游','宋','宋诗','song-poetry','','[]','一劍飄然萬里身，白頭也復走京塵。',64,'全唐诗/poet.song.130000.json','["一劍飄然萬里身，白頭也復走京塵。", "畫樓酒斾滴殘雨，緑樹鶯聲催暮春。", "絕塞勒回勲業夢，流年換盡市朝人。", "此生安得常强健，小艇湘湖自采蓴。"]'),
('78dde2bf-1e99-4499-ba33-e0915f066441','過六和塔前江亭小憩','陸游','宋','宋诗','song-poetry','','[]','斷岸孤亭日莫時，欄邊聊試葛巾欹。',64,'全唐诗/poet.song.130000.json','["斷岸孤亭日莫時，欄邊聊試葛巾欹。", "偶觀挂席乘潮快，便覺懸車納禄遲。", "痛飲相如無奈渇，清言叔寶不勝羸。", "年来親友凋零盡，惟有江山是舊知。"]'),
('2d6fa4d2-bc3a-46f3-9bbb-fbcd85ac47fb','春夕睡覺','陸游','宋','宋诗','song-poetry','','[]','破衫羸馬老黄塵，人自衰遲歲自新。',64,'全唐诗/poet.song.130000.json','["破衫羸馬老黄塵，人自衰遲歲自新。", "積雨恐侵春甲子，昏燈懶守夜庚申。", "花枝影轉欹殘月，鼻鼾聲豪撼四鄰。", "自笑功名猶有夢，散關金鼓震函秦。"]'),
('f275be2b-4e56-4848-ab7d-285d5256799c','送霍監丞出守盱眙','陸游','宋','宋诗','song-poetry','','[]','淮浦鱗鱗浸碧天，即今誰料作窮邊。',64,'全唐诗/poet.song.130000.json','["淮浦鱗鱗浸碧天，即今誰料作窮邊。", "空聞甌脱嘶胡馬，不見浮屠插霽烟。", "亭障久安無檄到，杯觴頻舉有詩傳。", "長城萬里英雄事，應笑窮儒飽晝眠。"]'),
('479b6ab3-83e1-4c3b-9258-fcbd42c268bb','寄題徐載叔秀才東莊','陸游','宋','宋诗','song-poetry','','[]','次公醒狂何必酒，直諒多聞俱可友。',96,'全唐诗/poet.song.130000.json','["次公醒狂何必酒，直諒多聞俱可友。", "萬籖插架號東莊，多稼連雲亦何有。", "今年偶入長安城，不識貴人呼作卿。", "南臺中丞掃榻見，北門學士倒屣迎。", "郎官酸寒誰肯顧，君来下馬談至暮。", "東莊雖富未可矜，更要縱横開武庫。"]'),
('5645c203-f083-4a19-ab45-b1b79f9fb5bd','入省','陸游','宋','宋诗','song-poetry','','[]','點點輕花墮緑盃，翩翩羸馬犯黄埃。',64,'全唐诗/poet.song.130000.json','["點點輕花墮緑盃，翩翩羸馬犯黄埃。", "眼邊好句等閑過，夢裏故人時一来。", "玉塞請行狂故在，霜髭自照老相催。", "今朝涼冷文書少，隠几南窗聽轉雷。"]'),
('3627db53-d091-4209-bb61-1a33438e37fc','入省 出省','陸游','宋','宋诗','song-poetry','','[]','五更束带聴朝雞，出省還家日已西。',64,'全唐诗/poet.song.130000.json','["五更束带聴朝雞，出省還家日已西。", "酒市雨餘青斾重，河橋風爽紫騮嘶。", "久慚旅飯糜倉粟，常憶新橙擣膾韲。", "萬事似棋聊爾耳，年来著數不勝低。"]'),
('74184e92-b6bc-4f32-872f-8e789219936e','和周元吉右司過弊居追懷南鄭相從之作','陸游','宋','宋诗','song-poetry','','[]','梁益東西六十州，大行臺出北防秋。',64,'全唐诗/poet.song.130000.json','["梁益東西六十州，大行臺出北防秋。", "閲兵金鼓震河渭，縱獵狐兔平山邱。", "露布捷書天上去，軍諮祭酒幄中謀。", "豈知今日詩来處，日落風生蘆荻洲。"]'),
('a36ba286-ffe3-48f1-8122-31e8b6d3dea7','尤延之侍郎屢求作遂初堂詩詩未成延之去國因以奉送','陸游','宋','宋诗','song-poetry','','[]','印何纍纍綬若若，只堪人看公何樂。',96,'全唐诗/poet.song.130000.json','["印何纍纍綬若若，只堪人看公何樂。", "忽然捩柂開布颿，慰滿平生一邱壑。", "遂初築堂今幾時，年年說歸真得歸。", "異書名刻堆滿屋，欠伸欲起遭書圍。", "捨之出逰公豈誤，緑髮朱顔已非故。", "請将勲業付諸郎，身踐當年遂初賦。"]'),
('ea8375cc-57b1-49f8-8473-0f1be45092b7','送張野夫寺丞牧滁州','陸游','宋','宋诗','song-poetry','','[]','皇天方憂九州裂，建隆真人仗黄鉞。',128,'全唐诗/poet.song.130000.json','["皇天方憂九州裂，建隆真人仗黄鉞。", "陣雲冷壓清流關，戰壘咿嚶氣如髮。", "逋誅猾虜入檻車，北風吹乾草頭血。", "一龍上天三百年，舊事空聞遺老說。", "金印斗大誰作州，公子玉面蒼髯虬。", "賦詩健筆挟風雨，論兵辯舌森戈矛。", "别君帳飲灞橋頭，長歌爲君寛旅愁。", "戰塲遺迹儻可畫，尺素寄我關河秋。"]'),
('27f0d4e4-6484-40ac-8854-799e04179f62','史院書事','陸游','宋','宋诗','song-poetry','','[]','信史新修稿滿床，牙籖黄帊带芸香。',64,'全唐诗/poet.song.130000.json','["信史新修稿滿床，牙籖黄帊带芸香。", "中人馳賜初宣旨，丞相傳呼早出堂。", "皇祖聖謨高萬古，諸賢直筆擅三長。", "孤臣曾趣龍墀對，白首爲郎只自傷。"]'),
('f777fbd1-96f1-4f42-8633-87c6d4acc8a8','病中數辱曾無逸架閣見問今日忽聞徙居走筆奉簡因致卜鄰之約','陸游','宋','宋诗','song-poetry','','[]','病羸不辦攬衣迎，剥啄空慚扣戸聲。',64,'全唐诗/poet.song.130000.json','["病羸不辦攬衣迎，剥啄空慚扣戸聲。", "凡藥豈能驅二豎，清心幸足制三彭。", "巷南僦屋儻可問，歲晚囊衣吾亦行。", "不爲朝天愁路澀，夜窗燈火要尋盟。"]'),
('d5cb298b-79b1-4723-8978-745776af4859','喜楊廷秀秘監再入館','陸游','宋','宋诗','song-poetry','','[]','公去蓬山輕，公歸蓬山重。',120,'全唐诗/poet.song.130000.json','["公去蓬山輕，公歸蓬山重。", "錦囊三千篇，字字律吕中。", "文章實公器，當與天下共。", "吾嘗評其妙，如龍馬受鞚。", "燕許亦有名，此事恐未夢。", "嗚呼大厦傾，孰可任梁棟。", "願公力起之，千載傳正統。", "時時醉黄封，高詠追屈宋。", "我如老蒼鶻，寂寞愁獨弄。", "杖屨勤来逰，雪霽梅欲動。"]'),
('b54c46de-c682-4f6d-bbb2-6f5c28fd2b18','次韵和楊伯子主簿見贈','陸游','宋','宋诗','song-poetry','','[]','齋戒叩頭牋天公，幸矣使我爲枯蓬。',256,'全唐诗/poet.song.130000.json','["齋戒叩頭牋天公，幸矣使我爲枯蓬。", "枯蓬於世百無用，始得曠快乘秋風。", "此生安往失貧賤，白髮蕭蕭對黄卷。", "今人雖鄰有不覿，古人却向書中見。", "猨啼月落青山空，舊隠夢寂思東蒙。", "不願峨冠赤墀下，且可短劍紅塵中。", "終年無人問良苦，眼望青天惟自許。", "可憐對酒不敢豪，它日空澆墳上土。", "文章最忌百家衣，火龍黼黻世不知。", "誰能養氣塞天地，吐出自足成虹蜺。", "渡江諸賢骨已朽，老夫亦将正邱首。", "杜郎苦瘦帽擫耳，程子久貧衣露肘。", "君復作意尋齊盟，豈知衰懦畏後生。", "大篇一讀我起立，喜君得法從家庭。", "鯤鵬自有天池著，誰謂太狂須束縳。", "大機大用君已傳，那遣老夫安注脚。"]'),
('7d8e2cd7-738d-4623-8908-f8f23a5e7b19','簡何同叔','陸游','宋','宋诗','song-poetry','','[]','白髮都門客，青燈夜雪時。',48,'全唐诗/poet.song.130000.json','["白髮都門客，青燈夜雪時。", "盡捐塵世事，細看月湖詩。", "格律冰霜敵，襟懷猿鶴知。", "吾儕端後死，此事要深期。"]'),
('a3c7d070-78fe-4495-ba01-ad46841d5e2d','去國待潮江亭太常徐簿宋卿載酒来别','陸游','宋','宋诗','song-poetry','','[]','昨解魚符已徑歸，偶隨尺一起柴扉。',64,'全唐诗/poet.song.130000.json','["昨解魚符已徑歸，偶隨尺一起柴扉。", "蹔留已愧黔吾突，久住空令緇客衣。", "外物紛紛何足問，故人眷眷莫相違。", "從今再見應無日，長與沙鷗共釣磯。"]'),
('e7a18bed-e9e9-43a6-a3bd-ea001cff2113','醉中作行草數紙','陸游','宋','宋诗','song-poetry','','[]','還家痛飲洗塵土，醉帖淋漓寄豪舉。',96,'全唐诗/poet.song.130000.json','["還家痛飲洗塵土，醉帖淋漓寄豪舉。", "石池墨瀋如海寛，玄雲下垂黑蛟舞。", "太陰鬼神挟風雨，夜半馬陵飛萬弩。", "堂堂筆陣從天下，氣壓唐人折釵股。", "丈夫本意陋千古，殘虜何足膏碪斧。", "驛書馳報兒單于，直用毛錐驚殺汝。"]'),
('87c60c4b-2bb5-4a42-b602-f386cbd47382','雨夜小酌','陸游','宋','宋诗','song-poetry','','[]','黄昏雲齊雪意熟，二更雪急聲簌簌。',96,'全唐诗/poet.song.130000.json','["黄昏雲齊雪意熟，二更雪急聲簌簌。", "地爐對火得奇温，兔醢魚鱐窮旨蓄。", "引杯且作稿面紅，脱帽不管衰鬢秃。", "浩歌三終徐自和，藏書萬卷方盡讀。", "從来本不擇死生，況復區區論禍福。", "雪晴著屐可登山，與子一放千里目。"]'),
('febde53c-17a2-4a00-b1a6-325a38218f9e','即事','陸游','宋','宋诗','song-poetry','','[]','塈壁編茅養病翁，五更擁褐聽霜風。',64,'全唐诗/poet.song.130000.json','["塈壁編茅養病翁，五更擁褐聽霜風。", "老雞棲冷啼偏早，宿火灰深撥更紅。", "知我向来惟斷簡，會心終竟在孤篷。", "東歸已賣腰間劍，魯叟從今不諱窮。"]'),
('be33cb68-a3ef-4b8c-aa30-f69c910b863e','到家旬餘意味甚適戱書','陸游','宋','宋诗','song-poetry','','[]','天恐紅塵著脚深，不教經歲去山林。',64,'全唐诗/poet.song.130000.json','["天恐紅塵著脚深，不教經歲去山林。", "欲酬清浄三生願，先洗功名萬里心。", "石鼎颼飀閑煮茗，玉徽零落自修琴。", "晚来剩有華胥興，卧看西窗一炷沉。"]'),
('7617d2dd-43b2-4668-96a5-5ce229242d2e','雨後復小雪','陸游','宋','宋诗','song-poetry','','[]','雨雪来無已，冬春忽欲交。',48,'全唐诗/poet.song.130000.json','["雨雪来無已，冬春忽欲交。", "賤貧安淡薄，老鈍耐譏嘲。", "村酒兒能取，農書手自鈔。", "莫年真箇懶，屋漏旋添茆。"]'),
('9d7be9a4-20e3-4f64-8bd1-9f6ed0bced5f','鯉魚行','陸游','宋','宋诗','song-poetry','','[]','鯉魚財三尺，淺水不覆脊。',88,'全唐诗/poet.song.130000.json','["鯉魚財三尺，淺水不覆脊。", "雖懷江湖樂，已嘆刀几赤。", "長鯨之長幾千丈，雪蹴山傾萬重浪。", "縱逰不厭滄海寛，一躍已在青天上。", "身世局促古所哀，噞喁貪餌胡爲哉。", "人間溝瀆莫更顧，夜半變化乘風雷。"]'),
('eea0bd0e-cfb5-4547-a838-f5890d3a6a11','雪夜作','陸游','宋','宋诗','song-poetry','','[]','雪重從壓竹，竹折有奇聲。',72,'全唐诗/poet.song.130000.json','["雪重從壓竹，竹折有奇聲。", "雪深亦莫掃，小窗終夜明。", "我老尚耐冷，開卷對短檠。", "龍茶與羔酒，得失不足評。", "但思被重鎧，夜入蔡州城。", "君勿輕癯儒，有志事竟成。"]'),
('fd6bc7a5-b43a-4164-abaf-0b986a8b60be','晨起','陸游','宋','宋诗','song-poetry','','[]','倦枕亷纎雨，幽窗料峭寒。',48,'全唐诗/poet.song.130000.json','["倦枕亷纎雨，幽窗料峭寒。", "溪柴旋篝火，野蔌鬪登槃。", "年老衣冠古，身閑宇宙寛。", "兒孫生我笑，趨揖已儒酸。"]'),
('792c220f-62e7-42e4-91c7-8a50cd5ff417','野饋','陸游','宋','宋诗','song-poetry','','[]','經年倉粟厭陳陳，天遣香秔饋野人。',64,'全唐诗/poet.song.130000.json','["經年倉粟厭陳陳，天遣香秔饋野人。", "黄耳蕈生齋缽富，白頭韭出客盤新。", "此生不復營三釜，一飽何曾羨八珍。", "尚愧古来高士在，杯羮無糝甑生塵。"]'),
('ccc48ac5-fe34-4f88-a2bc-02a9bfc8c0f1','醉中浩歌罷戯書','陸游','宋','宋诗','song-poetry','','[]','造物小兒如我何，還家依舊一漁蓑。',64,'全唐诗/poet.song.130000.json','["造物小兒如我何，還家依舊一漁蓑。", "穿雲逸響蘇門嘯，卷地悲風易水歌。", "老眼閱人真爛熟，壮心得酒旋消磨。", "傍觀虚作窮愁想，點檢霜髯却未多。"]'),
('239cfdc3-7181-4e0e-a899-8c680ca0440e','朝雨','陸游','宋','宋诗','song-poetry','','[]','中夜星照泥，平旦雲行西。',72,'全唐诗/poet.song.130000.json','["中夜星照泥，平旦雲行西。", "小屋古澤中，天昏雨凄凄。", "避濕升我堂，垂翅閔老雞。", "所欣園中蔬，冒土青滿畦。", "門無今雨客，路滑愁長堤。", "一杯且復睡，物理何足齊。"]'),
('7ac49854-89ce-4f77-9842-ecb991561202','春雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','苦雨何時止，微雲又作陰。',48,'全唐诗/poet.song.130000.json','["苦雨何時止，微雲又作陰。", "傍簷時小立，隠几復微吟。", "枝重殘紅濕，隄平漲緑深。", "物華元自好，老病負登臨。"]'),
('36d8a628-9f24-4f45-9812-8dbf35cac5fc','春雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','春愁無處避，春雨幾時晴。',48,'全唐诗/poet.song.130000.json','["春愁無處避，春雨幾時晴。", "黯黯陰連月，蕭蕭滴到明。", "窗昏減書課，弦緩咽琴聲。", "何以娱幽獨，新醅手自傾。"]'),
('7230e699-10f3-4806-9282-aecba304621b','記夢','陸游','宋','宋诗','song-poetry','','[]','夢裏都忘兩鬢殘，恍然白紵入長安。',64,'全唐诗/poet.song.130000.json','["夢裏都忘兩鬢殘，恍然白紵入長安。", "硾教紙熟修温卷，僦得驢騎候熱官。", "紅葉滿街秋著句，青樓燒燭夜追歡。", "如今萬事消除盡，老眼摩挲静處看。"]'),
('905b01e5-e5b3-4044-8c36-0274d9750df3','野興二首  其一','陸游','宋','宋诗','song-poetry','','[]','紅飯青蔬美莫加，鄰翁能共一甌茶。',64,'全唐诗/poet.song.130000.json','["紅飯青蔬美莫加，鄰翁能共一甌茶。", "舍西日緊花房斂，港北風生柳脚斜。", "笻杖不妨閑有伴，茆簷終勝老無家。", "自驚七十猶强健，采藥歸来見暮鴉。"]'),
('b2b3cbf7-2384-486b-a712-37194076e998','野興二首  其二','陸游','宋','宋诗','song-poetry','','[]','鬢邊莫笑久星星，造物常鍾我輩情。',64,'全唐诗/poet.song.130000.json','["鬢邊莫笑久星星，造物常鍾我輩情。", "每带餘酲蹋花影，又和殘夢聽鶯聲。", "軒窗風過書籖亂，洲渚潮生釣艇横。", "韓子未除豪氣在，文章都待不平鳴。"]'),
('23d6437c-0fdd-4bfc-8f61-6a5256508117','杭湖夜歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','昔如架上九秋鷹，今似窗間十月蠅。',64,'全唐诗/poet.song.130000.json','["昔如架上九秋鷹，今似窗間十月蠅。", "無復櫜鞬思出塞，不妨粥飯略同僧。", "白蘋洲晚初回櫂，緑樹村深已上燈。", "莫謂陶詩恨枯槁，細看字字可銘膺。"]'),
('38a83052-bbf2-4bd3-826b-9ecbf1859d66','杭湖夜歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','野艇迢迢信所之，歸来常及欲昏時。',64,'全唐诗/poet.song.130000.json','["野艇迢迢信所之，歸来常及欲昏時。", "陂塘烟重怨姑惡，林薄月明悲子規。", "出谷寺鐘初縹緲，穿籬績火已參差。", "欣然笑向譍門說，又了浮生一首詩。"]'),
('a244ae00-617b-40fe-9c9d-d83aa98d9bd4','或問余近況示以長句','陸游','宋','宋诗','song-poetry','','[]','天亦知予懶是真，莫年乞與自由身。',64,'全唐诗/poet.song.130000.json','["天亦知予懶是真，莫年乞與自由身。", "幽尋東浦鷺迎櫂，獨卧北窗鶯喚人。", "野卉滿頭狂取醉，草廬容膝樂忘貧。", "死時是處堪藏骨，不用要離更作鄰。"]'),
('8ebb70d1-5157-4a6b-94e3-2045153a8bf7','估客有自蔡州来者感悵彌日二首  其一','陸游','宋','宋诗','song-poetry','','[]','洮河馬死劍鋒摧，緑髮成絲每自哀。',32,'全唐诗/poet.song.130000.json','["洮河馬死劍鋒摧，緑髮成絲每自哀。", "幾歲中原消息斷，喜聞人自蔡州来。"]'),
('47652531-a8be-47a6-978a-0145142faabf','估客有自蔡州来者感悵彌日二首  其二','陸游','宋','宋诗','song-poetry','','[]','百戰元和取蔡州，如今胡馬飲淮流。',32,'全唐诗/poet.song.130000.json','["百戰元和取蔡州，如今胡馬飲淮流。", "和親自古非長筞，誰與朝家共此憂。"]'),
('88386b93-c2cf-4459-ab6b-635c020c8047','初夏郊行','陸游','宋','宋诗','song-poetry','','[]','小硯孤吟恐作愁，長堤曳杖且閑逰。',64,'全唐诗/poet.song.130000.json','["小硯孤吟恐作愁，長堤曳杖且閑逰。", "破雲山踴千螺翠，經雨波涵一鏡秋。", "粔籹青紅村步市，闌干高下寺家樓。", "去年此日君知否，十丈京塵沒馬頭。"]'),
('0d2e0cf3-3b82-4c84-b3f9-72b87c08bedf','重午','陸游','宋','宋诗','song-poetry','','[]','葉底榴花蹙絳繒，街頭初賣苑池冰。',32,'全唐诗/poet.song.130000.json','["葉底榴花蹙絳繒，街頭初賣苑池冰。", "世間各自有時節，蕭艾著冠稱道陵。"]'),
('6d3c12ce-ffb7-4f79-8b8d-afa3e3963be0','夏日','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵褦襶忙，放翁湖上獨相羊。',64,'全唐诗/poet.song.130000.json','["赤日黄塵褦襶忙，放翁湖上獨相羊。", "竹梢露滴驚殘夢，荷盖風翻送早涼。", "暑用酒逃猶有待，熱憑静勝更無方。", "空齋一榻翛然卧，閑看衣篝起篆香。"]'),
('39e93eae-b1a2-42b6-ac2e-b349c20b39db','睡起見楊花滿庭偶書','陸游','宋','宋诗','song-poetry','','[]','斷香裊裊傍窗紗，睡起瞢騰日未斜。',32,'全唐诗/poet.song.130000.json','["斷香裊裊傍窗紗，睡起瞢騰日未斜。", "堪嘆一春風雨惡，今年四月見楊花。"]'),
('c533ba06-7fb1-4c7e-93d7-3cf52147218c','梅雨','陸游','宋','宋诗','song-poetry','','[]','沐罷斜簮二寸冠，斷雲殘靄暗江干。',64,'全唐诗/poet.song.130000.json','["沐罷斜簮二寸冠，斷雲殘靄暗江干。", "絲絲梅子熟時雨，漠漠楝花開後寒。", "剩采芸香辟書蠧，旋舂麥麨續家餐。", "日長倦睫惟思閉，茗椀真須抵死寛。"]'),
('2ca7c479-f94c-492d-8b2a-d5fda940e154','醉歌','陸游','宋','宋诗','song-poetry','','[]','讀書三萬卷，仕宦皆束閣。',144,'全唐诗/poet.song.130000.json','["讀書三萬卷，仕宦皆束閣。", "學劍四十年，虜血未染鍔。", "不得爲長虹，萬丈掃寥廓。", "又不爲疾風，六月送飛雹。", "戰馬死槽櫪，公卿守和約。", "窮邊指淮淝，異域視京雒。", "於乎此何心，有酒吾忍酌。", "平生爲衣食，斂版靴兩脚。", "心雖了是非，口不給唯諾。", "如今老且病，鬢秃牙齒落。", "仰天少吐氣，餓死實差樂。", "壮心埋不朽，千載猶可作。"]'),
('ff6a2e0c-bdf1-47b5-b23c-c90b8b095731','醉書秦望山石壁','陸游','宋','宋诗','song-poetry','','[]','秋雨初霽開長空，夜天無雲吐白虹。',162,'全唐诗/poet.song.130000.json','["秋雨初霽開長空，夜天無雲吐白虹。", "擘波浴海出日月，破山卷地驅雷風。", "崐崘黄流瀉浩浩，太華巨掌摩穹穹。", "平生所懷正如此，拜賜虚皇稱放翁。", "放翁七十飲千鍾，耳目未廢頭未童。", "向来楚漢何足道，真覺萬古無英雄。", "行窮禹迹亦安往，聊借曠快洗我胸。", "濤瀾屢犯蛟鰐怒，澗谷或與精靈逢。", "黄金鑄就決河塞，俘獻頡利長安宫。", "不如醉筆掃青嶂，入石一寸豪健驚天公。"]'),
('a947858f-d1c4-4e77-93c1-0d3437cbd66a','秋夜','陸游','宋','宋诗','song-poetry','','[]','藥餌扶衰疾，琴書返故園。',48,'全唐诗/poet.song.130000.json','["藥餌扶衰疾，琴書返故園。", "陶公方止酒，樂令且清言。", "烟鳥宿沙際，露螢明草根。", "塵囂不到處，此意與誰論。"]'),
('c4044eea-4de1-484b-a5fb-e4e73a7eea49','夜意','陸游','宋','宋诗','song-poetry','','[]','孤夢初回夜氣清，世塵掃盡覺心平。',64,'全唐诗/poet.song.130000.json','["孤夢初回夜氣清，世塵掃盡覺心平。", "月沉洲渚漁歌遠，人語比鄰績火明。", "獨汲寒泉鳴細綆，静聽漏鼓下高城。", "悠然坐待東方白，却看軒窗淡日生。"]'),
('2b984e1a-497f-4c72-aa28-82973d226f8d','蝸廬','陸游','宋','宋诗','song-poetry','','[]','小葺蝸廬便著家，槿籬莎徑任欹斜。',64,'全唐诗/poet.song.130000.json','["小葺蝸廬便著家，槿籬莎徑任欹斜。", "爲生草草僧行脚，到處悠悠客泛槎。", "孤蝶惜衣晴曝粉，穉蜂貪蜜晚爭花。", "有書懶讀吾堪愧，睡起何妨自磑茶。"]'),
('0220995d-57bc-4f7c-ae3b-44f266aea9c2','予十年間兩坐斥辠雖擢髮莫數而詩爲首謂之嘲詠風月既還山遂以風月名小軒且作絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','扁舟又向鏡中行，小草清詩取次成。',32,'全唐诗/poet.song.130000.json','["扁舟又向鏡中行，小草清詩取次成。", "放逐尚非餘子比，清風明月入臺評。"]'),
('fc6e2088-0f4f-4ca6-a2a3-8bc07fc65169','予十年間兩坐斥辠雖擢髮莫數而詩爲首謂之嘲詠風月既還山遂以風月名小軒且作絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','緑蔬丹果薦瓢尊，身寄城南禹會村。',32,'全唐诗/poet.song.130000.json','["緑蔬丹果薦瓢尊，身寄城南禹會村。", "連坐頻年到風月，固應無客叩吾門。"]'),
('9d46a52b-2b75-4866-a4a9-076ccc010338','題梅漢卿醉經堂','陸游','宋','宋诗','song-poetry','','[]','他人爛醉錦瑟傍，君獨醉心編簡香。',64,'全唐诗/poet.song.130000.json','["他人爛醉錦瑟傍，君獨醉心編簡香。", "沉酣骨髓春盎盎，如枕麴蘖羅杯觴。", "三萬牙籖插高架，五千黄卷撐枯腸。", "信哉名教有樂地，白首不入無功鄉。"]'),
('43868a30-df79-4919-a681-b0bc40c0763c','得親舊書問近況以詩代書報之','陸游','宋','宋诗','song-poetry','','[]','溪頭日日弄潺湲，敢料餘生竟得全。',64,'全唐诗/poet.song.130000.json','["溪頭日日弄潺湲，敢料餘生竟得全。", "白簡免勞中執法，青銅罷筭小行年。", "花前一笑頻開口，林下深藏永息肩。", "欲養金丹還懶去，身今已是地行仙。"]'),
('d92b3961-1ffb-4997-a471-021563b817eb','放逐','陸游','宋','宋诗','song-poetry','','[]','放逐雖慚處士高，笑譚未減少年豪。',64,'全唐诗/poet.song.130000.json','["放逐雖慚處士高，笑譚未減少年豪。", "青山隨處有三窟，白首今年無二毛。", "正得笻枝爲老伴，盡将書帙付兒曹。", "飲酣自足稱名士，安用辛勤讀楚騷。"]'),
('9596f15c-c814-4402-9a9f-ad8d6e63a903','月下野步','陸游','宋','宋诗','song-poetry','','[]','空中磊落斗跨天，道旁荒寒月滿川。',112,'全唐诗/poet.song.130000.json','["空中磊落斗跨天，道旁荒寒月滿川。", "行歌驚起鷗鷺眠，三萬里在拄杖邊。", "敲門索酒太華前，飛渡黄河不須船。", "袖中短鐵青蜿蜒，昔曾巴邱從老僊。", "削平巖崖抉雲烟，此妙可得不可傳。", "雷聲殷殷電煜然，已覺邊境銷戈鋋。", "雪花如席登祁連，歸来却看東封年。"]'),
('0ed64246-9547-4bd9-948b-53c89306eb50','自詠','陸游','宋','宋诗','song-poetry','','[]','孤艇渺烟波，衡門暗薜蘿。',48,'全唐诗/poet.song.130000.json','["孤艇渺烟波，衡門暗薜蘿。", "衣冠醉學究，毛骨病維摩。", "撫几時長喟，臨觴亦浩歌。", "無勞問蝸角，蠻觸正横戈。"]'),
('f3ca916a-ee97-4b72-b545-0c11cb34ed4b','午睡起遇急雨','陸游','宋','宋诗','song-poetry','','[]','揩眼捫髯破晝眠，闌邊小立獨幽然。',64,'全唐诗/poet.song.130000.json','["揩眼捫髯破晝眠，闌邊小立獨幽然。", "樷花雨打無飛蝶，高柳風驚有墮蟬。", "才略本居元子下，功名那計祖生先。", "今朝會意君知否，目送飛雲揮五弦。"]'),
('d21a9a6f-a93e-416b-9d91-6c6d17bbe539','夜雨暴至','陸游','宋','宋诗','song-poetry','','[]','堂中虚窗雨氣入，堂前樷竹雨聲急。',64,'全唐诗/poet.song.130000.json','["堂中虚窗雨氣入，堂前樷竹雨聲急。", "山童束緼走求火，屋漏惟愁打書濕。", "秋風䆉稏九千頃，此夕真成傾玉粒。", "蹋歌作社約比鄰，一飽今年可平揖。"]'),
('0cc14b02-89c0-443b-892d-d9267877e46d','睡起作帖數行','陸游','宋','宋诗','song-poetry','','[]','睡餘得清風，起坐傍書几。',96,'全唐诗/poet.song.130000.json','["睡餘得清風，起坐傍書几。", "日長誰晤言，賴此管城子。", "欣然共游戯，一笑我忘爾。", "群鴻偶下集，但怪驚不起。", "古来翰墨事，著意更可鄙。", "跌宕三十年，一日造此理。", "不知筆在手，而況字落紙。", "三叫投紗巾，作歌識吾喜。"]'),
('0c961881-1d16-4043-8c78-f246fe2ed2c0','新秋','陸游','宋','宋诗','song-poetry','','[]','短鬢蕭蕭失舊青，此身已看作郵亭。',32,'全唐诗/poet.song.130000.json','["短鬢蕭蕭失舊青，此身已看作郵亭。", "新秋無限凄涼意，盡付風蟬與露螢。"]'),
('ed9fb442-77f2-4480-88a1-44ff3fc379ce','秋興二首  其一','陸游','宋','宋诗','song-poetry','','[]','去秋尚十日，軒窗夕已涼。',96,'全唐诗/poet.song.130000.json','["去秋尚十日，軒窗夕已涼。", "露草黏濕螢，壊壁啼寒螿。", "丈夫志四海，臨書慨以慷。", "白髮忽如此，惟有歸耕桑。", "藥餌且枝梧，鄰曲相扶将。", "豈無甕中酒，老病不能觴。", "南山有歸處，歲晚柏已行。", "下從吾親游，此事歲月長。"]'),
('3c1cdfb1-d1d9-4ab6-adf0-8bbc75ae92c2','秋興二首  其二','陸游','宋','宋诗','song-poetry','','[]','無食苦日長，無衣念秋近。',72,'全唐诗/poet.song.130000.json','["無食苦日長，無衣念秋近。", "雖云老農圃，未害樂堯舜。", "士生要弘毅，病在墮驕吝。", "得喪纔幾何，哀哉以身徇。", "平生最耐事，霜雪亦滿鬢。", "憂患一洗空，吾道其少進。"]'),
('dceee2f2-537a-42e2-96cc-93469d938938','幽居','陸游','宋','宋诗','song-poetry','','[]','幽居人迹稀，柴扉晝常掩。',48,'全唐诗/poet.song.130000.json','["幽居人迹稀，柴扉晝常掩。", "小池清見底，疏雨時數點。", "蟬嘒秋未衰，花房暮先斂。", "老大固多傷，年華還冉冉。"]'),
('e4e09032-cbde-43ef-bad9-4f287fbe7292','山居食每不肉戯作','陸游','宋','宋诗','song-poetry','','[]','谿友留魚不忍烹，直将蔬糲送餘生。',64,'全唐诗/poet.song.130000.json','["谿友留魚不忍烹，直将蔬糲送餘生。", "二升畬粟香炊飯，一把畦菘淡煮羮。", "莫笑開單成淨供，也能捫腹作徐行。", "秋来更有堪誇處，日傍東籬拾落英。"]'),
('217eab91-c66e-47a7-9cb8-bfc27e3d56fd','自笑','陸游','宋','宋诗','song-poetry','','[]','諸公衮衮幾金貂，自笑無材負聖朝。',64,'全唐诗/poet.song.130000.json','["諸公衮衮幾金貂，自笑無材負聖朝。", "老氣醉中猶跌宕，間身夢裏亦逍遥。", "舊書日伴吾兒讀，薄飯時從野叟招。", "病後秋衣須早製，竹窗殘夜雨蕭蕭。"]'),
('bc6a81f8-13ad-4da2-988d-4114c5663e1c','世上','陸游','宋','宋诗','song-poetry','','[]','世上悠悠東逝波，金丹将奈鬢絲何。',64,'全唐诗/poet.song.130000.json','["世上悠悠東逝波，金丹将奈鬢絲何。", "牆頭楊柳知秋早，窗外芭蕉受雨多。", "伏櫪自應如老驥，還鄉元欲借明駞。", "吾棋一局千年事，從使旁觀爛斧柯。"]'),
('7b3c47c4-4407-47df-a2b2-2b4d5a45d968','夜歸偶懷故人獨孤景略','陸游','宋','宋诗','song-poetry','','[]','買醉村場半夜歸，西山落月照柴扉。',32,'全唐诗/poet.song.130000.json','["買醉村場半夜歸，西山落月照柴扉。", "劉琨死後無奇士，獨聽荒雞泪滿衣。"]'),
('c13da87f-f817-470e-abf8-5a0ed5be7ff4','秋夜自近村歸','陸游','宋','宋诗','song-poetry','','[]','江頭浩歌天宇寛，刺船歸来清夜闌。',64,'全唐诗/poet.song.130000.json','["江頭浩歌天宇寛，刺船歸来清夜闌。", "女貞林黑月未上，姑惡聲悲村已寒。", "不恨故交日零落，本知浮生難控摶。", "頭童面槁更安往，莫問傍人君自看。"]'),
('661498d8-4930-43f8-9358-09c5ce624b35','夜聞蟋蟀','陸游','宋','宋诗','song-poetry','','[]','布穀布穀解勸耕，蟋蟀蟋蟀能促織。',120,'全唐诗/poet.song.130000.json','["布穀布穀解勸耕，蟋蟀蟋蟀能促織。", "州符縣帖無已時，勸耕促織知何益。", "安得生世當成周，一家百畝長無愁。", "緑桑鬱鬱暗微徑，黄犢叱叱行平疇。", "荆扉績火明煜煜，黍壟饁飯香浮浮。", "耕亦不須勸，織亦不須促。", "機上有餘布，盎中有餘粟。", "老翁白首如小兒，鼓腹擊壤相從嬉。"]'),
('e265ee20-52ee-4d83-b1b3-012dc4bc2eac','秋夜風雨暴至','陸游','宋','宋诗','song-poetry','','[]','風聲掠野来，澒洞如翻濤。',96,'全唐诗/poet.song.130000.json','["風聲掠野来，澒洞如翻濤。", "雨聲集庭木，桐葉聲最豪。", "殘暑一洗空，凜然念綈袍。", "秋色已登場，欲忘終歲勞。", "東舍捉鵝鴨，西舍烹豚羔。", "籬落開寒花，房攏壓小槽。", "貧賤何所嘆，樂歲成吾高。", "却拾牆角檠，拂拭賀汝遭。"]'),
('e25ff36c-630d-43f1-b3d4-d094321c7cb2','月下小酌','陸游','宋','宋诗','song-poetry','','[]','草樹已秋聲，郊原喜晚晴。',48,'全唐诗/poet.song.130000.json','["草樹已秋聲，郊原喜晚晴。", "風生雲盡散，天濶月徐行。", "下箸槎頭美，傳杯甕面清。", "追歡猶可勉，徂歲不須驚。"]'),
('7b1079c8-8b0f-49fa-b631-caaff3240326','鄰曲有未飯被追入郭者憫然有作','陸游','宋','宋诗','song-poetry','','[]','舂得香秔摘緑葵，縣符急急不容炊。',32,'全唐诗/poet.song.130000.json','["舂得香秔摘緑葵，縣符急急不容炊。", "君王日御金華殿，誰誦周家七月詩。"]'),
('f0c258ae-1235-48de-ae4e-12f471ff33e0','吾廬','陸游','宋','宋诗','song-poetry','','[]','吾廬鏡湖上，傍水開雲扃。',72,'全唐诗/poet.song.130000.json','["吾廬鏡湖上，傍水開雲扃。", "秋淺葉未丹，日落山更青。", "孤鶴從西来，長鳴掠沙汀。", "亦知常苦饑，未忍吞羶腥。", "我食雖不肉，匕箸窮芳馨。", "幽窗燈火冷，濁酒倒殘瓶。"]'),
('155edb75-fe7d-4878-a4d9-df5422346cbe','飲酒望西山戱詠','陸游','宋','宋诗','song-poetry','','[]','太白十詩九言酒，醉翁無詩不說山。',32,'全唐诗/poet.song.130000.json','["太白十詩九言酒，醉翁無詩不說山。", "若耶老農識幾字，也與二事日相關。"]'),
('18a921c4-23df-4904-b7c7-45585b0c6209','小院','陸游','宋','宋诗','song-poetry','','[]','小院回廊夕照明，放翁夜坐一笻横。',64,'全唐诗/poet.song.130000.json','["小院回廊夕照明，放翁夜坐一笻横。", "銅匜暖徹香初過，鐵杵聲清藥欲成。", "世事熟看無一可，古人不作與誰評。", "新涼社酒家家熟便，用陽狂了此生。"]'),
('2d757169-eb2d-478f-8ea2-7ebd06910501','發箧得故人書有感','陸游','宋','宋诗','song-poetry','','[]','衰鬢星星換舊青，世間萬事但堪驚。',64,'全唐诗/poet.song.130000.json','["衰鬢星星換舊青，世間萬事但堪驚。", "晨炊欲熟客未覺，夜漏漸殘人尚行。", "花發且爲無事飲，詩成非復不平鳴。", "京華朋舊凋零盡，忽見緘題似隔生。"]'),
('7b457c6a-be54-4f2e-92b1-9fc0017f3e68','秋光','陸游','宋','宋诗','song-poetry','','[]','年年最愛秋光好，病起逢秋合賦詩。',64,'全唐诗/poet.song.130000.json','["年年最愛秋光好，病起逢秋合賦詩。", "樷菊漸黄人醉後，孤燈初暗雨来時。", "舊書細讀猶多味，老態相尋似有期。", "早信爲農勝覓禄，一生虚作虎頭癡。"]'),
('4b2f58d1-6338-4b80-91c4-eb6179322275','晚秋風雨','陸游','宋','宋诗','song-poetry','','[]','儘道漁村陋，秋来物色奇。',48,'全唐诗/poet.song.130000.json','["儘道漁村陋，秋来物色奇。", "寒生沽酒興，雨及種花時。", "狂舞欲誰屬，清吟空自知。", "茫茫宇宙內，吾道竟何之。"]'),
('cbebb998-8af1-4f8d-b874-5e1d54053be2','幽居二首  其一','陸游','宋','宋诗','song-poetry','','[]','白髮蕭蕭僅到肩，一枝藤杖日翩躚。',64,'全唐诗/poet.song.130000.json','["白髮蕭蕭僅到肩，一枝藤杖日翩躚。", "草苫牆北棲雞屋，泥補橋西放鴨船。", "心似枯葵空向日，身如病櫟孰知年。", "放懷却有翛然處，不養金丹不學禪。"]'),
('3c2a6376-0c27-454a-8847-c4e360ec3667','幽居二首  其二','陸游','宋','宋诗','song-poetry','','[]','面面秋山擁翠屏，天留三畝著雲扃。',64,'全唐诗/poet.song.130000.json','["面面秋山擁翠屏，天留三畝著雲扃。", "迎霜南阜楓林赤，飽雨西村菜甲青。", "散筞人驚衰後健，浩歌自覺醉中醒。", "凌烟冠劍應無爾，布帽裙襦老管寧。"]'),
('bafedf80-5619-41b3-97c6-4197bbdd8c8d','故山四首  其一','陸游','宋','宋诗','song-poetry','','[]','功名莫苦怨天慳，一櫂歸来到死閑。',64,'全唐诗/poet.song.130000.json','["功名莫苦怨天慳，一櫂歸来到死閑。", "傍水無家無好竹，卷簾是處是青山。", "滿籃箭竹瑤簪白，壓擔稜梅鶴頂殷。", "野興盡時尤可樂，小江烟雨趁潮還。"]'),
('251e0ab3-d714-4248-8ed1-daae7ff49a13','故山四首  其二','陸游','宋','宋诗','song-poetry','','[]','禹祠行樂盛年年，繡轂爭先罨畫船。',64,'全唐诗/poet.song.130000.json','["禹祠行樂盛年年，繡轂爭先罨畫船。", "十里烟波明月夜，萬人歌吹早鶯天。", "花如上苑常成市，酒似新豐不直錢。", "老子未須悲白髮，黄公壚下且閑眠。"]'),
('2d32e4b9-683c-436b-9ec7-7f86cd314508','故山四首  其三','陸游','宋','宋诗','song-poetry','','[]','老尉鴻飛隠市門，千年猶有舊巢痕。',64,'全唐诗/poet.song.130000.json','["老尉鴻飛隠市門，千年猶有舊巢痕。", "陸生於此寓棋局，曾丈時来開酒樽。", "渺渺帆檣遥見海，冥冥蒲葦不知村。", "數僧也復投詩社，零落今無一二存。"]'),
('d620bad5-b012-4115-b64e-0cd45806111a','故山四首  其四','陸游','宋','宋诗','song-poetry','','[]','落磵泉奔舞玉虹，護丹松老卧蒼龍。',64,'全唐诗/poet.song.130000.json','["落磵泉奔舞玉虹，護丹松老卧蒼龍。", "霜柑籬角寒初熟，野碓雲邊夜自舂。", "挈榼人沽村市酒，打包僧趁寺樓鐘。", "幽尋自是年来懶，枉道山靈不見容。"]'),
('47e8a16a-7db3-4047-b20b-fc99791f0985','秋晚弊廬小葺一室過冬欣然有作','陸游','宋','宋诗','song-poetry','','[]','放翁畢竟合躬耕，剩喜東歸樂太平。',64,'全唐诗/poet.song.130000.json','["放翁畢竟合躬耕，剩喜東歸樂太平。", "碧瓦新霜寒尚薄，明窗嫰日雨初晴。", "素琴尋得無弦曲，野餉烹成不糝羮。", "更說市朝癡太絕，一湖秋水濯塵纓。"]'),
('dad0ff03-85ed-47f9-aaac-d7c3766e28de','小室晚酌','陸游','宋','宋诗','song-poetry','','[]','病不禁寒怯早霜，東齋隨事具杯觴。',64,'全唐诗/poet.song.130000.json','["病不禁寒怯早霜，東齋隨事具杯觴。", "清時寛大何妨醉，白首龍鍾未減狂。", "枝葉扶檠山果熟，鹽醯調適野蔬香。", "興闌徑覔華胥路，枕藉圖書滿一床。"]'),
('91e5b237-911b-4b24-b1c6-d71b482ce3e0','冬晚山房書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','山澤何妨老太平，巉巉骨相本来清。',64,'全唐诗/poet.song.130000.json','["山澤何妨老太平，巉巉骨相本来清。", "月明滿地看梅影，露下隔溪聞鶴聲。", "未辨藥苗逢客問，欲酬琴價約僧評。", "胡奴仁祖今俱絕，且學湘纍拾菊英。"]'),
('c896c07a-d01c-4b03-b708-3965d0260e59','冬晚山房書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','屏迹山村病日增，烏皮几穏得閑凭。',64,'全唐诗/poet.song.130000.json','["屏迹山村病日增，烏皮几穏得閑凭。", "凍雲傍水封梅蕚，嫩日烘窗釋硯冰。", "歲盡光陰饒衮衮，身閑醉夢且騰騰。", "蠻童采藥歸来晚，客至從嗔喚不譍。"]'),
('4be2fe6b-5aae-41cb-9ecb-bb5a12124aff','村居日飲酒對梅花醉則擁紙衾熟睡甚自適也','陸游','宋','宋诗','song-poetry','','[]','江村歲晚掩柴荆，地僻久無車馬聲。',64,'全唐诗/poet.song.130000.json','["江村歲晚掩柴荆，地僻久無車馬聲。", "孤寂惟尋麴道士，一寒仍賴楮先生。", "醡頭珠滴愁先破，帳底春回夢易成。", "莫笑衰翁殺風景，小瓶梅蘂解卿卿。"]'),
('fd878a13-da35-4855-a4d9-a186689b58ca','山居疊韵','陸游','宋','宋诗','song-poetry','','[]','禽吟陰森林，鹿伏樸樕木。',72,'全唐诗/poet.song.130000.json','["禽吟陰森林，鹿伏樸樕木。", "嗚呼吾徒愚，僕僕逐肉粟。", "聨翩憐鳶肩，覆餗速戮辱。", "艱難還山間，獨欲足畜牧。", "躋梯棲西谿，築屋宿北谷。", "光芒常當藏，櫝玉觸俗目。"]'),
('d2d0296b-6d3c-41f9-8087-a36b762d64ae','寓嘆三首  其一','陸游','宋','宋诗','song-poetry','','[]','心已忘斯世，天猶活此翁。',48,'全唐诗/poet.song.130000.json','["心已忘斯世，天猶活此翁。", "嫩湯茶乳白，軟火地爐紅。", "課婢耘蔬甲，呼兒下釣筒。", "生涯君勿笑，聊足慰塗窮。"]'),
('a684b6bf-1175-4abd-8a67-4dff64c9e0a2','寓嘆三首  其二','陸游','宋','宋诗','song-poetry','','[]','久矣門無客，高齋獨掩扉。',48,'全唐诗/poet.song.130000.json','["久矣門無客，高齋獨掩扉。", "敢言消壮志，要是息危機。", "清露夜自滴，孤雲寒不歸。", "晨炊勿關念，更典箧中衣。"]'),
('4672e916-6153-4664-a62a-1164e92dee1f','寓嘆三首  其三','陸游','宋','宋诗','song-poetry','','[]','裘薄便冬暖，簞空畏午饑。',48,'全唐诗/poet.song.130000.json','["裘薄便冬暖，簞空畏午饑。", "臨成乞米帖，看入借車詩。", "學古心猶壮，憂時語自悲。", "公卿闕自重，社稷欲誰期。"]'),
('14201c5f-a351-4dd9-a6b1-76638389f186','贈惟了侍者二首  其一','陸游','宋','宋诗','song-poetry','','[]','水邊剝啄打門誰，滿袖清風一紙詩。',32,'全唐诗/poet.song.130000.json','["水邊剝啄打門誰，滿袖清風一紙詩。", "驚起放翁蝴蝶夢，半窗寒日欲斜時。"]'),
('a800b7d2-194c-479e-aca6-f32a43e61b95','贈惟了侍者二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪中僵卧不須悲，徹骨清寒始觧詩。',32,'全唐诗/poet.song.130000.json','["雪中僵卧不須悲，徹骨清寒始觧詩。", "一等人間閑草木，月窗君看早梅枝。"]'),
('eafc4213-5277-4a84-afed-0f75c10bc299','題湖邊旗亭','陸游','宋','宋诗','song-poetry','','[]','春色初回杜若洲，佳人又典鷫鸘裘。',64,'全唐诗/poet.song.130000.json','["春色初回杜若洲，佳人又典鷫鸘裘。", "八千里外狂漁父，五百年前舊酒樓。", "渡口遠山顰翠黛，天邊新月挂瓊鈎。", "回頭笑向紅塵說，也有閑愁到此不。"]'),
('08fc4718-279a-4d06-88c8-9127dc5ba192','醉卧道邊覺而有賦','陸游','宋','宋诗','song-poetry','','[]','太華五千仞，天台四萬丈。',92,'全唐诗/poet.song.130000.json','["太華五千仞，天台四萬丈。", "一枝古藤如黑龍，天遣飄然寄閑放。", "莫怪公卿不我知，我自不知渠是誰。", "史書弄筆後來事，繡鞍寶带聊兒嬉。", "旗亭爛醉官道卧，醒後無人數吾過。", "世間恩怨一時空，且免它年送臨賀。"]'),
('d74c5cbe-1189-44d6-973c-da62f767e9b9','寓懷四首  其一','陸游','宋','宋诗','song-poetry','','[]','脱粟未爲饑，短褐未爲寒。',132,'全唐诗/poet.song.130000.json','["脱粟未爲饑，短褐未爲寒。", "衆毁心自可，身困氣愈完。", "茆屋雖三間，趺坐則已寛。", "濁酒不滿瓢，浩歌有餘歡。", "祿食妻子樂，功名後人看。", "成敗兩蝸角，貴賤一鼠肝。", "芒芒百年夢，底物堪控摶。", "不如學餐霞，駐此雙頰丹。", "行披終南雲，飛渡黄河湍。", "巋然過空城，人言古長安。", "霜露蒙荆榛，喟然增永嘆。"]'),
('65a487bd-6013-49da-8c3b-c0d25d62098c','寓懷四首  其二','陸游','宋','宋诗','song-poetry','','[]','蒼璧與黄琮，初非俗所貴。',72,'全唐诗/poet.song.130000.json','["蒼璧與黄琮，初非俗所貴。", "粲然薦繅藉，可對越天地。", "我豈賣餅兒，自衒三家市。", "持槃叫道邊，雖售無乃愧。", "文章等卜祝，王公以儒戲。", "書成藏名山，此是千載事。"]'),
('e10f7b90-5e9d-4ba1-84bd-4c3ae38659c0','寓懷四首  其三','陸游','宋','宋诗','song-poetry','','[]','我昔浮滄溟，浩渺難具論。',72,'全唐诗/poet.song.130000.json','["我昔浮滄溟，浩渺難具論。", "中外漭不辨，日月互吐吞。", "神龍忽上騰，尾鬛風霆奔。", "積浪自生火，烈焰焚乾坤。", "笑謂同舟子，世豈無鵬鯤。", "聊持豪逸氣，壓汝破碎魂。"]'),
('9df9140b-3d95-420b-ba62-1a6d60a58173','寓懷四首  其四','陸游','宋','宋诗','song-poetry','','[]','鮑魚載沙丘，鹿馬獻阿房。',84,'全唐诗/poet.song.130000.json','["鮑魚載沙丘，鹿馬獻阿房。", "泗上老亭長，仿佯起東方。", "干戈暗宇縣，黥徒化侯王。", "富貴誠可慕，葅醢亦足當。", "青門獨無恙，種瓜亦何傷。", "後有阮嗣宗，絕識未易量。", "楚漢真豎子，孰謂斯人狂。"]'),
('aa75b7a1-2f4d-4591-85fd-c7f44f91b34d','喜事','陸游','宋','宋诗','song-poetry','','[]','武夷老子雪垂肩，喜事何曾減少年。',64,'全唐诗/poet.song.130000.json','["武夷老子雪垂肩，喜事何曾減少年。", "鸚鵡螺深翻細浪，辟邪爐暖起微烟。", "幽花滴露霑紗帽，亂絮憑風撲畫船。", "虎豹九關君勿嘆，未妨一笑住壺天。"]'),
('ed9b82a5-5f64-4f88-b345-61ac2e2077fc','甜羮','陸游','宋','宋诗','song-poetry','','[]','山厨薪桂軟炊秔，旋洗香蔬手自烹。',32,'全唐诗/poet.song.130000.json','["山厨薪桂軟炊秔，旋洗香蔬手自烹。", "從此八珍俱避舍，天蘇陁味屬甜羮。"]'),
('f65759ee-8949-4f4f-b033-027560967c3b','縱筆四首  其一','陸游','宋','宋诗','song-poetry','','[]','文叔一人知此翁，洛陽城裏又東風。',32,'全唐诗/poet.song.130000.json','["文叔一人知此翁，洛陽城裏又東風。", "譲他綠髮好年少，二十四歲作三公。"]'),
('8832fdc6-af56-412a-98bb-5595784b539e','縱筆四首  其二','陸游','宋','宋诗','song-poetry','','[]','一紙除書到海邊，紫皇賜號武夷仙。',32,'全唐诗/poet.song.130000.json','["一紙除書到海邊，紫皇賜號武夷仙。", "功名敢道渾無意，暫作閑人五百年。"]'),
('acf9ea76-dd06-4dc5-8dfb-08718621376d','縱筆四首  其三','陸游','宋','宋诗','song-poetry','','[]','背上嵯峨兩肉山，明駞有債自須還。',32,'全唐诗/poet.song.130000.json','["背上嵯峨兩肉山，明駞有債自須還。", "玉霄峰頭雪色鹿，清曉一聲烟雨間。"]'),
('e9e4a7a8-7e48-4456-a9ad-f39a2c15909a','縱筆四首  其四','陸游','宋','宋诗','song-poetry','','[]','素月徘徊牛斗間，天風吹鶴度函關。',32,'全唐诗/poet.song.130000.json','["素月徘徊牛斗間，天風吹鶴度函關。", "一年似此佳時少，喚起陳摶醉華山。"]'),
('a1e12301-f81b-4bbd-b1b5-f49725a882bb','自嘲觧嘲二首  其一','陸游','宋','宋诗','song-poetry','','[]','世變真難料，吾癡只自嘲。',48,'全唐诗/poet.song.130000.json','["世變真難料，吾癡只自嘲。", "移山謀畚土，黏日欲煎膠。", "得句題修竹，烹茶拾墮巢。", "行年不須筭，斷是死衡茆。"]'),
('6435ed60-834d-4671-8583-4ada9ee5abbd','自嘲觧嘲二首  其二','陸游','宋','宋诗','song-poetry','','[]','種稻稽山下，誅茆剡曲傍。',48,'全唐诗/poet.song.130000.json','["種稻稽山下，誅茆剡曲傍。", "鳴雞耐昏旦，飛燕異炎凉。", "古劍寒三尺，殘書亂一床。", "穹穹與厚厚，能識我非狂。"]'),
('643ee94c-a7b9-4703-9cca-aece8dd96b02','春雨絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','恰喜西窗晚照明，虚簷又報雨來聲。',32,'全唐诗/poet.song.130000.json','["恰喜西窗晚照明，虚簷又報雨來聲。", "端憂不用占龜兆，壊盡花時自觧晴。"]'),
('4eff3ef1-4595-4dcd-ad1e-7f79f7a9b560','春雨絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','千點猩紅蜀海棠，誰憐雨裏作啼粧。',32,'全唐诗/poet.song.130000.json','["千點猩紅蜀海棠，誰憐雨裏作啼粧。", "殺風景處君知否，正伴鄰翁救麥忙。"]'),
('c68eb65c-8804-4f1b-8898-b5ddb2826066','春雨絕句六首  其三','陸游','宋','宋诗','song-poetry','','[]','天公似欲敗蠶麰，雨冒南山暮不收。',32,'全唐诗/poet.song.130000.json','["天公似欲敗蠶麰，雨冒南山暮不收。", "騃女癡兒那念此，貪看科斗滿清溝。"]'),
('c6cb25f3-d994-452b-9c7c-0b15c720995b','春雨絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','今年春半不知春，飛雹奔雷嚇殺人。',32,'全唐诗/poet.song.130000.json','["今年春半不知春，飛雹奔雷嚇殺人。", "縫得春衫元未著，免敎惆悵洛陽塵。"]'),
('16316102-0e99-4170-8920-5c368c8bcd88','春雨絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','梅中最晚是緗梅，一日來看欲百回。',32,'全唐诗/poet.song.130000.json','["梅中最晚是緗梅，一日來看欲百回。", "俗紫凡紅終避舍，不妨自向雨中開。"]'),
('9101a10b-a950-4984-99c8-04aac45e05f1','春雨絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','蕭條冬令侵春晚，淅瀝寒聲滴夜長。',32,'全唐诗/poet.song.130000.json','["蕭條冬令侵春晚，淅瀝寒聲滴夜長。", "更事老翁頑到底，每言宜睡好燒香。"]'),
('79394c70-66a3-4895-a0ad-2be81f241a5a','雨中卧病有感','陸游','宋','宋诗','song-poetry','','[]','病卧窮山白髮新，不堪風雨過中春。',64,'全唐诗/poet.song.130000.json','["病卧窮山白髮新，不堪風雨過中春。", "歌呼空倚一尊酒，零落漸無吾輩人。", "千戴詩書成長物，兩京宫闕委胡塵。", "非熊老子不復見，誰吊遺魂清渭濵。"]'),
('a76be41b-c4d3-4724-b0bf-fd9301f375d1','舟中作','陸游','宋','宋诗','song-poetry','','[]','不遷比景戍交河，三徑歸來得已多。',64,'全唐诗/poet.song.130000.json','["不遷比景戍交河，三徑歸來得已多。", "應俗愈踈身老大，讀書漸廢意蹉跎。", "閑從孫叟蘇門嘯，醉和荆卿易水歌。", "歌罷却揮孤櫂去，石闌干下買漁蓑。"]'),
('63b77caf-a2f6-4944-a8bd-5bd8a6f1d9fe','山園','陸游','宋','宋诗','song-poetry','','[]','買得新園近釣磯，旋營茆棟設柴扉。',64,'全唐诗/poet.song.130000.json','["買得新園近釣磯，旋營茆棟設柴扉。", "山經宿雨修容出，花倚和風作態飛。", "世事只成驚老眼，酒徒頻約典春衣。", "狂吟爛醉君無笑，十丈愁城要解圍。"]'),
('afe3353a-4544-4c7f-906d-c17a7681dc9b','聞虜亂','陸游','宋','宋诗','song-poetry','','[]','運數群胡盡，烟塵北道昏。',48,'全唐诗/poet.song.130000.json','["運數群胡盡，烟塵北道昏。", "百年身易老，萬里志空存。", "楊柳揺馳道，櫻桃奉寢園。", "南公忠義薄，此恨與誰論。"]'),
('b320ed12-f569-4b60-8ba5-c225a02551ff','題千秋觀懷賀亭','陸游','宋','宋诗','song-poetry','','[]','河湟使典珥左貂，曲江相君謝不朝。',160,'全唐诗/poet.song.130000.json','["河湟使典珥左貂，曲江相君謝不朝。", "宫中玉環狐作妖，黠虜旁窺心已驕。", "天維欲絕地軸搖，有識凜凜憂宗祧。", "賀公託言師松喬，黄冠徑歸侶漁樵。", "老馬立仗不自聊，去如鸞鳳冲烟霄。", "傾都祖餞擁渭橋，賢哉大夫脱塵囂。", "揚州渡江木蘭橈，入東夜聽錢塘潮。", "我來故祠竹蕭蕭，黄冠野服傳生綃。", "詞卑愧匪英瓊瑤，空采蘋藻奠桂椒。", "虛堂斷香閉寂寥，遺魂零落何由招。"]'),
('373b9d96-107b-4d8a-ba8c-923b1e8cae6a','禹祠','陸游','宋','宋诗','song-poetry','','[]','我昔下三峽，南賔繫歸艫。',216,'全唐诗/poet.song.130000.json','["我昔下三峽，南賔繫歸艫。", "渡江謁神禹，拜手薦爼壺。", "壽藤枝如虬，巨柏腹若刳。", "門庭雖日荒，殿寢猶枝梧。", "巴俗喜禱祠，解牛舞群巫。", "巍巍黻冕古，食與夷鬼俱。", "聖度固兼容，臣憤獨不攄。", "還鄉瞻廟貌，嬴政久已除。", "嶽牧儼如生，想像聞都俞。", "廓清雖可喜，欲退復躊躇。", "念昔平水土，棋布畫九區。", "豈知千歲後，戎羯居中都。", "老虜失大刑，今復得其雛。", "直令挽天河，未濯腥膻汙。", "夷鬼細事耳，披攘直須臾。", "天下讎不復，大耻何時祛。", "蚩蚩謂固然，此責在吾徒。", "揮涕霑庭草，誰憐小臣愚。"]'),
('5c4c7a83-dd1f-4a5a-8f5a-d261305781c6','樊江','陸游','宋','宋诗','song-poetry','','[]','手中一卷養魚經，又向樊江上草亭。',64,'全唐诗/poet.song.130000.json','["手中一卷養魚經，又向樊江上草亭。", "朝雨染成新漲綠，春烟澹盡遠山青。", "榜舟不厭頻來往，岸幘常須半醉醒。", "賦罷新詩自高詠，滿汀鷗鷺欲忘形。"]'),
('ae572cee-a161-4893-be72-9b9b46e3c4a6','東關二首  其一','陸游','宋','宋诗','song-poetry','','[]','路入東關物象奇，角巾老子曵笻枝。',64,'全唐诗/poet.song.130000.json','["路入東關物象奇，角巾老子曵笻枝。", "蠶如黑蟻桑生後，秧似青鍼水滿時。", "穿市不嫌微雨濕，過谿翻喜壊橋危。", "當年野店題詩處，又典春衣具午炊。"]'),
('23d4c48d-a90c-4a5d-b059-243ed3bdc766','東關二首  其二','陸游','宋','宋诗','song-poetry','','[]','雲蹙魚鱗襯夕陽，放翁繫纜水雲鄉。',64,'全唐诗/poet.song.130000.json','["雲蹙魚鱗襯夕陽，放翁繫纜水雲鄉。", "一笻疾步人驚健，斗酒高歌自笑狂。", "風暖市樓吹絮雪，蠶生村舍采桑黄。", "東阡南陌無窮樂，底事隨人作許忙。"]'),
('a2063bf3-bd0d-46db-99e2-46ef54862fd7','練塘','陸游','宋','宋诗','song-poetry','','[]','微風吹頰酒初醒，落日舟横杜若汀。',32,'全唐诗/poet.song.130000.json','["微風吹頰酒初醒，落日舟横杜若汀。", "水秀山明何所似，玉人臨鏡暈螺青。"]'),
('e501a403-a568-4e86-970d-efdadbf66f5b','娥江市','陸游','宋','宋诗','song-poetry','','[]','小聚依江近，支流入浦分。',48,'全唐诗/poet.song.130000.json','["小聚依江近，支流入浦分。", "荒寒孤店雨，零亂野祠雲。", "薄餉炊畬粟，珍烹采澗芹。", "年來去健羨，摩腹自欣欣。"]'),
('482a1800-9192-4770-9d0d-d42081c303aa','宿野人家','陸游','宋','宋诗','song-poetry','','[]','避雨來投白版扉，野人憐客不相違。',64,'全唐诗/poet.song.130000.json','["避雨來投白版扉，野人憐客不相違。", "林喧鳥雀棲初定，村近牛羊暮自歸。", "土釡暖湯先濯足，豆䕸吹火旋烘衣。", "老來世路渾諳盡，露宿風餐未覺非。"]'),
('fc661cbc-67dc-4828-8897-86766f5d32cb','舟中遣懷','陸游','宋','宋诗','song-poetry','','[]','三黜歸來結草廬，平生狂態掃無餘。',64,'全唐诗/poet.song.130000.json','["三黜歸來結草廬，平生狂態掃無餘。", "但思下帷授老子，那復騎牛讀漢書。", "曆曆舊逰渾似夢，蕭蕭殘髮不勝梳。", "閑中事業君知否，不把漁竿即荷鉏。"]'),
('3362f755-9e7f-4735-9f2b-f6d8cf32f89a','歸次樊江','陸游','宋','宋诗','song-poetry','','[]','芳草東西路，綠楊長短亭。',48,'全唐诗/poet.song.130000.json','["芳草東西路，綠楊長短亭。", "人生豈匏繫，吾志本鴻冥。", "征袖朝霑雨，歸帆夜戴星。", "長魚幸能買，且復倒殘瓶。"]'),
('0c2d0f15-2c43-4a31-9b7e-98e8dd7ecd2d','夜過魯墟','陸游','宋','宋诗','song-poetry','','[]','中夜過魯墟，船底鳴細浪。',96,'全唐诗/poet.song.130000.json','["中夜過魯墟，船底鳴細浪。", "月出菱歌長，林闇績火壯。", "故居不可識，四顧但青嶂。", "百年幾廢興，撫事一悽愴。", "士生本耕稼，時來偶卿相。", "功名亦餘事，所勉在素尚。", "况吾多難者，久已冥得喪。", "微祿行當辭，没身事幽曠。"]'),
('a8e359c4-03f7-4dd9-ac22-3eaef4f9fd27','有感','陸游','宋','宋诗','song-poetry','','[]','温洛榮河拱舊京，從來人物富豪英。',64,'全唐诗/poet.song.130000.json','["温洛榮河拱舊京，從來人物富豪英。", "報仇雖有楚三戸，守節得無齊二城。", "敵虜寕能斷地脉，王師行復暢天聲。", "鳳麟久伏應争奮，勉爲明時頌太平。"]'),
('9d8789e8-23f4-484e-a532-1a166f418c21','逰石帆玉笥石旗諸山','陸游','宋','宋诗','song-poetry','','[]','暮景苦多病，幽尋寄一欣。',48,'全唐诗/poet.song.130000.json','["暮景苦多病，幽尋寄一欣。", "溪喧常似雨，石潤易生雲。", "天迥回鴉陣，林疏過鹿群。", "莫談朝市事，吾老厭紛紛。"]'),
('c870dc95-1364-41e4-affd-c4200be4ebdf','信步近村','陸游','宋','宋诗','song-poetry','','[]','端閑何以永今朝，拈得笻枝度野橋。',64,'全唐诗/poet.song.130000.json','["端閑何以永今朝，拈得笻枝度野橋。", "三畝空園喧啄木，十尋高樹絡凌霄。", "長饑未必緣詩瘦，多悶惟須賴酒澆。", "興盡歸來又陳迹，一林風葉暮蕭蕭。"]'),
('9c8c0880-7160-4dd5-ba10-9d43e20f9208','寒食省九里大墓','陸游','宋','宋诗','song-poetry','','[]','陌上簫聲正賣餳，籃輿兀兀雨冥冥。',64,'全唐诗/poet.song.130000.json','["陌上簫聲正賣餳，籃輿兀兀雨冥冥。", "人來平野一點白，山壓亂雲千疊青。", "石馬朱門松下路，凍韲冷飯柳陰亭。", "華顛尚記兒童日，撫事興懷涕自零。"]'),
('c8d5795c-2d4c-4beb-bd53-23c4144c6fad','平水道中','陸游','宋','宋诗','song-poetry','','[]','處處陂水滿，家家巢燕忙。',48,'全唐诗/poet.song.130000.json','["處處陂水滿，家家巢燕忙。", "葉舒桑漸闇，穗重麥初昻。", "高下山花發，青紅粉餌香。", "亦知時節好，老大自悲傷。"]'),
('a2d48271-cc68-4f4c-b551-0864755f557d','五雲橋','陸游','宋','宋诗','song-poetry','','[]','若耶北與鏡湖通，縹緲飛橋跨半空。',32,'全唐诗/poet.song.130000.json','["若耶北與鏡湖通，縹緲飛橋跨半空。", "陵谷變遷誰復識，我來徙倚暮烟中。"]'),
('9b7acb61-3bb1-47d7-9ebf-80da82960647','小雨雲門溪上','陸游','宋','宋诗','song-poetry','','[]','好雨疏踈壓暮埃，斷雲漠漠带春雷。',64,'全唐诗/poet.song.130000.json','["好雨疏踈壓暮埃，斷雲漠漠带春雷。", "離黄穿樹語斷續，翠碧衘魚飛去來。", "生菜入盤隨冷餅，朱櫻上市伴青梅。", "狂吟不是誇强健，老氣如山未許摧。"]'),
('0b0ce4cf-5f40-44c7-a9fb-ef8311d26434','雲門獨坐','陸游','宋','宋诗','song-poetry','','[]','山北山南處處行，回頭六十七清明。',32,'全唐诗/poet.song.130000.json','["山北山南處處行，回頭六十七清明。", "如今老去摧頹甚，獨坐焚香聴水聲。"]'),
('5dbecc8b-5489-4afd-b64a-05fa85d3bac8','泛湖至東涇三首  其一','陸游','宋','宋诗','song-poetry','','[]','春水六七里，夕陽三四家。',48,'全唐诗/poet.song.130000.json','["春水六七里，夕陽三四家。", "兒童牧鵝鴨，婦女治桑麻。", "地僻衣巾古，年豐笑語譁。", "老夫維小艇，半醉摘藤花。"]'),
('b4865d73-c8a8-4a62-90eb-006153e1f456','泛湖至東涇三首  其二','陸游','宋','宋诗','song-poetry','','[]','湖光分别浦，嶺路過前村。',48,'全唐诗/poet.song.130000.json','["湖光分别浦，嶺路過前村。", "泉石相縈带，雲烟互吐吞。", "耕犁無易業，鄰曲有通婚。", "試覓誅茆地，吾將遺子孫。"]'),
('cf0dd1d1-6a20-47a3-ac6b-72e890da6805','泛湖至東涇三首  其三','陸游','宋','宋诗','song-poetry','','[]','細細桃枝竹，疏踈麂眼籬。',48,'全唐诗/poet.song.130000.json','["細細桃枝竹，疏踈麂眼籬。", "雪霜燒葑夜，月露采菱時。", "腰斧登山早，移罾出浦遲。", "關心盡幽事，恨汝不能詩。"]'),
('a3899860-4b28-4ab8-8a24-a582d9cb988f','舟過梅塢胡氏居愛其幽邃爲賦一詩','陸游','宋','宋诗','song-poetry','','[]','稽山翠入家家窗，此家清絕無與雙。',64,'全唐诗/poet.song.130000.json','["稽山翠入家家窗，此家清絕無與雙。", "丹葩綠樹錦繡谷，清波白石玻璃江。", "一堤茂草有眠犢，數掩短籬無吠尨。", "北軒商略可散髮，借與放翁傾酒缸。"]'),
('e056818c-c971-41e6-a9c8-23f572baab7a','北窗','陸游','宋','宋诗','song-poetry','','[]','北窗本意傲羲皇，老返園廬味更長。',64,'全唐诗/poet.song.130000.json','["北窗本意傲羲皇，老返園廬味更長。", "犢健戴星耕白水，蠶饑衝雨采青桑。", "俚儒朱墨開冬學，廟史牲牢祝歲穣。", "從此鬢毛雖似雪，未妨擊壌頌虞唐。"]'),
('ed3e357e-1657-4f62-b986-2e3d066d68dd','聞蛙','陸游','宋','宋诗','song-poetry','','[]','科斗忽安在，蛙聲豪有餘。',48,'全唐诗/poet.song.130000.json','["科斗忽安在，蛙聲豪有餘。", "雖成兩部樂，恨失一編書。", "忿怒緣何事，號呼可奈渠。", "厨人不遐棄，猶得伴溪魚。"]'),
('4ce12419-ae31-49af-9db8-cc6e718cff51','晚春感事四首  其一','陸游','宋','宋诗','song-poetry','','[]','風惡房櫳燕子歸，雨多山路蕨芽肥。',64,'全唐诗/poet.song.130000.json','["風惡房櫳燕子歸，雨多山路蕨芽肥。", "青餈旋擣作寒食，白葛預裁充暑衣。", "穉子日長供課早，故人官達寄書稀。", "幽居自喜渾無事，又向湖陰坐釣磯。"]'),
('5336e1ce-976f-4fcf-a7d0-3fc2c6e395a5','晚春感事四首  其二','陸游','宋','宋诗','song-poetry','','[]','和風薄靄過清明，減盡重裘覺體輕。',64,'全唐诗/poet.song.130000.json','["和風薄靄過清明，減盡重裘覺體輕。", "正午軒窗無樹影，乍晴阡陌有鶯聲。", "醸成西蜀鵝雛酒，煮就東坡玉糁羮。", "捫腹翛然出門去，春郊何處不堪行。"]'),
('bce42d0d-9999-41a7-9c40-f414e43a4f06','晚春感事四首  其三','陸游','宋','宋诗','song-poetry','','[]','徙倚闌干送落暉，年華冉冉恨依依。',64,'全唐诗/poet.song.130000.json','["徙倚闌干送落暉，年華冉冉恨依依。", "護雛燕子常更出，著雨楊花又懶飛。", "己爲讀書悲眼力，還因攬带嘆腰圍。", "親朋半作荒郊冢，欲話初心泪滿衣。"]'),
('577da0a1-8bcc-4f53-b0da-2f546d3a4c3c','晚春感事四首  其四','陸游','宋','宋诗','song-poetry','','[]','少年騎馬入咸陽，鶻似身輕蝶似狂。',64,'全唐诗/poet.song.130000.json','["少年騎馬入咸陽，鶻似身輕蝶似狂。", "蹴鞠塲邉萬人看，鞦韆旗下一春忙。", "風光流轉渾如昨，志氣低摧只自傷。", "日永東齋淡無事，閉門掃地獨焚香。"]'),
('91c50a9a-67e1-433a-90b6-d53ef6a201e3','山居','陸游','宋','宋诗','song-poetry','','[]','平生杜宇最相知，遺我巢山一叚奇。',64,'全唐诗/poet.song.130000.json','["平生杜宇最相知，遺我巢山一叚奇。", "茶磑細香供隱几，松風幽韵入哦詩。", "溪邊拂石同兒釣，竹下開軒喚客棋。", "幾許放翁新事業，不教虚過太平時。"]'),
('fb21e133-1c79-4946-a80b-dbabd7f3ccea','四月三日同子坦子聿遊湖中諸山','陸游','宋','宋诗','song-poetry','','[]','我行無所詣，悠揚信舴艋。',144,'全唐诗/poet.song.130000.json','["我行無所詣，悠揚信舴艋。", "愛此綠樹村，捨棹度小嶺。", "路窮忽披豁，怳然得異境。", "蒼玉立萬峰，清鏡渺千頃。", "更爲西南行，聊破春晝永。", "遙看秀邃處，疑足事幽屏。", "一崦果可人，奇石插碧井。", "鏘鳴若環佩，其味復甘冷。", "徘徊不忍去，照我鬚鬢影。", "須臾日穿林，井靣光炯炯。", "古今勝絕意，正用一笑領。", "安得絕世喧，於兹慕箕潁。"]'),
('efe77a53-8925-47ee-aff7-dbab58df76cd','梅僊塢小隱','陸游','宋','宋诗','song-poetry','','[]','綠樹陰陰小嶺西，一翁二子自扶攜。',64,'全唐诗/poet.song.130000.json','["綠樹陰陰小嶺西，一翁二子自扶攜。", "雨前芳嫩初浮盌，臘脚清醇旋拆泥。", "本欲省緣行買餅，未能去殺尚烹雞。", "弄橈莫便尋歸路，湖静無風日未低。"]'),
('184b9aa3-7811-486c-b131-92950fbb9ef4','盟雲','陸游','宋','宋诗','song-poetry','','[]','謂雲本無心，企望乃爾奇。',144,'全唐诗/poet.song.130000.json','["謂雲本無心，企望乃爾奇。", "謂雲果有心，百變端爲誰。", "豈憐此翁愁，一出怡悦之。", "横截千嶂平，高擎一峰危。", "銀城突嵳峨，玉海浩渺瀰。", "或爲群龍矯，或作孤鶴飛。", "卷舒閑有態，去來倐無時。", "滃滃覆松頂，靄靄映水湄。", "带雨過僧窗，和月傍釣磯。", "豈惟困畫工，吾詩固難追。", "惟當與之盟，畢世相娱嬉。", "忍饑固易耳，此友不可欺。"]'),
('eb29ab7c-7370-42c3-9bcb-5b1318e87f40','示兒','陸游','宋','宋诗','song-poetry','','[]','舍東已種百本桑，舍西仍築百步塘。',128,'全唐诗/poet.song.130000.json','["舍東已種百本桑，舍西仍築百步塘。", "早茶采盡晚茶出，小麥方秀大麥黄。", "老夫一飽手捫腹，不復舉首號蒼蒼。", "讀書習氣掃未盡，燈前簡牘紛朱黄。", "吾兒從旁論治亂，每使老子喜欲狂。", "不須飲酒徑自醉，取書相和聲琅琅。", "人生百病有已時，獨有書癖不可醫。", "願兒力耕足衣食，讀書萬卷真何益。"]'),
('10002db8-7ed2-41fd-90bc-cc54ef2c046d','村居初夏五首  其一','陸游','宋','宋诗','song-poetry','','[]','暮境難禁日月催，臘醅初見坼泥開。',64,'全唐诗/poet.song.130000.json','["暮境難禁日月催，臘醅初見坼泥開。", "壓車麥穗黄雲卷，食葉蠶聲白雨來。", "薄飯蕨薇端可飽，短衫紵葛亦新裁。", "宦塗自古多憂畏，白首爲農信樂哉。"]'),
('c658b249-e7ef-41be-a386-2f4650923995','村居初夏五首  其二','陸游','宋','宋诗','song-poetry','','[]','北陌東阡節物新，往來饋餉走比鄰。',64,'全唐诗/poet.song.130000.json','["北陌東阡節物新，往來饋餉走比鄰。", "出籠鵝白輕紅掌，藉藻魚鮮淡墨鱗。", "笑語相聞豐歲樂，耕桑自足古風淳。", "頽然一醉茆簷下，且免西曹議吐茵。"]'),
('1bdbd9bb-456c-4fb0-915e-960a3d7d39cd','村居初夏五首  其三','陸游','宋','宋诗','song-poetry','','[]','煮酒開時日正長，山家隨分答年光。',64,'全唐诗/poet.song.130000.json','["煮酒開時日正長，山家隨分答年光。", "梅青巧配吴鹽白，筍美偏宜蜀豉香。", "風暖緊催蠶上簇，雨餘閑看稻移秧。", "老夫見事真成晚，浪走人間兩鬢霜。"]'),
('f258541a-9c6e-418b-82fc-3b15d6acab25','村居初夏五首  其四','陸游','宋','宋诗','song-poetry','','[]','天遣爲農老故鄉，山園三畝鏡湖傍。',64,'全唐诗/poet.song.130000.json','["天遣爲農老故鄉，山園三畝鏡湖傍。", "嫩莎經雨如秧綠，小蝶穿花似繭黄。", "斗酒隻雞人笑樂，十風五雨歲豐穣。", "相逢但喜桑麻長，欲話窮通已兩忘。"]'),
('a3c08d37-0839-4299-8801-316baa40cfb0','村居初夏五首  其五','陸游','宋','宋诗','song-poetry','','[]','故鄉風物勝荆吳，流水青山無處無。',64,'全唐诗/poet.song.130000.json','["故鄉風物勝荆吳，流水青山無處無。", "列植園林多美菓，飽鉏畦壟富嘉蔬。", "橋邊來淬剶桑斧，池畔行芟縳糭菰。", "我有素紈如月扇，會憑名手作新圗。"]'),
('0a973629-4090-4b15-88da-b6240e9c5e5b','城東逆旅','陸游','宋','宋诗','song-poetry','','[]','店家乞火燎征衣，濕竹生薪不受吹。',64,'全唐诗/poet.song.130000.json','["店家乞火燎征衣，濕竹生薪不受吹。", "更甚從戎戍邊日，正如隨計入關時。", "百年擾擾夢相似，萬事悠悠心自知。", "賴有床頭周易在，不妨清坐忍朝饑。"]'),
('8019976d-8695-46e5-b525-03de9a040772','江村初夏','陸游','宋','宋诗','song-poetry','','[]','紫葚狼籍桑林下，石榴一枝紅可把。',96,'全唐诗/poet.song.130000.json','["紫葚狼籍桑林下，石榴一枝紅可把。", "江村夏淺暑猶薄，農事方興人滿野。", "連雲麥熟新食麨，小裹荷香初賣鮓。", "蘋洲蓬艇疾如鳥，沙路芒鞵健如馬。", "君看早朝塵撲靣，豈勝春耕泥沒踝。", "爲農世世樂有餘，寄語兒曹勿輕捨。"]'),
('8c0b9b92-f45e-4824-9f20-4abdba0d57e9','舟中作','陸游','宋','宋诗','song-poetry','','[]','湖海飄然避世紛，汀洲沙鷺舊知聞。',64,'全唐诗/poet.song.130000.json','["湖海飄然避世紛，汀洲沙鷺舊知聞。", "漁舟卧看山方好，野店沽嘗酒易醺。", "病骨未成松下土，老身常伴渡頭雲。", "美芹欲獻雖堪笑，此意區區亦愛君。"]'),
('a03bbcb5-dfa2-48a5-a2f7-bedb83b9186b','東關二首  其一','陸游','宋','宋诗','song-poetry','','[]','天華寺西艇子横，白蘋風細浪紋平。',32,'全唐诗/poet.song.130000.json','["天華寺西艇子横，白蘋風細浪紋平。", "移家只欲東關住，夜夜湖中看月生。"]'),
('ff27e59b-d64e-4c1f-a996-283bc6be1b79','東關二首  其二','陸游','宋','宋诗','song-poetry','','[]','烟水蒼茫西復東，扁舟又繫柳陰中。',32,'全唐诗/poet.song.130000.json','["烟水蒼茫西復東，扁舟又繫柳陰中。", "三更酒醒殘燈在，卧聴蕭蕭雨打篷。"]'),
('8c2d374e-7118-4ea3-a169-a6cfab273332','少微山','陸游','宋','宋诗','song-poetry','','[]','平生一舴艋，幾到少微山。',48,'全唐诗/poet.song.130000.json','["平生一舴艋，幾到少微山。", "傑觀掃無迹，高人呼不還。", "崕崩危欲壓，磴斷滑難攀。", "日暮增幽興，漁歌漭蒼間。"]'),
('d0194d93-ce53-4c64-94a6-e21689b32b60','舟行至織女潭','陸游','宋','宋诗','song-poetry','','[]','櫓枝揺碎碧琉璃，織女潭東白塔西。',64,'全唐诗/poet.song.130000.json','["櫓枝揺碎碧琉璃，織女潭東白塔西。", "带犢吴牛依茂樾，添巢海燕啄新泥。", "山谿曲折遥通谷，沙水淙潺各赴溪。", "猶恨兒曹不同載，一尊他日要重攜。"]'),
('ac94c80e-0cb6-4afc-ab44-24e98c3a8b8f','書嘆','陸游','宋','宋诗','song-poetry','','[]','濩落非時用，棲遲送此生。',48,'全唐诗/poet.song.130000.json','["濩落非時用，棲遲送此生。", "只知求醉死，何憚得狂名。", "伏櫪天涯老，吞舟海澨横。", "眼前交舊盡，有泪對誰傾。"]'),
('37713f54-6e47-4389-b994-cf24542b88c8','小園獨立','陸游','宋','宋诗','song-poetry','','[]','草香無處覓，花嫩不禁飛。',48,'全唐诗/poet.song.130000.json','["草香無處覓，花嫩不禁飛。", "澤國春歸晚，柴門客過稀。", "新泥添燕戸，細雨濕鶯衣。", "倚杖臨階久，衰翁氣力微。"]'),
('2d6b0004-ae33-4cb5-8cd1-6be98fdca6d3','觀蘇滄浪草書絹圗歌','陸游','宋','宋诗','song-poetry','','[]','天孫獨處河之湄，龍梭夜織冰蠶絲。',99,'全唐诗/poet.song.130000.json','["天孫獨處河之湄，龍梭夜織冰蠶絲。", "機頭剪落光陸離，騎鯨仙人醉題詩。", "字大如斗健欲飛，利刀猛斫生蛟螭。", "墨渇字燥尤怪奇，百鬽潜影神靈悲。", "嗚呼束雲作筆兮海爲硯，激水上騰龍野戰。", "乾坤震蕩人始驚，筆未落時誰得見。"]'),
('06a705c7-e5de-4502-b57e-5c34eecc86b4','睡起書觸目','陸游','宋','宋诗','song-poetry','','[]','壓架藤花重，團枝杏子稠。',48,'全唐诗/poet.song.130000.json','["壓架藤花重，團枝杏子稠。", "渇蜂窺硯水，弱燕集簾鈎。", "入夏暑猶薄，投閑身自由。", "午窗初睡起，幽興付茶甌。"]'),
('1e56e172-32f2-4186-8ac7-2715f43c6500','曉雨初霽','陸游','宋','宋诗','song-poetry','','[]','曉來一雨洗塵痕，濃綠陰陰可一園。',32,'全唐诗/poet.song.130000.json','["曉來一雨洗塵痕，濃綠陰陰可一園。", "燕子聲中寂無事，獨穿苔徑出籬門。"]'),
('9bd2d84b-1802-48b9-8a3d-f213660a6a79','夏雨','陸游','宋','宋诗','song-poetry','','[]','連朝暑溽不可過，動地忽有東北風。',64,'全唐诗/poet.song.130000.json','["連朝暑溽不可過，動地忽有東北風。", "嵯峨雲壓世界碎，夭矯龍卷江湖空。", "塵沙洗濯草木醒，溝澮瀲灎舟舸通。", "更煩造物出壯觀，跨海千丈垂天虹。"]'),
('2f09d444-bd8e-4e38-a751-002abde66d02','自東涇度小嶺聞有地可卜庵喜而有賦','陸游','宋','宋诗','song-poetry','','[]','小嶺西南烟水間，頗聞有地百弓寛。',64,'全唐诗/poet.song.130000.json','["小嶺西南烟水間，頗聞有地百弓寛。", "誰其云者兩黄鵠，何以報之雙玉盤。", "竹塢未昏先晻曖，蓮汀當暑亦清寒。", "一庵何日從吾好，會約高人共倚闌。"]'),
('fcd4949d-90cc-48ab-9a70-78c29a48eecd','露坐','陸游','宋','宋诗','song-poetry','','[]','五月暑猶薄，中庭試葛衣。',48,'全唐诗/poet.song.130000.json','["五月暑猶薄，中庭試葛衣。", "蛙聲經雨壯，螢點避風稀。", "塵念三生誤，歸心半世違。", "殘年端有幾，可復負漁磯。"]'),
('c305420f-adf9-4e98-8b1b-6c72a7ef0beb','自笑','陸游','宋','宋诗','song-poetry','','[]','自笑胸中抵海寛，韭韲麥飯日加餐。',64,'全唐诗/poet.song.130000.json','["自笑胸中抵海寛，韭韲麥飯日加餐。", "住山緣熟塵機息，養氣功深槁靣丹。", "惡路慣曾經灎澦，浮生何啻夢邯鄲。", "鏡湖五月秋蕭爽，剩傍灘頭把釣竿。"]'),
('f6639bc1-2a73-4f9b-9607-533c00519498','夜賦','陸游','宋','宋诗','song-poetry','','[]','夜窗搔首髮鬅鬙，病不勝衣倚瘦藤。',64,'全唐诗/poet.song.130000.json','["夜窗搔首髮鬅鬙，病不勝衣倚瘦藤。", "堪笑顔回忍饑面，常依韓愈看書燈。", "殘生已與灰俱冷，舊友誰如几可憑。", "月落風生忽增氣，掠簷勁翮有歸鷹。"]'),
('f6e74fd6-1f52-40b6-bdc8-64c24e630711','書懷','陸游','宋','宋诗','song-poetry','','[]','老死已無日，功名猶自期。',24,'全唐诗/poet.song.130000.json','["老死已無日，功名猶自期。", "清笳太行路，何日出王師。"]'),
('c2eb8d0b-a1a7-46d5-9068-d55d97c0ac72','醉後作小草因成長句','陸游','宋','宋诗','song-poetry','','[]','天教老去未全衰，猶欠縱横萬首詩。',64,'全唐诗/poet.song.130000.json','["天教老去未全衰，猶欠縱横萬首詩。", "家近將軍觴詠地，身如太史滯留時。", "酒翻銀浪紅螺醆，墨涌玄雲紫玉池。", "流落不妨風味在，花前醉草寫烏絲。"]'),
('862842d0-336f-4455-bacc-c01dcd00daff','雨中作','陸游','宋','宋诗','song-poetry','','[]','空濛初喜灑橺楹，忽聴空階點滴聲。',64,'全唐诗/poet.song.130000.json','["空濛初喜灑橺楹，忽聴空階點滴聲。", "高枕便知宜夕睡，豐年不嘆負春耕。", "多情幽草沿牆綠，無賴群蛙繞舍鳴。", "屈指清秋兩旬近，却愁徂歲又峥嶸。"]'),
('89920795-c62b-4178-a3a2-31c16c33eefe','詠史','陸游','宋','宋诗','song-poetry','','[]','入郢功成賜屬鏤，削吴計用載厨車。',32,'全唐诗/poet.song.130000.json','["入郢功成賜屬鏤，削吴計用載厨車。", "閉門種菜英雄事，莫笑衰翁日荷鋤。"]'),
('2a38a3db-7f16-4dab-98b4-e615309eb4ee','登鵝鼻山至絕頂訪秦刻石且北望大海山路危甚人迹所罕至也','陸游','宋','宋诗','song-poetry','','[]','街頭旋買雙芒屩，作意登山殊不惡。',160,'全唐诗/poet.song.130000.json','["街頭旋買雙芒屩，作意登山殊不惡。", "蒼崖無罅竹鞭逸，崩石欲墜松根絡。", "憑高開豁快送目，曆險崎嶇危著脚。", "川雲忽起兩蛟舞，瀑水高吹萬珠落。", "大巖空腔誰所刳，絕壁峭立端疑削。", "坡平或可坐百人，峽束僅容飛一鶴。", "蛇蹊岌岌頭自眩，鬼谷惨惨神先愕。", "秦皇馬迹散莓苔，如鑴非鑴鑿非鑿。", "殘碑不禁野火燎，造物似報焚書虐。", "人民城郭俱已非，烟海浮天獨如昨。"]'),
('40bad43b-c145-490b-be1f-93431a245d91','六七月之交山中凉甚','陸游','宋','宋诗','song-poetry','','[]','城市方炎熱，村墟乃爾凉。',48,'全唐诗/poet.song.130000.json','["城市方炎熱，村墟乃爾凉。", "拂窗桐葉下，繞舍稻花香。", "獨鶴警秋露，雙螢明屋梁。", "卧聞機婦織，感嘆夜初長。"]'),
('ea5860c6-d2e6-4952-a95d-c9f25af8226c','幽居三首  其一','陸游','宋','宋诗','song-poetry','','[]','大患元因有此身，百年强半走踆踆。',64,'全唐诗/poet.song.130000.json','["大患元因有此身，百年强半走踆踆。", "折殘廣武城邉柳，染盡洛陽衣上塵。", "繞樹鵲孤棲漸稳，支床龜老息初勻。", "出門不欲摩雙眼，世態年來又一新。"]'),
('baaaf334-c2d7-47db-961b-0e9afe081204','幽居三首  其二','陸游','宋','宋诗','song-poetry','','[]','百頃菰蒲古澤中，老夫病起恰秋風。',64,'全唐诗/poet.song.130000.json','["百頃菰蒲古澤中，老夫病起恰秋風。", "流年不貸人皆老，造物無私我自窮。", "市隱昔曾從嘯父，山栖今欲効園公。", "芳樽雖匪金丹術，槁面尊前也蹔紅。"]'),
('358bc25c-f4b7-4ffe-a6d0-3b520f224c71','幽居三首  其三','陸游','宋','宋诗','song-poetry','','[]','烟水重重際海涯，夜深風雨耿茆茨。',64,'全唐诗/poet.song.130000.json','["烟水重重際海涯，夜深風雨耿茆茨。", "交朋散落歡娱少，憂患侵陵志氣衰。", "癡腹何由有鱗甲，俗情自未去毛皮。", "詩書六十餘年夢，更擬傳衣付小兒。"]'),
('a36cdc85-9408-4b65-b8dc-1b3b430d1f6d','園中雜詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','藝花本無多，過眼那復遺。',48,'全唐诗/poet.song.130000.json','["藝花本無多，過眼那復遺。", "陰陰一園綠，佳處乃在兹。", "悠然東窗下，顧與枕簟宜。", "風輕竹觧籜，雨足果壓枝。"]'),
('d62c8f85-5ce3-4983-ab3d-a3035a245dc3','園中雜詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','珍禽下上鳴，迨及清潤時。',48,'全唐诗/poet.song.130000.json','["珍禽下上鳴，迨及清潤時。", "豈惟侑我觴，亦以起我詩。", "白練一團雪，來與紅練俱。", "魚虎飛照水，意若愛翠裾。"]'),
('b466ab2b-bf67-4412-ac47-cb4a7e7141e2','予所居南並鏡湖北則陂澤重複抵海小舟縱所之或數日乃歸','陸游','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',48,'全唐诗/poet.song.130000.json','["□□□□□，□□□□□。", "□□□□□，□□□□□。", "人間五十年，自笑晚乃悟。", "歸來寫苔紙，老憊無傑句。"]'),
('6eb63c1d-04da-4fea-82c4-ff282d295d6b','王給事餉玉友','陸游','宋','宋诗','song-poetry','','[]','散髮蕭然蒲葦林，馬軍送酒慰孤斟。',64,'全唐诗/poet.song.130000.json','["散髮蕭然蒲葦林，馬軍送酒慰孤斟。", "江河不洗古今恨，天地能知忠義心。", "無侣有時邀落月，放狂連夕到横參。", "玉船湛湛真秋露，却恨鵝兒色尚深。"]'),
('79ef0b12-f2bc-4294-84a7-d55fc28d65e2','晚興','陸游','宋','宋诗','song-poetry','','[]','白布裙襦退士裝，短籬幽徑獨相羊。',64,'全唐诗/poet.song.130000.json','["白布裙襦退士裝，短籬幽徑獨相羊。", "莎根蟋蟀催秋候，稗穂蜻蜓立晚凉。", "屈子所悲人盡醉，酈生常謂我非狂。", "知心賴有青天在，又炷中庭一夕香。"]'),
('9820bf0a-3370-4aba-862e-799354e395ac','村圃','陸游','宋','宋诗','song-poetry','','[]','村圃穿荒翳，秋容變慘悽。',48,'全唐诗/poet.song.130000.json','["村圃穿荒翳，秋容變慘悽。", "柳踈蟬噪急，雨重鵲飛低。", "小草臨池學，新詩滿竹題。", "若令車馬到，何處有幽棲。"]'),
('ec5a4f21-038d-4c93-8b90-fc5c00e452f5','七月一日夜坐舍北水涯戲作','陸游','宋','宋诗','song-poetry','','[]','兀傲胡床酒半醒，釣筒收盡數舟横。',64,'全唐诗/poet.song.130000.json','["兀傲胡床酒半醒，釣筒收盡數舟横。", "風生細葛無三伏，月上疏林正四更。", "北斗離離低欲盡，明河脉脉去無聲。", "斥僊豈復塵中戀，便擬騎鯨返玉京。"]'),
('2b3d00cd-83ec-40a2-9949-0719e2923c7a','病後登山亭','陸游','宋','宋诗','song-poetry','','[]','野客雙蓬鬢，空山一草亭。',48,'全唐诗/poet.song.130000.json','["野客雙蓬鬢，空山一草亭。", "睡魔欺茗薄，疾豎怯丹靈。", "治世窮馮衍，殘年老管寕。", "安居得後死，不敢恨飄零。"]'),
('31aad2b0-69de-494d-b478-f377a1b1a8fc','覽鏡','陸游','宋','宋诗','song-poetry','','[]','白頭漸覺黑絲多，造物將如此老何。',64,'全唐诗/poet.song.130000.json','["白頭漸覺黑絲多，造物將如此老何。", "三萬里天供醉眼，二千年事入悲歌。", "劍關曾蹴連雲棧，海道新窺浴日波。", "未頌中興吾未死，插江崖石竟須磨。"]'),
('55e88f07-22a4-4a2f-9680-cb5eac97ffc4','遣懷','陸游','宋','宋诗','song-poetry','','[]','許國區區不自勝，秋風空羨下鞲鷹。',64,'全唐诗/poet.song.130000.json','["許國區區不自勝，秋風空羨下鞲鷹。", "青雲夜嘆初心誤，白髮朝看一倍增。", "積憤有時歌易水，孤忠無路哭昭陵。", "頭顱自揣今如此，尚欲閑尋紫閣僧。"]'),
('f646435a-08ae-4d34-a829-858127d8e919','開元寺小閣十四韵','陸游','宋','宋诗','song-poetry','','[]','淵源兩名衲，築閣捫星辰。',168,'全唐诗/poet.song.130000.json','["淵源兩名衲，築閣捫星辰。", "近山卧蜿蜒，遠山高嶙峋。", "朝看雨空濛，暮揖雲輪囷。", "賦詩有宿諾，下語終未親。", "萬法不孤起，請君作其因。", "高挂四靣窗，凈掃一榻塵。", "室中絕人聲，門前謝車輪。", "容我睡半日，兩忘主與賔。", "緩燒海南沉，細碾建谿春。", "是間儻有句，可與屈宋鄰。", "詩如奮蟄龍，夭矯不受馴。", "使可造次得，何異池中鱗。", "世有擾龍手，愧我非其人。", "詩不已就乎，著眼勿逡巡。"]'),
('b22b25c6-f261-433c-bf89-f129effa3da3','寄題趙寛之主簿慈順堂','陸游','宋','宋诗','song-poetry','','[]','人間得意盡危機，猶有榮親事未非。',64,'全唐诗/poet.song.130000.json','["人間得意盡危機，猶有榮親事未非。", "魏闕恩光新綠綬，高堂娱侍舊斑衣。", "牙籖插架書無恙，蘭膳循陔養莫違。", "况有兩公天下士，爲君百斛瀉珠璣。"]'),
('f31cebf8-cbc3-4aac-8171-3b3596f9e3ac','郊居二首  其一','陸游','宋','宋诗','song-poetry','','[]','平生萬事不容求，惟有郊居志已酬。',64,'全唐诗/poet.song.130000.json','["平生萬事不容求，惟有郊居志已酬。", "更漏遠城雞唱曉，歲時無曆葉知秋。", "潮生小舫行收荻，月落長歌起飯牛。", "已作幸民仍醉死，人間毁譽判悠悠。"]'),
('26400e4f-1f39-458a-bf64-5869be48568a','郊居二首  其二','陸游','宋','宋诗','song-poetry','','[]','索米官倉例坐愚，東方未可戲侏儒。',64,'全唐诗/poet.song.130000.json','["索米官倉例坐愚，東方未可戲侏儒。", "行藏要付他年看，富貴真堪一笑無。", "等死不過賖歲月，長閑勿更問妻孥。", "狂豪儘道非平昔，老膽輪囷尚滿軀。"]'),
('93623cde-6a4d-4a67-a5c0-37fecc1e3577','新秋感事二首  其一','陸游','宋','宋诗','song-poetry','','[]','江上清秋昨夜回，漁扉正對荻洲開。',64,'全唐诗/poet.song.130000.json','["江上清秋昨夜回，漁扉正對荻洲開。", "志存天下食不足，節慕古人讒愈來。", "風際紙鳶那觧久，祭餘芻狗會堪哀。", "蕭然散髮聴秋雨，剩領新凉入酒杯。"]'),
('57ccfa9a-7127-4265-820c-1ca0c785e6a1','新秋感事二首  其二','陸游','宋','宋诗','song-poetry','','[]','北渚秋風凋白蘋，流年冉冉默傷神。',64,'全唐诗/poet.song.130000.json','["北渚秋風凋白蘋，流年冉冉默傷神。", "强顔未忍乞墦祭，積毁僅逃輸鬼薪。", "半榼浮蛆初試醸，兩螯斫雪又嘗新。", "受恩自度終無報，聊爲清時備隱淪。"]'),
('23915b5d-dda6-4548-b3b6-7b1e6300847b','八月一日微雨驟凉','陸游','宋','宋诗','song-poetry','','[]','流汗沾衣喘不供，孰知有此快哉風。',64,'全唐诗/poet.song.130000.json','["流汗沾衣喘不供，孰知有此快哉風。", "新凉忽覺從天下，殘暑真成掃地空。", "恰轉輕雷過林塢，已吹好雨到簾櫳。", "幽人病愈閑無事，剩賦歌詩樂歲豐。"]'),
('b430bd3d-297a-400f-86e3-0b339ca08b14','秋雨三首  其一','陸游','宋','宋诗','song-poetry','','[]','剡曲高秋一草亭，雨來迨我醉初醒。',64,'全唐诗/poet.song.130000.json','["剡曲高秋一草亭，雨來迨我醉初醒。", "豪吞平野宜閑望，急打虚窗入静聴。", "沙上濕雲號斷雁，籬根衰草綴孤螢。", "老人懶復親燈火，卧看爐香掩素屏。"]'),
('25526d5c-87f5-4618-9713-35d02a2b40f9','秋雨三首  其二','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵勢已窮，凄風苦雨却匆匆。',64,'全唐诗/poet.song.130000.json','["赤日黄塵勢已窮，凄風苦雨却匆匆。", "盛衰黙定見天造，寒暑宻移成歲功。", "柯葉凋零無茂木，羽翰憔悴有覊鴻。", "誰知病客悲秋意，盡在空堦點滴中。"]'),
('516576b0-abaa-4b58-80f3-5fd9e70f53a7','秋雨三首  其三','陸游','宋','宋诗','song-poetry','','[]','冷雨蕭蕭澀不晴，樷篁遮盡小窗明。',64,'全唐诗/poet.song.130000.json','["冷雨蕭蕭澀不晴，樷篁遮盡小窗明。", "故衾獨展成酣寢，新醸初嘗得細傾。", "壁簡積陰添蠧字，床琴生潤咽絃聲。", "此時懷抱真難遣，一首清詩信筆成。"]'),
('e4c3c6b1-adc6-4921-b64e-d542988a2f81','月下獨坐','陸游','宋','宋诗','song-poetry','','[]','髮根蕭爽受微風，徙倚闌干月正中。',64,'全唐诗/poet.song.130000.json','["髮根蕭爽受微風，徙倚闌干月正中。", "天宇了無雲一點，城樓俄報鼓三通。", "庭皋簌簌吹凋葉，江渚翩翩落斷鴻。", "回首人間塵土惡，騎鯨聊駐水精宫。"]'),
('8ac51614-32e7-4699-8734-1db9524fb642','秋日步至湖桑埭西','陸游','宋','宋诗','song-poetry','','[]','伏枕衰方劇，搘笻氣忽增。',48,'全唐诗/poet.song.130000.json','["伏枕衰方劇，搘笻氣忽增。", "細泉鳴暗竇，疏樹映孤燈。", "斷雁寒依渚，强魚健脱罾。", "行纒已無用，却作在家僧。"]'),
('07b2bc6a-7473-4421-bd75-07d51de15d33','秋社二首  其一','陸游','宋','宋诗','song-poetry','','[]','明朝逢社日，鄰曲樂年豐。',48,'全唐诗/poet.song.130000.json','["明朝逢社日，鄰曲樂年豐。", "稻蟹雨中盡，海氛秋後空。", "不須諛土偶，正可倚天公。", "酒滿銀杯綠，相呼一笑中。"]'),
('361e4b18-3a30-435c-a953-ac3134bb9e98','秋社二首  其二','陸游','宋','宋诗','song-poetry','','[]','浦溆漁歌遠，茆茨績火明。',48,'全唐诗/poet.song.130000.json','["浦溆漁歌遠，茆茨績火明。", "新凉迎病起，樂事及秋成。", "社肉分初至，官壺買旋傾。", "殘年得家食，何以報時清。"]'),
('92bd5f1a-33e6-4188-be2c-1d6811fbe835','秋思六首  其一','陸游','宋','宋诗','song-poetry','','[]','南鄭歸來二十霜，背人歲月去堂堂。',64,'全唐诗/poet.song.130000.json','["南鄭歸來二十霜，背人歲月去堂堂。", "破裘不補知寒早，倦枕無憀厭夜長。", "年少若爲評宿士，狂生曾是說高皇。", "慨然此夕江湖夢，猶繞天山古戰塲。"]'),
('5f49a7b7-bde9-4a74-92a4-dd52dfe90914','秋思六首  其二','陸游','宋','宋诗','song-poetry','','[]','一生書劍徧天涯，兩歲秋風喜在家。',64,'全唐诗/poet.song.130000.json','["一生書劍徧天涯，兩歲秋風喜在家。", "爛醉日傾無筭酒，高眠時聴屬私蛙。", "園林夕照明丹柿，籬落初寒蔓碧花。", "便擬挂冠君會否，耳根不復耐喧譁。"]'),
('b88513d4-5cca-48f5-afa3-7d72f019b2a9','秋思六首  其三','陸游','宋','宋诗','song-poetry','','[]','殘暑偏能著此翁，吹襟剩喜得西風。',64,'全唐诗/poet.song.130000.json','["殘暑偏能著此翁，吹襟剩喜得西風。", "露滋小徑蘭苕冷，月射高梁燕戸空。", "衰病呻吟真一洗，醉歌跌宕與誰同。", "從今日日增幽興，水際先丹數葉楓。"]'),
('a026139c-3eb4-457c-a001-4f3df9f5d070','秋思六首  其四','陸游','宋','宋诗','song-poetry','','[]','半年閉戸廢登臨，直自春殘病至今。',64,'全唐诗/poet.song.130000.json','["半年閉戸廢登臨，直自春殘病至今。", "帳外昏燈伴孤夢，簷前寒雨滴愁心。", "中原形勝關河在，列聖憂勤德澤深。", "遥想遺民垂泣處，大梁城闕又秋砧。"]'),
('a81ddaf2-4ac4-4c45-8f4e-4e3a186cee75','秋思六首  其五','陸游','宋','宋诗','song-poetry','','[]','雁陣横空送早寒，白頭病叟住江干。',64,'全唐诗/poet.song.130000.json','["雁陣横空送早寒，白頭病叟住江干。", "風林脱葉山容瘦，霜稲登塲野色寛。", "萬里關河驚契濶，一尊鄰曲話悲歡。", "書生餓死尋常事，那得重彈挂壁冠。"]'),
('252115e7-21a8-4eb5-b92c-3457976658db','秋思六首  其六','陸游','宋','宋诗','song-poetry','','[]','藥畦蔬壟夕陽中，带落冠欹一病翁。',64,'全唐诗/poet.song.130000.json','["藥畦蔬壟夕陽中，带落冠欹一病翁。", "步蹇每妨行樂興，眼昏幾廢讀書功。", "露濃乍警雲巢鶴，風勁先凋玉井桐。", "欲賦悲秋却休去，鬢絲已是滿青銅。"]'),
('7eb7c576-8e8e-4165-a7df-f2bf264ea015','以事至城南書觸目','陸游','宋','宋诗','song-poetry','','[]','十里西風吹帽裙，江城衣杵遠猶聞。',64,'全唐诗/poet.song.130000.json','["十里西風吹帽裙，江城衣杵遠猶聞。", "路如劍閣逢秋雨，山似爐峰鏁暮雲。", "原上老翁眠犢背，籬根小婦牧羊群。", "百錢且就村塲醉，舌本醇醨莫苦分。"]'),
('1f6831eb-db4b-4f81-b18d-014a4805271e','舍西夕望','陸游','宋','宋诗','song-poetry','','[]','茆舍菱陂北，柴門藥圃西。',48,'全唐诗/poet.song.130000.json','["茆舍菱陂北，柴門藥圃西。", "奇雲去人近，澹月傍簷低。", "野迥羊牛下，林昏鳥雀栖。", "郊墟少還往，父子自扶攜。"]'),
('ca547972-11d0-48d3-9d32-18f0b7882aba','題城侍者峴山圗','陸游','宋','宋诗','song-poetry','','[]','漢水沉碑安在哉，千年峴首獨崔嵬。',32,'全唐诗/poet.song.130000.json','["漢水沉碑安在哉，千年峴首獨崔嵬。", "平生不作羊公計，但欲無名死草萊。"]'),
('090900aa-af7e-4bf4-9372-cee459d2c55a','題城侍者剡溪圗','陸游','宋','宋诗','song-poetry','','[]','暮境侵尋兩鬢絲，湖邉自葺小茆茨。',32,'全唐诗/poet.song.130000.json','["暮境侵尋兩鬢絲，湖邉自葺小茆茨。", "從今步步俱回棹，不獨山陰興盡時。"]'),
('e311edd3-e219-4370-81b9-8ecb8c60d314','晚秋農家八首  其一','陸游','宋','宋诗','song-poetry','','[]','老來萬事懶，不獨廢應酬。',48,'全唐诗/poet.song.130000.json','["老來萬事懶，不獨廢應酬。", "門前即湖山，亦復罕出逰。", "吾廬有真樂，一榻眠高秋。", "回看世上事，得喪良悠悠。"]'),
('80be5a92-2f64-4fa6-8f7c-996d3d1b3004','晚秋農家八首  其二','陸游','宋','宋诗','song-poetry','','[]','秋雨無時休，令我雙鬢縞。',48,'全唐诗/poet.song.130000.json','["秋雨無時休，令我雙鬢縞。", "庭荒何由鉏，木落不得掃。", "遣奴入城市，寸步困泥潦。", "菰首幸可烹，芻豢置勿道。"]'),
('9c35033c-8426-44ce-8e79-81b8cae68100','晚秋農家八首  其三','陸游','宋','宋诗','song-poetry','','[]','豢犬使警夜，畜雞用司旦。',48,'全唐诗/poet.song.130000.json','["豢犬使警夜，畜雞用司旦。", "徹警盗所窺，失旦固吾患。", "豈無糠粞費，施報不可緩。", "家居亦爲政，發我中夜嘆。"]'),
('43b45993-ae3c-48b0-88c7-3052ad2b1246','晚秋農家八首  其四','陸游','宋','宋诗','song-poetry','','[]','東鄰稻上塲，勞之以一壺。',48,'全唐诗/poet.song.130000.json','["東鄰稻上塲，勞之以一壺。", "西鄰女受聘，賀之以一襦。", "誠知物寡薄，且用交里閭。", "努力畢農功，租賦勿後輸。"]'),
('54dfe35c-51ae-46ed-8693-ec56840135e4','晚秋農家八首  其五','陸游','宋','宋诗','song-poetry','','[]','我年近七十，與世長相忘。',48,'全唐诗/poet.song.130000.json','["我年近七十，與世長相忘。", "筋力幸可勉，扶衰業耕桑。", "身雜老農間，何能避風霜。", "夜半起飯牛，北斗垂大荒。"]'),
('110ea17e-d4a0-4a6e-bf6b-54bf7d2775b0','晚秋農家八首  其六','陸游','宋','宋诗','song-poetry','','[]','疏溝架略彴，拾瓦疊浮屠。',48,'全唐诗/poet.song.130000.json','["疏溝架略彴，拾瓦疊浮屠。", "既畫菘韭畦，遂營瓜芋區。", "豉香吴鹽白，飽計已有餘。", "捫腹笑自賀，無羊敗吾蔬。"]'),
('5d981971-5305-4799-baae-bb64a7e77787','晚秋農家八首  其七','陸游','宋','宋诗','song-poetry','','[]','苦寒牛亦耕，甚雨雞亦鳴。',48,'全唐诗/poet.song.130000.json','["苦寒牛亦耕，甚雨雞亦鳴。", "物物各有職，怠心其敢萌。", "我老返農圃，學業付後生。", "語兒續膏油，勿輟讀書聲。"]'),
('52337cb4-78ee-4950-894d-cb43a7190761','晚秋農家八首  其八','陸游','宋','宋诗','song-poetry','','[]','吾里賢長者，蓋有萬石風。',48,'全唐诗/poet.song.130000.json','["吾里賢長者，蓋有萬石風。", "少年以利遷，但可哀其窮。", "仁義亦何常，聖賢與人同。", "我言不足取，汝豈忘乃翁。"]'),
('60dd6761-714f-4eda-8db0-3019e0b1b798','湖上小閣','陸游','宋','宋诗','song-poetry','','[]','蒲萄初紫柿初紅，小閣憑闌萬里風。',32,'全唐诗/poet.song.130000.json','["蒲萄初紫柿初紅，小閣憑闌萬里風。", "莫怪年來增酒量，此中能著太虚空。"]'),
('ba06afbc-97ac-44eb-8edc-35b60f0e7b5b','苦雨嘆','陸游','宋','宋诗','song-poetry','','[]','九淵龍公出忘還，瓦溝垂溜聲淙潺。',96,'全唐诗/poet.song.130000.json','["九淵龍公出忘還，瓦溝垂溜聲淙潺。", "茫茫大澤北際海，瀲瀲平湖南浸山。", "吾廬四望路俱斷，蛙黽争雄亂昏旦。", "漏床腐席夜失眠，濕竈生薪朝不爨。", "今年十分喜有秋，豈知青秧出禾頭。", "老夫一飽復繆悠，聴兒讀書寛百憂。"]'),
('9fdc32e5-a4b0-4a18-a73e-f40308f84128','遣懷','陸游','宋','宋诗','song-poetry','','[]','秋風策策冷吹衣，謝病經年晝掩扉。',64,'全唐诗/poet.song.130000.json','["秋風策策冷吹衣，謝病經年晝掩扉。", "絕世本來希獨立，刺天不復計群飛。", "細思萬古名何用，太息九原誰與歸。", "葬近要離非素意，富春灘畔有苔磯。"]'),
('ba6c5857-177e-457c-9fee-5b53cd59bf3b','道石三首  其一','陸游','宋','宋诗','song-poetry','','[]','秋風嫋嫋雨斑斑，身隱幽窗筆硯間。',32,'全唐诗/poet.song.130000.json','["秋風嫋嫋雨斑斑，身隱幽窗筆硯間。", "小試壺公縮地術，數峰閑對道州山。"]'),
('88285ec3-d6e9-470b-8e90-fa401379f294','道石三首  其二','陸游','宋','宋诗','song-poetry','','[]','林慮靈壁俱尤物，散落人間不復還。',32,'全唐诗/poet.song.130000.json','["林慮靈壁俱尤物，散落人間不復還。", "投老東歸風味在，舂陵小岫伴身閑。"]'),
('9ee66d9d-f817-4c47-a063-56c1233ccde8','道石三首  其三','陸游','宋','宋诗','song-poetry','','[]','誤因禄米棄蓴鱸，一落塵埃底事無。',32,'全唐诗/poet.song.130000.json','["誤因禄米棄蓴鱸，一落塵埃底事無。", "布韈青鞵雖興盡，此峰聊當卧逰圗。"]'),
('9f7de15e-25ed-480c-be26-288ec02ab44c','蘭亭','陸游','宋','宋诗','song-poetry','','[]','蘭亭絕勝擅吾州，病起身閑得縱逰。',64,'全唐诗/poet.song.130000.json','["蘭亭絕勝擅吾州，病起身閑得縱逰。", "曲水流觴千古勝，小山樷桂一年秋。", "酒酣起舞風前袖，興盡回橈月下舟。", "江左諸賢嗟未遠，感今懷昔使人愁。"]'),
('44da4968-64fc-4ab8-892a-7a90b1fa51fc','小葺村居','陸游','宋','宋诗','song-poetry','','[]','昔我作屋時，趣欲庇風雨。',120,'全唐诗/poet.song.130000.json','["昔我作屋時，趣欲庇風雨。", "茆茨寒自刈，條枚細相拄。", "庫濕生蚍𧉈，得暖森翅羽。", "摧撓自棟梁，朽敗連柱礎。", "鄰父爲我言，努力謀安處。", "土堅瓦可陶，步近木易取。", "豈知七十翁，沉痼久未愈。", "身世如浮漚，家舍真逆旅。", "一床居易足，十歲敢自許。", "且當復其初，浩歌卧環堵。"]'),
('178fbb19-8e66-496f-8013-90c3b4678c9e','書陶靖節桃源詩後','陸游','宋','宋诗','song-poetry','','[]','寄奴談笑取秦燕，愚智皆知晉鼎遷。',32,'全唐诗/poet.song.130000.json','["寄奴談笑取秦燕，愚智皆知晉鼎遷。", "獨爲桃源人作傳，固應不仕義熙年。"]'),
('33fcad4f-1edb-4218-9836-e4771c98dead','有叟','陸游','宋','宋诗','song-poetry','','[]','有叟鏡湖邉，茆茨八九椽。',48,'全唐诗/poet.song.130000.json','["有叟鏡湖邉，茆茨八九椽。", "憑闌秋萬里，閉戸醉經年。", "身外浮名小，胸中浩氣全。", "此生吾自判，造物恐無權。"]'),
('7680b6f8-c812-4ef3-b4ae-c4547086c619','不寐','陸游','宋','宋诗','song-poetry','','[]','老眼睡眠少，林居烟雨昏。',48,'全唐诗/poet.song.130000.json','["老眼睡眠少，林居烟雨昏。", "百年歸老死，萬事付乾坤。", "熠熠螢穿幔，錚錚鐵過門。", "欲明聞漉稻，浩嘆閔黎元。"]'),
('2fc8efc9-ff2b-473c-87bc-8d8edb8f5fc8','遥夜','陸游','宋','宋诗','song-poetry','','[]','遥夜凛高秋，蕭條念褐裘。',48,'全唐诗/poet.song.130000.json','["遥夜凛高秋，蕭條念褐裘。", "烟江新雁下，竹塢暗螢流。", "舊友嗟誰在，初心恐不酬。", "一尊桑落酒，聊得洗吾愁。"]'),
('65987d7f-1997-46bf-b3a7-d330e1f78ea7','秋晚思梁益舊逰三首  其一','陸游','宋','宋诗','song-poetry','','[]','幅巾笻杖立籬門，秋意蕭條欲斷魂。',32,'全唐诗/poet.song.130000.json','["幅巾笻杖立籬門，秋意蕭條欲斷魂。", "恰似嘉陵江上路，冷雲微雨濕黄昏。"]'),
('4cbd4bcf-e724-486b-ac1f-130369c76048','秋晚思梁益舊逰三首  其二','陸游','宋','宋诗','song-poetry','','[]','憶昔西行萬里餘，長亭夜夜夢歸吴。',32,'全唐诗/poet.song.130000.json','["憶昔西行萬里餘，長亭夜夜夢歸吴。", "如今曆盡風波惡，飛棧連雲是坦途。"]'),
('f8debb91-3f0b-4486-9b57-f4510a258289','秋晚思梁益舊逰三首  其三','陸游','宋','宋诗','song-poetry','','[]','滄波極目江鄉恨，衰草連天塞路愁。',32,'全唐诗/poet.song.130000.json','["滄波極目江鄉恨，衰草連天塞路愁。", "三十年間行萬里，不論南北怯登樓。"]'),
('faee1afc-c346-45fb-a7a1-9ba8cc720be7','紹熙辛亥九月四日雨後白龍挂西北方復雨三日作長句記之','陸游','宋','宋诗','song-poetry','','[]','長空黮闇如欲夜，白龍騰拏見雲罅。',128,'全唐诗/poet.song.130000.json','["長空黮闇如欲夜，白龍騰拏見雲罅。", "鱗間出火光照江，尾卷風霆雨如射。", "老人百歲見未曾，兒童閉門伏床下。", "髮毛慘凛誰復支，性命么微不禁嚇。", "登塲已嘆禾生耳，出戸仍愁泥沒胯。", "皇天生民豈不愛，龍亦何心敗吾稼。", "父老相看出無策，攬涕頓顙號枌社。", "移床避漏我亦忙，秉燭題詩寄悲吒。"]'),
('5704523b-9096-4269-85e2-01bfa6d853af','蔬圃','陸游','宋','宋诗','song-poetry','','[]','蔬圃依山脚，漁扉竝水涯。',48,'全唐诗/poet.song.130000.json','["蔬圃依山脚，漁扉竝水涯。", "卧枝開野菊，殘枿出秋茶。", "病骨知天色，羈懷感物華。", "餘年有幾許，且灌邵平瓜。"]'),
('41c927f1-e87e-4ef4-8ac0-5bedfcbccdeb','農家','陸游','宋','宋诗','song-poetry','','[]','南畝勤菑穫，西城謹蓋藏。',48,'全唐诗/poet.song.130000.json','["南畝勤菑穫，西城謹蓋藏。", "種蕎乘霽日，斫荻待微霜。", "谿碓新舂白，山厨野簌香。", "何須北窗卧，始得傲羲皇。"]'),
('7e0ee776-253f-4cc6-8634-c42c6f442c8e','自喜','陸游','宋','宋诗','song-poetry','','[]','半生羈宦走人間，醉裏心寛夢裏閑。',32,'全唐诗/poet.song.130000.json','["半生羈宦走人間，醉裏心寛夢裏閑。", "自喜如今無一事，讀書纔倦即逰山。"]'),
('89391d8f-b942-4b1a-81bc-929b7db50b7e','重九後風雨不止遂作小寒三首  其一','陸游','宋','宋诗','song-poetry','','[]','病軀剩喜即新秋，殘暑無端抵死留。',32,'全唐诗/poet.song.130000.json','["病軀剩喜即新秋，殘暑無端抵死留。", "風雨掃除雖一快，凋年揺落已堪愁。"]'),
('80448549-513b-4e4e-9fac-4f70ba7388ff','重九後風雨不止遂作小寒三首  其二','陸游','宋','宋诗','song-poetry','','[]','菊枝欹倒不成樷，井上梧桐葉半空。',32,'全唐诗/poet.song.130000.json','["菊枝欹倒不成樷，井上梧桐葉半空。", "射虎南山無復夢，雨蓑烟艇伴漁翁。"]'),
('8614a5aa-c51a-4a1b-97ae-88753fc3fb63','重九後風雨不止遂作小寒三首  其三','陸游','宋','宋诗','song-poetry','','[]','夜長稚子添書課，霜近衰翁憶醉鄉。',32,'全唐诗/poet.song.130000.json','["夜長稚子添書課，霜近衰翁憶醉鄉。", "儘道吴中時節晚，菊花也有一枝黄。"]'),
('70002c39-4818-4c3d-a9c6-6b40c9baa53f','城南上原陳翁以賣花爲業得錢悉供酒資又不能獨飲逢人輙强與共醉辛亥九月十二日偶過其門訪之敗屋一間妻子饑寒而此翁已大醉矣殆隱者也爲賦一詩','陸游','宋','宋诗','song-poetry','','[]','君不見會稽城南賣花翁，以花爲糧如蜜蠭。',115,'全唐诗/poet.song.130000.json','["君不見會稽城南賣花翁，以花爲糧如蜜蠭。", "朝賣一株紫，暮賣一枝紅。", "屋破見青天，盎中米常空。", "賣花得錢送酒家，取酒盡時還賣花。", "春春花開豈有極，日日我醉終無涯。", "亦不知天子殿前宣白麻，亦不知相公門前築堤沙。", "客來與語不能答，但見醉髮覆面垂髿髿。"]'),
('775def02-b7bd-4f07-81a7-47c3331ef755','甜羮之法以菘菜山藥芋萊菔雜爲之不施醯醬山庖珍烹也戲作一絕','陸游','宋','宋诗','song-poetry','','[]','老住湖邉一把茆，時沽村酒具山殽。',32,'全唐诗/poet.song.130000.json','["老住湖邉一把茆，時沽村酒具山殽。", "年來傳得甜羮法，更爲吴酸作觧嘲。"]'),
('b9e9b6b7-60ec-42b3-8689-5e2e2b56b773','暮秋書事','陸游','宋','宋诗','song-poetry','','[]','暮秋風雨卷茆茨，砧杵聲中過雁悲。',64,'全唐诗/poet.song.130000.json','["暮秋風雨卷茆茨，砧杵聲中過雁悲。", "楓葉欲丹先惨澹，菊樷半倒不支持。", "旗亭人熟容賖酒，野寺僧閑得對棋。", "莫怪苦尋林下事，駭機滿地只心知。"]'),
('390ad299-11a2-4507-83bc-ce8a9b1f76c8','早自偏門入城晚出南堰門以歸','陸游','宋','宋诗','song-poetry','','[]','早從偏門入，暮從南堰歸。',96,'全唐诗/poet.song.130000.json','["早從偏門入，暮從南堰歸。", "鮑郎山前路，空翠浮烟霏。", "秋令忽已深，病骨頻添衣。", "向來慕功名，常恐斯心違。", "乃今知其難，崦嵫迫殘暉。", "伯鸞與幼安，尚友或庶幾。", "到家亦既夕，青燈耿窗扉。", "且復取書讀，父子窮相依。"]'),
('8c72280c-f61f-4884-b10a-004ebf72942b','初寒','陸游','宋','宋诗','song-poetry','','[]','蚊蝇掃迹葉飛初，剩喜幽窗讀我書。',64,'全唐诗/poet.song.130000.json','["蚊蝇掃迹葉飛初，剩喜幽窗讀我書。", "牆角短檠真耐久，手中團扇又成踈。", "百年作夢行休去，九月無衣亦晏如。", "獨恨故人消息斷，寒江誰與倩雙魚。"]'),
('b5207e64-333a-43f8-8b1d-d0eed3543023','小舟自紅橋之南過吉澤歸三山二首  其一','陸游','宋','宋诗','song-poetry','','[]','霏霏寒雨數家村，雞犬蕭然晝閉門。',32,'全唐诗/poet.song.130000.json','["霏霏寒雨數家村，雞犬蕭然晝閉門。", "它日路迷君勿恨，人間隨處有桃源。"]'),
('9dd84d37-32d2-493f-b9bc-b3ef3a0bdd7a','小舟自紅橋之南過吉澤歸三山二首  其二','陸游','宋','宋诗','song-poetry','','[]','六月芙蕖正盛時，畫船長記醉題詩。',32,'全唐诗/poet.song.130000.json','["六月芙蕖正盛時，畫船長記醉題詩。", "世間好景元無盡，霜落荷枯又一奇。"]'),
('50f13508-d272-4f45-8035-49710f5dd2e6','得猫於近村以雪兒名之戲爲作詩','陸游','宋','宋诗','song-poetry','','[]','似虎能緣木，如駒不伏轅。',48,'全唐诗/poet.song.130000.json','["似虎能緣木，如駒不伏轅。", "但知空鼠穴，無意爲魚飱。", "薄荷時時醉，氍毹夜夜温。", "前生舊童子，伴我老山村。"]'),
('2ebf4576-46d0-4fc7-8c63-cc5a900d93cc','晝睡','陸游','宋','宋诗','song-poetry','','[]','眼昏妨讀書，不睡復何如。',48,'全唐诗/poet.song.130000.json','["眼昏妨讀書，不睡復何如。", "擁被新寒裏，伸腰午飯餘。", "斷香縈倦枕，踈雨滴前除。", "未竟華胥樂，茶甌莫喚渠。"]'),
('c4de2c06-695d-49c5-845e-d0bf4631e414','戲詠閑適','陸游','宋','宋诗','song-poetry','','[]','暮秋風雨暗江津，不下書堂已過旬。',64,'全唐诗/poet.song.130000.json','["暮秋風雨暗江津，不下書堂已過旬。", "鸚鵡籠寒晨自訴，貍奴氊暖夜相親。", "典衣旋買修琴料，叩戸時聞請藥人。", "說與鄉鄰當賀我，死前長作自由身。"]'),
('b9acbd0b-6284-4de8-bf3c-650452b30043','寓嘆二首  其一','陸游','宋','宋诗','song-poetry','','[]','荷戈常記壯逰時，齒豁頭童不自知。',64,'全唐诗/poet.song.130000.json','["荷戈常記壯逰時，齒豁頭童不自知。", "已分功名非力致，更悲文字與年衰。", "端居漸覺從人懶，熟睡偏於聴雨宜。", "自斷歸休君勿怪，一杯韲糁敵瓊糜。"]'),
('d25bb438-2c79-4f4b-be50-8de54323d424','寓嘆二首  其二','陸游','宋','宋诗','song-poetry','','[]','醉撫酒壺憐矲矮，卧看香岫愛嶙峋。',64,'全唐诗/poet.song.130000.json','["醉撫酒壺憐矲矮，卧看香岫愛嶙峋。", "舊時京洛塵埃面，今作江湖風月民。", "幻世界中均起滅，太虚空裏孰寃親。", "可齋入定論千劫，說與天魔任惱人。"]'),
('c26d8e76-8e94-4f80-88c9-3517bd8e5fbd','獨夜','陸游','宋','宋诗','song-poetry','','[]','獨夜迢迢掩素屏，病懷羈思共竛竮。',64,'全唐诗/poet.song.130000.json','["獨夜迢迢掩素屏，病懷羈思共竛竮。", "房櫳十月寒初重，風雨三更酒半醒。", "繁杵有聲時斷續，殘缸無焰尚青熒。", "怳然喚起西征夢，身卧金牛古驛亭。"]'),
('ee5314dc-808a-43f4-9e42-d3278f7e5be2','記九月二十六夜夢','陸游','宋','宋诗','song-poetry','','[]','海山萬峰鬱参差，宫殿揷水蟠蛟螭。',128,'全唐诗/poet.song.130000.json','["海山萬峰鬱参差，宫殿揷水蟠蛟螭。", "碧桃千樹自開落，飛橋架空來者誰。", "桐枝高聳棲丹鳳，蓮葉半展巢金龜。", "和風微度寶筝響，永日徐轉簾陰移。", "西廂恍記舊逰處，素壁好在尋春詩。", "當年意氣不少譲，跌宕醉墨紛淋漓。", "宿酲未觧字猶濕，人間歲月浩莫推。", "嘆驚撫几忽夢斷，海濶天遠難重期。"]'),
('8954feaf-9564-45a1-a40b-cc57363f7385','夢海山壁間詩不能盡記以其意追補四首  其一','陸游','宋','宋诗','song-poetry','','[]','碧海無風鏡面平，潮來忽作雪山傾。',32,'全唐诗/poet.song.130000.json','["碧海無風鏡面平，潮來忽作雪山傾。", "金橋化出三千丈，閑把松枝引鶴行。"]'),
('668b1463-7507-4bc6-b27c-7ad2d5ebcc99','夢海山壁間詩不能盡記以其意追補四首  其二','陸游','宋','宋诗','song-poetry','','[]','海上乘雲滿袖風，醉捫星斗躡虚空。',32,'全唐诗/poet.song.130000.json','["海上乘雲滿袖風，醉捫星斗躡虚空。", "要知壯觀非塵世，半夜鯨波浴日紅。"]'),
('d972a704-3cea-4694-9d6d-635dfba6b590','夢海山壁間詩不能盡記以其意追補四首  其三','陸游','宋','宋诗','song-poetry','','[]','一劍能清萬里塵，讒波深處偶全身。',32,'全唐诗/poet.song.130000.json','["一劍能清萬里塵，讒波深處偶全身。", "那知九轉丹成後，却插金貂侍帝宸。"]'),
('33087c22-e520-4780-960d-f2483ce46271','夢海山壁間詩不能盡記以其意追補四首  其四','陸游','宋','宋诗','song-poetry','','[]','春殘枕籍落花眠，正是周家定鼎年。',32,'全唐诗/poet.song.130000.json','["春殘枕籍落花眠，正是周家定鼎年。", "睡起不知秦漢事，一尊閑醉華陽川。"]'),
('0f055baf-02d6-49c2-8f5a-5789489d725d','當食嘆','陸游','宋','宋诗','song-poetry','','[]','黄𪁟舉網收，錦雉带箭墮。',84,'全唐诗/poet.song.130000.json','["黄𪁟舉網收，錦雉带箭墮。", "藉藻頳鯉鮮，發奩蒼兔卧。", "吾儕亦何心，甘味樂死禍。", "貪夫五鼎烹，志士首陽餓。", "請言觀其終，孰爲當吊賀。", "八月黍可炊，五月麥可磨。", "一飽端有餘，努力事舂簸。"]'),
('0279eefc-c7a9-4aa8-bd99-3d8f57f1bdf6','睡鄉','陸游','宋','宋诗','song-poetry','','[]','有酒君勿啜，入腸作戈矛。',96,'全唐诗/poet.song.130000.json','["有酒君勿啜，入腸作戈矛。", "有書君勿觀，到眼生君愁。", "不如睡鄉去，萬事風馬牛。", "郊墟無來客，風雨送暮秋。", "苔甃蟲唧唧，霜林葉颼颼。", "是時一枕睡，不博萬戸侯。", "斗帳裁青氊，重衾擁黄紬。", "蕐山希夷翁，千載可與逰。"]'),
('09a98808-77e4-4c99-8914-e6a331c94aaf','晨興','陸游','宋','宋诗','song-poetry','','[]','未旦雞三號，將旦鵝群鳴。',96,'全唐诗/poet.song.130000.json','["未旦雞三號，將旦鵝群鳴。", "湖陂地曠快，頗樂聞此聲。", "回首宦遊日，鈴索攪五更。", "未言簿書勞，讒謗隨日生。", "一饑百憂散，灑然懷抱清。", "雨後初得薺，晨庖有珍烹。", "豈不念加糁，侈汰恐易萌。", "且當讀古書，至味敵太羮。"]'),
('0c4be461-bdf5-442e-9dc0-5f4b902bc4a9','初冬從父老飲村酒有作','陸游','宋','宋诗','song-poetry','','[]','父老招呼共一觴，歲猶中熟有餘糧。',64,'全唐诗/poet.song.130000.json','["父老招呼共一觴，歲猶中熟有餘糧。", "蕎花漫漫渾如雪，豆莢離離未著霜。", "山路獵歸收兔網，水濵農隙架魚梁。", "醉看四海何曾窄，且復相扶醉夕陽。"]'),
('f96acc62-4a02-4d31-9148-4541e93b5750','懷南鄭舊逰','陸游','宋','宋诗','song-poetry','','[]','南山南畔昔從戎，賔主相期意氣中。',64,'全唐诗/poet.song.130000.json','["南山南畔昔從戎，賔主相期意氣中。", "渇驥奔時書滿壁，餓鴟鳴處箭凌風。", "千艘粟漕魚關北，一點烽傳駱谷東。", "惆悵壯逰成昨夢，戴公亭下伴漁翁。"]'),
('864ec033-f2fa-484e-a5db-2ba77c8c41d9','冬夜讀書','陸游','宋','宋诗','song-poetry','','[]','霜雪紛紛滿鬢毛，凋年懷抱獨蕭騷。',64,'全唐诗/poet.song.130000.json','["霜雪紛紛滿鬢毛，凋年懷抱獨蕭騷。", "房櫳夜悄孤燈暗，原野風悲萬木號。", "病卧極知趨死近，老勤猶欲與書鏖。", "小兒可付巾箱業，未用逢人嘆不遭。"]'),
('78e34aef-2d1f-4c43-ab0e-bbde0298786b','余爲成都帥司參議成將軍漢卿爲成都路兵鈐相從無虚日余被召出蜀漢卿坐法謫居於涪既得自便因卜築爲涪人今年廣漢僧祖成來山陰乃言嘗至永嘉樂清縣柳市之廣福寺有黄先生寓寺中煉丹及見則漢卿也余聞之感嘆不已爲賦此詩','陸游','宋','宋诗','song-poetry','','[]','將軍胸中備文武，鐡馬黄旗玉關路。',128,'全唐诗/poet.song.130000.json','["將軍胸中備文武，鐡馬黄旗玉關路。", "羌胡可滅心自知，富貴有命才可與。", "奪官置之三峽中，空山猿鳥同朝暮。", "道逢奇士握手談，明日家人不知處。", "平生心事一丹竈，萬里生涯兩芒屨。", "東嘉古寺卧高秋，時有巢仙來叩戸。", "山中豈識故將軍，但怪英姿凛不群。", "電眼蝟鬚長八尺，論丹說劍氣凌雲。"]'),
('0a2a4cb9-a733-415e-93e6-03f845abaf4d','雜題六首  其一','陸游','宋','宋诗','song-poetry','','[]','松肪釀酒石根醉，槲葉作衣雲外行。',32,'全唐诗/poet.song.130000.json','["松肪釀酒石根醉，槲葉作衣雲外行。", "指點人間一長嘆，秋風又到洛陽城。"]'),
('bb06add4-1822-4c79-9338-bd724a7321ac','雜題六首  其二','陸游','宋','宋诗','song-poetry','','[]','山家貧甚亦支撐，時撫桐孫一再行。',32,'全唐诗/poet.song.130000.json','["山家貧甚亦支撐，時撫桐孫一再行。", "朝甑米空烹芋粥，夜缸油盡點松明。"]'),
('57c0d928-3a7d-4b34-9401-88a0ccf279e3','雜題六首  其三','陸游','宋','宋诗','song-poetry','','[]','羊裘老人只念歸，安用星辰動紫微。',32,'全唐诗/poet.song.130000.json','["羊裘老人只念歸，安用星辰動紫微。", "洛陽城中市兒眼，情知不識釣魚磯。"]'),
('d3dcd4c5-4879-422f-803f-5d50e50e81d0','雜題六首  其四','陸游','宋','宋诗','song-poetry','','[]','黍醅新壓野雞肥，茆店酣歌送落暉。',32,'全唐诗/poet.song.130000.json','["黍醅新壓野雞肥，茆店酣歌送落暉。", "人道山僧最無事，憐渠猶趁暮鐘歸。"]'),
('cd717bbc-7eef-46af-94d9-b89a23e7117b','雜題六首  其五','陸游','宋','宋诗','song-poetry','','[]','釣魚吹笛本閑身，正坐微官白髮新。',32,'全唐诗/poet.song.130000.json','["釣魚吹笛本閑身，正坐微官白髮新。", "著屐此生猶幾緉，可令復踏九衢塵。"]'),
('154defb6-ed58-4a5f-a447-8d57e7e2b590','雜題六首  其六','陸游','宋','宋诗','song-poetry','','[]','山光染黛朝如濕，川氣鎔銀暮不收。',32,'全唐诗/poet.song.130000.json','["山光染黛朝如濕，川氣鎔銀暮不收。", "詩料滿前誰領略，時時來倚水邉樓。"]'),
('094b099d-7e2d-4399-9579-dafbf03895f7','思蜀四首  其一','陸游','宋','宋诗','song-poetry','','[]','思蜀寸心折，歸吴雙鬢衰。',48,'全唐诗/poet.song.130000.json','["思蜀寸心折，歸吴雙鬢衰。", "今年脱虎口，昨夜夢蟆頤。", "死隔平時友，愁吟别後詩。", "江山應好在，誰記踏青期。"]'),
('918e4d74-7b20-4cf9-8d71-d61300352d11','思蜀四首  其二','陸游','宋','宋诗','song-poetry','','[]','一作劍關客，閑逰將十年。',48,'全唐诗/poet.song.130000.json','["一作劍關客，閑逰將十年。", "不嫌狂駭俗，自許醉知天。", "瑞草溪橋路，青衣野廟壖。", "霜天獵歸處，萬里入横鞭。"]'),
('ec657736-5d32-460f-851f-52436582a462','思蜀四首  其三','陸游','宋','宋诗','song-poetry','','[]','來從雲棧北，行度雪山西。',48,'全唐诗/poet.song.130000.json','["來從雲棧北，行度雪山西。", "故事談金馬，遺蹤訪石犀。", "閑情淡於水，豪飲醉如泥。", "壊壁塵封遍，何人拂舊題。"]'),
('497f27ab-535e-4dc0-9edc-e7ce53afaef2','思蜀四首  其四','陸游','宋','宋诗','song-poetry','','[]','玉食峨嵋栮，金韲丙穴魚。',48,'全唐诗/poet.song.130000.json','["玉食峨嵋栮，金韲丙穴魚。", "常思晚秋醉，未與故人疏。", "白髮當歸隱，青山可結廬。", "梅花消息動，悵望雪消初。"]'),
('5f5eedda-ba38-4c87-a81e-5a1e81ac6a1d','散吏','陸游','宋','宋诗','song-poetry','','[]','拜賜明時散吏名，頭銜字字敵冰清。',64,'全唐诗/poet.song.130000.json','["拜賜明時散吏名，頭銜字字敵冰清。", "讀書有味聊忘老，賦祿無多亦代耕。", "笠澤蓴鱸秋向晚，緱山笙鶴月微明。", "人間樂事今真得，莫恨摧頽白髮生。"]'),
('168f13d4-9f50-4f80-9578-8031043085d8','題剡溪瑩上人梅花小軸','陸游','宋','宋诗','song-poetry','','[]','孤舟清曉下溪灘，爲訪梅花不怕寒。',32,'全唐诗/poet.song.130000.json','["孤舟清曉下溪灘，爲訪梅花不怕寒。", "忽有一枝横竹外，醉中推起短篷看。"]'),
('cfb1f3e5-3dbb-4428-b61c-51129a1e7227','夜夢逰驪山','陸游','宋','宋诗','song-poetry','','[]','秦楚相望萬里天，豈知今夕宿温泉。',32,'全唐诗/poet.song.130000.json','["秦楚相望萬里天，豈知今夕宿温泉。", "穿雲潄月無窮恨，依舊潺湲古縣前。"]'),
('df57739a-768d-423b-9b6d-e75b3daadcdc','枕上','陸游','宋','宋诗','song-poetry','','[]','簷角查查鵲語輕，窗櫺澹澹日痕生。',32,'全唐诗/poet.song.130000.json','["簷角查查鵲語輕，窗櫺澹澹日痕生。", "清愁不逐爐香散，旋啜寒韲解宿酲。"]'),
('e2ae59d5-5093-47df-86a9-e6789dbb058c','五更讀書示子','陸游','宋','宋诗','song-poetry','','[]','近村遠村雞續鳴，大星已高天未明。',96,'全唐诗/poet.song.130000.json','["近村遠村雞續鳴，大星已高天未明。", "床頭瓦檠燈煜爚，老夫凍坐書縱横。", "暮年於書更多味，眼底明明見莘渭。", "但令病骨尚枝梧，半盞殘膏未爲費。", "吾兒雖戅素業存，頗能伴翁飽菜根。", "萬鍾一品不足論，時來出手蘓元元。"]'),
('e85e633b-8958-40a3-9e74-6dc2e2554028','夜坐','陸游','宋','宋诗','song-poetry','','[]','天公似欲假餘齡，鍼石年來幸小停。',64,'全唐诗/poet.song.130000.json','["天公似欲假餘齡，鍼石年來幸小停。", "微火暖爐娱獨夜，斷雲吐月縞中庭。", "眼前樂事寒醅綠，身後虚名蠧簡青。", "賴有古人同此志，傍觀不用嘆伶仃。"]'),
('d8758a3d-465e-4787-99b7-9d3025bf195c','卧龍','陸游','宋','宋诗','song-poetry','','[]','危磴盤紆上翠微，倚天樓觀碧参差。',64,'全唐诗/poet.song.130000.json','["危磴盤紆上翠微，倚天樓觀碧参差。", "雨來海氣先横騖，風惡松柯盡倒垂。", "孤鶻歸巢翅翎重，斷鴻覔伴語聲悲。", "人間萬事難禁老，醉撫闌干欲暮時。"]'),
('8108fa4f-d34b-4e61-939b-8d27d5c44b72','野步晚歸','陸游','宋','宋诗','song-poetry','','[]','江村十日喜霜晴，草死泥乾拄杖輕。',64,'全唐诗/poet.song.130000.json','["江村十日喜霜晴，草死泥乾拄杖輕。", "溝港淺來無鷺下，郊原暖處有牛耕。", "奔馳久厭兒童戲，淪落偏知世俗情。", "欲向書窗了殘課，歸來猶占夕陽明。"]'),
('7069ac89-2385-4f99-9f74-ad4529d14278','並山東南閑步至野人吳氏居乃歸','陸游','宋','宋诗','song-poetry','','[]','信步閑行遍四鄰，擁籬老稚看綸巾。',64,'全唐诗/poet.song.130000.json','["信步閑行遍四鄰，擁籬老稚看綸巾。", "人隨世換朋儕少，志與年衰感慨頻。", "梅送冷香横雪岸，雁翻孤影下烟津。", "豐年何地醻君賜，剩向旗亭作醉人。"]'),
('96fca4c6-e6c8-4967-b1f3-01fa7db1037a','晝睡','陸游','宋','宋诗','song-poetry','','[]','我年垂七十，齒髮日變遷。',72,'全唐诗/poet.song.130000.json','["我年垂七十，齒髮日變遷。", "初無金丹術，何以追飛仙。", "惟有一高枕，可以餞餘年。", "蕭蕭敗榻上，鼻鼾心了然。", "靜如豹隱霧，湛若珠藏淵。", "寄語少年輩，未宜嘲孝先。"]'),
('4406c47d-8f7a-4d6f-9543-2b6e05cf2082','連日有雪意戲書','陸游','宋','宋诗','song-poetry','','[]','壯歲羈遊半九州，即今憔悴老菟裘。',64,'全唐诗/poet.song.130000.json','["壯歲羈遊半九州，即今憔悴老菟裘。", "狂心那復繳鴻鵠，世事己如風馬牛。", "雪作未成增慘澹，葉飛欲盡更颼飀。", "聊將袖裏平戎事，判斷干巖萬壑秋。"]'),
('e0ab7381-7cf9-4425-8e7a-e2b80cceeccd','兩蜀故人寄余閬中左緜題名石刻來皆二十餘年矣悵然有感','陸游','宋','宋诗','song-poetry','','[]','憶過西州樂飲時，百車載酒萬花圍。',64,'全唐诗/poet.song.130000.json','["憶過西州樂飲時，百車載酒萬花圍。", "只言身外皆餘事，豈信人間有駭機。", "雪鬢巳成新夢境，緇塵空化舊征衣。", "早知一笑難如此，剩判年光醉不歸。"]'),
('7764e890-bb1b-4417-b771-4516d6871d0e','歲晚','陸游','宋','宋诗','song-poetry','','[]','歲晚霜風正怒號，荒村敗屋擁藜蒿。',64,'全唐诗/poet.song.130000.json','["歲晚霜風正怒號，荒村敗屋擁藜蒿。", "窮猶可勉聖賢事，老豈遽忘鉛槧勞。", "從宦雖如棋己决，治經竊比繭初繅。", "閉門養氣淵源在，未敢摧傷學楚騷。"]'),
('b6515082-29b6-4de5-a1bc-517eb8624e8e','夢斷','陸游','宋','宋诗','song-poetry','','[]','夢斷燈殘聞雁聲，攬衣起坐待天明。',64,'全唐诗/poet.song.130000.json','["夢斷燈殘聞雁聲，攬衣起坐待天明。", "街頭濁酒不堪醉，窗外疏梅空復情。", "人欲見擠真砭石，身寧輕用作投瓊。", "南湖可引春疇美，只合躬耕畢此生。"]'),
('5fa39d95-2b91-4959-a5e7-ce096bfd70e5','雨聲','陸游','宋','宋诗','song-poetry','','[]','雨聲點滴朝復暮，中有詩人絕塵句。',128,'全唐诗/poet.song.130000.json','["雨聲點滴朝復暮，中有詩人絕塵句。", "雲門咸池渺千古，斷譜遺音此其緒。", "雨聲點滴夜不休，中有羈臣去國愁。", "九疑聨翩湘水秋，忠誠內激涕自流。", "我今衰病百無念，卧對青燈吐殘焰。", "支床納息効寒龜，傍枕長吟笑孤劍。", "雨聲不斷睡愈美，窗白鴉啼攬衣起。", "呼兒燒兔傾濁醪，又倚胡床雨聲裏。"]'),
('90722c91-bc23-4b1b-8def-df0a8c2ebf42','農家','陸游','宋','宋诗','song-poetry','','[]','低垣矮屋俯江流，渾舍相娛到白頭。',64,'全唐诗/poet.song.130000.json','["低垣矮屋俯江流，渾舍相娛到白頭。", "累世不知名宦樂，百年那識别離愁。", "飯餘常貯新陳穀，農隙閑眠子母牛。", "聞道少年俱孝謹，未應家法愧恬侯。"]'),
('93856a15-fc99-4cca-ab38-2ff69a9dab41','夜行湖上','陸游','宋','宋诗','song-poetry','','[]','月痕澹欲無，斗柄低半没。',72,'全唐诗/poet.song.130000.json','["月痕澹欲無，斗柄低半没。", "荒陂雁飛鳴，草屋牛卧齕。", "我行湖邊路，霜冷刮病骨。", "斷隄沙水濕，屨滑常恐蹷。", "殘年垂七十，野處猶短褐。", "窮死士所有，權門不可謁。"]'),
('94496219-dab7-4689-96d5-60e1e9a21d42','冬夜讀書忽聞雞唱','陸游','宋','宋诗','song-poetry','','[]','齷齪常談笑老生，丈夫失意合躬耕。',64,'全唐诗/poet.song.130000.json','["齷齪常談笑老生，丈夫失意合躬耕。", "天涯懷友月千里，燈下讀書雞一鳴。", "事去大床空獨卧，時來豎子或成名。", "春蕪何限英雄骨，白髮蕭蕭未用驚。"]'),
('0e76a95c-82ed-4d98-aa69-4b738f511de7','梅花絕句十首  其一','陸游','宋','宋诗','song-poetry','','[]','凜凜冰霜晨，皎皎風月夜。',24,'全唐诗/poet.song.130000.json','["凜凜冰霜晨，皎皎風月夜。", "南山有飛仙，來結尋梅社。"]'),
('2dd0e294-1dbc-4b65-92e1-81ce050590a6','梅花絕句十首  其二','陸游','宋','宋诗','song-poetry','','[]','憶昔西戍日，夜宿僊人原。',24,'全唐诗/poet.song.130000.json','["憶昔西戍日，夜宿僊人原。", "風吹野梅香，夢繞江南村。"]'),
('2274be04-5a6c-4c85-a837-9de2dbaa1e19','梅花絕句十首  其三','陸游','宋','宋诗','song-poetry','','[]','錦城梅花海，十里香不斷。',24,'全唐诗/poet.song.130000.json','["錦城梅花海，十里香不斷。", "醉帽插花歸，銀鞍萬人看。"]'),
('03eb83d2-634e-464d-bad3-9c483ffaa0a8','梅花絕句十首  其四','陸游','宋','宋诗','song-poetry','','[]','低空銀一鈎，糝野玉三尺。',24,'全唐诗/poet.song.130000.json','["低空銀一鈎，糝野玉三尺。", "愁絕水邊花，無人問消息。"]'),
('b0e612c5-430f-40e4-ace0-8e2d40440e78','梅花絕句十首  其五','陸游','宋','宋诗','song-poetry','','[]','蘭荃古所貴，梅乃晚見稱。',24,'全唐诗/poet.song.130000.json','["蘭荃古所貴，梅乃晚見稱。", "盛衰各有時，類非人力能。"]'),
('f265f920-e0c1-4899-bb86-c035eff24c16','梅花絕句十首  其六','陸游','宋','宋诗','song-poetry','','[]','子欲作梅詩，當造幽絕境。',24,'全唐诗/poet.song.130000.json','["子欲作梅詩，當造幽絕境。", "筆端有纖塵，正恐梅未肯。"]'),
('da58ad1f-e1f3-4570-8fa6-ec34f96612c0','梅花絕句十首  其七','陸游','宋','宋诗','song-poetry','','[]','清霜徹花骨，霜重花欲折。',24,'全唐诗/poet.song.130000.json','["清霜徹花骨，霜重花欲折。", "我知造物意，遣子世味絕。"]'),
('ca78ace0-6528-4bc9-89fb-ff51148d417f','梅花絕句十首  其八','陸游','宋','宋诗','song-poetry','','[]','士窮見節義，木槁自芬芳。',24,'全唐诗/poet.song.130000.json','["士窮見節義，木槁自芬芳。", "坐回萬物春，賴此一點香。"]'),
('1fdc183c-cba9-43d3-86ae-6e44da826e6e','梅花絕句十首  其九','陸游','宋','宋诗','song-poetry','','[]','南村花己繁，北塢殊未動。',24,'全唐诗/poet.song.130000.json','["南村花己繁，北塢殊未動。", "更賖一月期，待我醉春甕。"]'),
('e9325ca4-b56e-43c9-a85f-2d8aef271847','梅花絕句十首  其一○','陸游','宋','宋诗','song-poetry','','[]','山月縞中庭，幽人酒初醒。',24,'全唐诗/poet.song.130000.json','["山月縞中庭，幽人酒初醒。", "不是怯清寒，愁蹋梅花影。"]'),
('63b85946-05cc-4957-90e7-be88947c9857','閉户','陸游','宋','宋诗','song-poetry','','[]','簞瓢虚道不堪憂，閉户方從造物遊。',64,'全唐诗/poet.song.130000.json','["簞瓢虚道不堪憂，閉户方從造物遊。", "安樂本因無事得，功名常忌有心求。", "洗除仇怨忘戀觸，收斂光芒靜斗牛。", "兒報床頭春甕熟，人間萬事轉悠悠。"]'),
('12987e6c-26b3-4d11-b7d7-b9fc18fb1128','小園竹間得梅一枝','陸游','宋','宋诗','song-poetry','','[]','若耶溪邊鶴髮叟，流落一生端坐口。',128,'全唐诗/poet.song.130000.json','["若耶溪邊鶴髮叟，流落一生端坐口。", "如今不怕桃李嗔，更因竹君得梅友。", "嶺頭羈旅萬里愁，江上凄涼一杯酒。", "枝横澹月影在地，蘂插烏巾香馥手。", "交情歲晚金石堅，孤操凜然真耐久。", "荒山野水終自得，銀燭金壺亦何有。", "夢魂不接莊周蝶，心事肯付張緒柳。", "晚來畫角動高城，起舞聊爲放翁壽。"]'),
('3efa6b76-4210-4375-a4f8-deead6fe1624','梅花絕句二首  其一','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u548f\u7269", "\u6885\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','幽谷那堪更北枝，年年自分著花遲。',32,'全唐诗/poet.song.130000.json','["幽谷那堪更北枝，年年自分著花遲。", "高標逸韵君知否，正在層冰積雪時。"]'),
('8d096f27-d39e-4d4e-be6e-9d6cc255cb48','梅花絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','萬瓦清霜夜漏殘，小舟斜月過闌干。',32,'全唐诗/poet.song.130000.json','["萬瓦清霜夜漏殘，小舟斜月過闌干。", "老來一事偏堪恨，好看梅時却怕寒。"]'),
('34a350b6-e94e-43b8-b909-5688f0358139','得林正父察院書問信甚勤以長句寄謝','陸游','宋','宋诗','song-poetry','','[]','折柳湖南别尚新，書來已見柳揺春。',64,'全唐诗/poet.song.130000.json','["折柳湖南别尚新，書來已見柳揺春。", "故情有此膠投漆，薄俗從渠越視秦。", "長劍拄頤那復夢，短衣掩脛未全貧。", "有詩亦欲頻持寄，腸斷西江六六鱗。"]'),
('0c90c859-9723-45f8-849f-7bbd90472a24','蔬食戲書','陸游','宋','宋诗','song-poetry','','[]','新津韭黄天下無，色如鵝黄三尺餘。',96,'全唐诗/poet.song.130000.json','["新津韭黄天下無，色如鵝黄三尺餘。", "東門彘肉更奇絕，肥美不減塞羊酥。", "貴珍詎敢雜常饌，桂炊薏米圓比珠。", "還吳此味那復有，日飯脱粟焚枯魚。", "人生口腹何足道，往往坐役七尺軀。", "羶葷從今一掃除，夜煮白石箋陰符。"]'),
('774d4132-4155-43ca-8e34-309825516496','嘆俗','陸游','宋','宋诗','song-poetry','','[]','風俗陵夷日可憐，乞墦鉗市亦欣然。',32,'全唐诗/poet.song.130000.json','["風俗陵夷日可憐，乞墦鉗市亦欣然。", "看渠皮底元無血，那識虞卿魯仲連。"]'),
('bc6a6f55-cf87-46bb-b3be-28398eece80b','晚飯罷小立門外有作','陸游','宋','宋诗','song-poetry','','[]','此心何敢慕輕肥，尚愧無功飽蕨薇。',64,'全唐诗/poet.song.130000.json','["此心何敢慕輕肥，尚愧無功飽蕨薇。", "浦面鳥衝殘靄去，柳陰人荷一鋤歸。", "病嗟短髮紛紛白，老覺初心種種非。", "百步空庭著明月，黄昏手自掩荆扉。"]'),
('c9f1ebdf-9f7b-47d3-98f9-8d96dcd70511','觀梅至花涇高端叔解元見尋二首  其一','陸游','宋','宋诗','song-poetry','','[]','春晴閑過野僧家，邂逅詩人共晚茶。',32,'全唐诗/poet.song.130000.json','["春晴閑過野僧家，邂逅詩人共晚茶。", "歸見諸公問老子，爲言滿帽插梅花。"]'),
('4f79e228-5180-4e7f-a59e-647f719dc95b','觀梅至花涇高端叔解元見尋二首  其二','陸游','宋','宋诗','song-poetry','','[]','春暖山中雲作堆，放翁艇子出尋梅。',32,'全唐诗/poet.song.130000.json','["春暖山中雲作堆，放翁艇子出尋梅。", "不須問信道傍叟，但覓梅花多處來。"]'),
('914652fa-f1e4-47f2-9578-245c3706c996','春雪','陸游','宋','宋诗','song-poetry','','[]','江雲垂野雪如簁，閠歲春來特地遲。',32,'全唐诗/poet.song.130000.json','["江雲垂野雪如簁，閠歲春來特地遲。", "倒盡酒壺終日醉，臥聽兒誦半山詩。"]'),
('eb9ad9cb-86ce-43f6-89d3-6505a090a136','舟過季家山小泊','陸游','宋','宋诗','song-poetry','','[]','困睫濛濛渴煮茶，繫船來叩野人家。',64,'全唐诗/poet.song.130000.json','["困睫濛濛渴煮茶，繫船來叩野人家。", "風翻翠浪千畦麥，水漾紅雲一塢花。", "健犢破荒耕犖确，幽禽除蠧啄槎牙。", "尋春非復衰翁事，且伴兒童一笑譁。"]'),
('335b8195-1d35-42cb-a765-ff784dacb135','送王成之給事','陸游','宋','宋诗','song-poetry','','[]','我昔揚帆掠吳楚，夜泊秦淮聽春雨。',192,'全唐诗/poet.song.130000.json','["我昔揚帆掠吳楚，夜泊秦淮聽春雨。", "明朝冠蓋擁長亭，誤辱諸公問良苦。", "是時衆中初識公，天驥蹴踏萬馬空。", "知心投分財數語，玉塵謖謖生清風。", "冶城醉墨鴉棲壁，長干祖道花照席。", "公方閉户試諸生，坐嘆江山少顔色。", "爾來俛仰三十春，欲話舊遊無故人。", "豈知邂逅逢一笑，使我肝膽還輪囷。", "衰遲少復入城市，虚左屢招慚主意。", "忽聞上印却悽然，悔不日日從公醉。", "朝廷三載虚一相，如公早合鸞臺上。", "榮河温洛久風沙，此段功名勿多讓。"]'),
('3b2e96c7-8d47-4a09-95b3-7953be73ba0f','山家','陸游','宋','宋诗','song-poetry','','[]','白石青莎一徑斜，斷無人迹到山家。',64,'全唐诗/poet.song.130000.json','["白石青莎一徑斜，斷無人迹到山家。", "梁間歸燕避微雨，池面遊魚爭落花。", "雪鬢但增新感慨，金鞭那復舊豪華。", "明窗睡起渾無事，篝火風爐自試茶。"]'),
('170b5c9a-5016-4554-987c-4f9baa5c2dae','送傑上人歸成都二首  其一','陸游','宋','宋诗','song-poetry','','[]','錦城一别鬢成絲，今日山陰送傑師。',32,'全唐诗/poet.song.130000.json','["錦城一别鬢成絲，今日山陰送傑師。", "亂絮飛花撲行路，正如東郭放船時。"]'),
('ddd98363-3f1f-46c5-b87e-5ce5ca2caeec','送傑上人歸成都二首  其二','陸游','宋','宋诗','song-poetry','','[]','春夜挑燈話别愁，此心己在錦江頭。',32,'全唐诗/poet.song.130000.json','["春夜挑燈話别愁，此心己在錦江頭。", "舊時處處塵昏壁，想復長吟爲小留。"]'),
('2cd19e01-32cf-4f81-b38e-522e215ccae2','落魄','陸游','宋','宋诗','song-poetry','','[]','落魄江湖七十翁，欲持一笑與誰同。',64,'全唐诗/poet.song.130000.json','["落魄江湖七十翁，欲持一笑與誰同。", "蕭蕭雪鬢難藏老，寂寂蓬門可諱窮。", "好句尚來欹枕處，壯心時在倚樓中。", "無涯毁譽何勞詰，骨朽人間論自公。"]'),
('49ed6386-1f54-4098-b732-a30901745fc0','春晴出遊','陸游','宋','宋诗','song-poetry','','[]','芳樹參差葉已成，園林隨處聽鶯聲。',64,'全唐诗/poet.song.130000.json','["芳樹參差葉已成，園林隨處聽鶯聲。", "遊人正樂還興嘆，造物無心却有情。", "糝徑落紅猶可藉，漲溪分緑已堪耕。", "蘭亭禹廟年年好，剩伴鄉鄰醉太平。"]'),
('5177c4a8-02ce-40e7-9d45-f0164347229f','題瑩上人二畫 剡谿','陸游','宋','宋诗','song-poetry','','[]','天地又秋風，谿山憶剡中。',24,'全唐诗/poet.song.130000.json','["天地又秋風，谿山憶剡中。", "孤舟幸閑著，借我訪支公。"]'),
('41a4765e-8678-4d94-bde2-fa0b2c666e1a','題瑩上人二畫 吳江','陸游','宋','宋诗','song-poetry','','[]','曉聽楓橋鍾，暮泊松江月。',24,'全唐诗/poet.song.130000.json','["曉聽楓橋鍾，暮泊松江月。", "斯人亦可人，淡墨冩愁絕。"]'),
('88e96699-b0bf-4d18-8951-e8d782b43d99','和張功父見寄二首  其一','陸游','宋','宋诗','song-poetry','','[]','舉世何人念此翁，敢期相問寂寥中。',64,'全唐诗/poet.song.130000.json','["舉世何人念此翁，敢期相問寂寥中。", "回思舊社驚年往，細讀來書恨紙窮。", "我用荷鋤爲事業，君將高枕示神通。", "叮寧一語宜深聽，信筆題詩勿太工。"]'),
('c9f44395-eeb6-4d85-b404-8df58ba864b5','和張功父見寄二首  其二','陸游','宋','宋诗','song-poetry','','[]','佐命貂蟬再世孫，手鉏瓜壟傍青門。',64,'全唐诗/poet.song.130000.json','["佐命貂蟬再世孫，手鉏瓜壟傍青門。", "超騰已得丹換骨，戀著肯求香返魂。", "正復悲秋如騎省，可令病渴似文園。", "庭前柏樹西來意，握手何時得共論。"]'),
('9c309dae-2dc2-4d48-b3f9-258b8557c2e7','山家暮春二首  其一','陸游','宋','宋诗','song-poetry','','[]','遶屋清陰合，緣堤緑草纖。',48,'全唐诗/poet.song.130000.json','["遶屋清陰合，緣堤緑草纖。", "起蠶初放食，新麥已磨鎌。", "苦筍先調醬，青梅小蘸鹽。", "佳時幸無事，酒盡更須添。"]'),
('85ac1a4c-7489-4625-bb98-b8818f3cbe47','山家暮春二首  其二','陸游','宋','宋诗','song-poetry','','[]','行飯獨相羊，扶藜過野塘。',48,'全唐诗/poet.song.130000.json','["行飯獨相羊，扶藜過野塘。", "晴光生蝶粉，暖律變鶯吭。", "麨美群兒競，蠶饑小婦忙。", "深知遊宦惡，窮死勿離鄉。"]'),
('2b2adff4-11dc-4418-8898-c6b1e56d3b87','讀王季夷舊所寄詩','陸游','宋','宋诗','song-poetry','','[]','燈前忽見季夷詩，泪灑行間不自知。',32,'全唐诗/poet.song.130000.json','["燈前忽見季夷詩，泪灑行間不自知。", "醉别西津如昨日，露晞漚滅己多時。"]'),
('1b66965f-6e89-4a62-8f38-770cac5e2d7f','題庠闍黎二畫 秋景','陸游','宋','宋诗','song-poetry','','[]','秋山瘦嶙峋，秋水渺無津。',24,'全唐诗/poet.song.130000.json','["秋山瘦嶙峋，秋水渺無津。", "如何草亭上，却欠倚闌人。"]'),
('2a69c3a3-2464-4968-9d50-4a9089d20a6b','題庠闍黎二畫 雪景','陸游','宋','宋诗','song-poetry','','[]','溪上望前峰，巉巉千仞玉。',24,'全唐诗/poet.song.130000.json','["溪上望前峰，巉巉千仞玉。", "渾舍喜翁歸，地爐煨芋熟。"]'),
('5df6a4e2-1c5d-4457-8fcd-9d9c37b4a952','入雲門小憩五雲橋','陸游','宋','宋诗','song-poetry','','[]','穀雨初過換夾衣，園林零落到薔薇。',64,'全唐诗/poet.song.130000.json','["穀雨初過換夾衣，園林零落到薔薇。", "鳴鳩日暖遥相應，雛燕風柔漸獨飛。", "臺省多才吾輩拙，江湖久客暮年歸。", "雲門蹋月方清絕，且倚溪橋看夕霏。"]'),
('efe6be9a-5473-4fdc-a01b-f3447734ea90','黄祊小店野飯示子坦子聿','陸游','宋','宋诗','song-poetry','','[]','山林久衰病，生世幾清明。',48,'全唐诗/poet.song.130000.json','["山林久衰病，生世幾清明。", "未作松根卧，猶尋溪上行。", "食新炊麥飯，嘗饁啜蒓羮。", "孺子雖知學，家貧且力耕。"]'),
('8915d934-c4d2-4f46-9dc1-421e19190197','山園','陸游','宋','宋诗','song-poetry','','[]','山園寂寂閉春風，箇裏天教著放翁。',64,'全唐诗/poet.song.130000.json','["山園寂寂閉春風，箇裏天教著放翁。", "萬事已抛孤枕外，一尊常醉亂花中。", "閑隨戲蝶忘形久，細聽啼鶯得意同。", "月桂可憐常在眼，小樷時放一枝紅。"]'),
('741693b1-7217-4cde-a5e7-157a02ea63af','入城至郡圃及諸家園亭遊人甚盛','陸游','宋','宋诗','song-poetry','','[]','老子何曾慣市塵，今朝也復入城闉。',64,'全唐诗/poet.song.130000.json','["老子何曾慣市塵，今朝也復入城闉。", "太平有象人人醉，造物無私處處春。", "九陌鶯花娛病眼，一竿風月屬閑身。", "不緣興盡回橈早，要就湖波照角巾。"]'),
('958b0d29-feb5-44b2-8ada-211f62e5fca0','次韵范參政書懷十首  其一','陸游','宋','宋诗','song-poetry','','[]','養氣頽然似木雞，謗讒寧復問端倪。',64,'全唐诗/poet.song.130000.json','["養氣頽然似木雞，謗讒寧復問端倪。", "生塵甑暖喜炊黍，轑釡羮香忘糝藜。", "萬里曾遊雲棧北，一庵今卧鏡湖西。", "殘年老病侵腰膂，那得隨人病夏畦。"]'),
('edc7b59b-07ac-4773-9bae-c20a681106fe','次韵范參政書懷十首  其二','陸游','宋','宋诗','song-poetry','','[]','已著山林掃塔衣，洗除仕路劍頭炊。',64,'全唐诗/poet.song.130000.json','["已著山林掃塔衣，洗除仕路劍頭炊。", "心光焰焰雖潛發，頷雪紛紛己太遲。", "度日只今閑水牯，知時從昔羡山雌。", "掩關未必渾無事，擬徧寒山百首詩。"]'),
('b83a33c5-698b-40ba-b3dc-961205797283','次韵范參政書懷十首  其三','陸游','宋','宋诗','song-poetry','','[]','身寄崦嵫欲盡時，且貪餘景伴兒嬉。',64,'全唐诗/poet.song.130000.json','["身寄崦嵫欲盡時，且貪餘景伴兒嬉。", "故廬手種竹千箇，醉帽時篸花一枝。", "蠧篋有書供夙好，衡門無客作新知。", "羊裘自欠封侯骨，敢道君房徹底癡。"]'),
('f87306c5-5658-4b01-ae1d-e3f30c1545a1','次韵范參政書懷十首  其四','陸游','宋','宋诗','song-poetry','','[]','感昔傷懷一喟然，事賢猶及紹興前。',64,'全唐诗/poet.song.130000.json','["感昔傷懷一喟然，事賢猶及紹興前。", "此身顛仆應無日，諸老凋零不計年。", "客少可羅門外雀，家貧也辦杖頭錢。", "揷花醉舞春風裏，不學龐翁更問禪。"]'),
('4fcfc6a6-3938-419d-bfd8-db8f9f659f8a','次韵范參政書懷十首  其五','陸游','宋','宋诗','song-poetry','','[]','春寒還似暮冬天，敗絮重披有蝨緣。',64,'全唐诗/poet.song.130000.json','["春寒還似暮冬天，敗絮重披有蝨緣。", "雖欠高僧分白氎，偶蒙暴客恕青氊。", "濁醪盎盎貧猶醉，倦枕昏昏晝亦眠。", "年少從渠笑衰懶，相呼禹廟看龍船。"]'),
('9c494570-b43c-4c84-b133-d0ee2ed5fcfd','次韵范參政書懷十首  其六','陸游','宋','宋诗','song-poetry','','[]','祠禄恩寬亦例沾，屏居懷抱苦厭厭。',64,'全唐诗/poet.song.130000.json','["祠禄恩寬亦例沾，屏居懷抱苦厭厭。", "戍邊事往功名忤，迎客兒扶老病兼。", "遇興榜舟無遠近，破愁沽酒任酸甜。", "殘年唯有讀書癖，盡發家藏三萬籖。"]'),
('f7115149-e99d-45b2-8405-6ada259435dd','次韵范參政書懷十首  其七','陸游','宋','宋诗','song-poetry','','[]','芋栗多儲煮復煨，一塵那許到靈臺。',64,'全唐诗/poet.song.130000.json','["芋栗多儲煮復煨，一塵那許到靈臺。", "虹穿道室爐丹熟，龍吼空山匣劍開。", "躡屩未成遊地肺，掩扉聊欲隠天台。", "桃花榮謝吾何預，一任劉郎去後栽。"]'),
('549e36b4-3eee-486e-aa4a-1384b803e58c','次韵范參政書懷十首  其八','陸游','宋','宋诗','song-poetry','','[]','探梅方憶雪中歸，轉眼青青子滿枝。',64,'全唐诗/poet.song.130000.json','["探梅方憶雪中歸，轉眼青青子滿枝。", "築圃漫爲娛老計，襞牋又賦送春詩。", "乞身何日還初服，坐食終年愧聖時。", "睡起西窗澹無事，一枰閑看客爭棋。"]'),
('9c5182e9-22d5-411f-afde-f56f2be8afdb','次韵范參政書懷十首  其九','陸游','宋','宋诗','song-poetry','','[]','宇內寓形財幾時，西山俄己迫斜暉。',64,'全唐诗/poet.song.130000.json','["宇內寓形財幾時，西山俄己迫斜暉。", "百年過隙古所嘆，衆口鑠金胡不歸。", "己是平生行逆境，更堪末路踐危機。", "夜香一炷無他祝，稽首虚空懺昨非。"]'),
('e3c29d89-266c-4519-bc01-841f66090420','次韵范參政書懷十首  其一○','陸游','宋','宋诗','song-poetry','','[]','趙州行脚我安能，閑却床邊六尺藤。',64,'全唐诗/poet.song.130000.json','["趙州行脚我安能，閑却床邊六尺藤。", "釣閣卧聼西澗雨，棋軒遥見北村燈。", "平生愛睡如甘酒，晚歲憂讒劇履冰。", "剩欲舒懷答清嘯，半空鸞鳳愧孫登。"]'),
('ba18e83b-dd69-4186-88ba-b1efd406979a','春晚村居雜賦絕句六首  其一','陸游','宋','宋诗','song-poetry','','[]','作堤蜿蜿六百尺，西崦東村成一家。',32,'全唐诗/poet.song.130000.json','["作堤蜿蜿六百尺，西崦東村成一家。", "春雨乍晴桑吐葉，秋風初冷稻吹花。"]'),
('df77619e-110c-41ad-a137-731b3fcafcb0','春晚村居雜賦絕句六首  其二','陸游','宋','宋诗','song-poetry','','[]','鵝兒草綠侵行路，帔子花明照屋除。',32,'全唐诗/poet.song.130000.json','["鵝兒草綠侵行路，帔子花明照屋除。", "處處乞漿俱得酒，杖頭何恨一錢無。"]'),
('ec6aedd5-a5c8-4af1-ba52-139bf327ec4a','春晚村居雜賦絕句六首  其三','陸游','宋','宋诗','song-poetry','','[]','一篙湖水鴨頭綠，千樹桃花人面紅。',32,'全唐诗/poet.song.130000.json','["一篙湖水鴨頭綠，千樹桃花人面紅。", "茆舍青帘起余意，聊將醉舞答春風。"]'),
('88db79bf-292f-4444-a312-d7a1d5c26166','春晚村居雜賦絕句六首  其四','陸游','宋','宋诗','song-poetry','','[]','朝書牛券拈枯筆，暮祭蠶神酌凍醪。',32,'全唐诗/poet.song.130000.json','["朝書牛券拈枯筆，暮祭蠶神酌凍醪。", "閑放無憂窮有意，傍人錯羡此翁高。"]'),
('7af431f9-4864-4fbe-8dc8-a5943db2ffa8','春晚村居雜賦絕句六首  其五','陸游','宋','宋诗','song-poetry','','[]','澆書滿挹浮蛆瓮，攤飯横眠夢蝶床。',32,'全唐诗/poet.song.130000.json','["澆書滿挹浮蛆瓮，攤飯横眠夢蝶床。", "莫笑山翁見機晚，也勝朝市一生忙。"]'),
('3dd8b05b-1e31-40cc-bf9f-b562197f4a7a','春晚村居雜賦絕句六首  其六','陸游','宋','宋诗','song-poetry','','[]','午枕閉門無客攪，夜燈開卷有兒同。',32,'全唐诗/poet.song.130000.json','["午枕閉門無客攪，夜燈開卷有兒同。", "若爲牋與天公道，盡乞餘生向此中。"]'),
('ca0f482d-8957-4598-ad6e-3e75d501abc5','沽埭西酒小酌','陸游','宋','宋诗','song-poetry','','[]','埭西小店酒新篘，一醉今朝覺易謀。',64,'全唐诗/poet.song.130000.json','["埭西小店酒新篘，一醉今朝覺易謀。", "從曠劫來俱有死，出青天外始無愁。", "功名未許妨高卧，風月猶能賦遠遊。", "造物向人元不薄，卷簾萬頃鏡湖秋。"]'),
('40bc149d-41f9-4b3b-8974-6461fb1980ae','戲詠村居二首  其一','陸游','宋','宋诗','song-poetry','','[]','歌起陂頭正插秧，梯斜籬外又求桑。',64,'全唐诗/poet.song.130000.json','["歌起陂頭正插秧，梯斜籬外又求桑。", "日長處處鶯聲美，歲樂家家麥飯香。", "林杏半丹禁宿雨，樷萱自斂避斜陽。", "北窗合是羲皇上，巳置臨風八尺床。"]'),
('fa1de860-0051-4e4a-858e-7942b927d08c','戲詠村居二首  其二','陸游','宋','宋诗','song-poetry','','[]','馬跡車聲斷已無，鄰翁笑語自相呼。',64,'全唐诗/poet.song.130000.json','["馬跡車聲斷已無，鄰翁笑語自相呼。", "衣裁大布如亭長，船設低篷學釣徒。", "愍物欲師僧施食，畏人愁報吏催租。", "陳蕃壯志消磨盡，一室從今却掃除。"]'),
('8a00290e-ae5b-4617-a20c-7d600633195f','戲詠閑適三首  其一','陸游','宋','宋诗','song-poetry','','[]','鈔書字細眼猶明，擣藥聲清疾漸平。',64,'全唐诗/poet.song.130000.json','["鈔書字細眼猶明，擣藥聲清疾漸平。", "桐葉雨邊尋斷夢，菊花香裏散餘酲。", "人間榮辱知難到，紙上興亡看亦輕。", "惟恨暮年交舊少，滿懷情話向誰傾。"]'),
('6a8f138d-ce63-4170-b622-3f26f7bda8ba','戲詠閑適三首  其二','陸游','宋','宋诗','song-poetry','','[]','剡曲稽山是故鄉，人言景物似瀟湘。',64,'全唐诗/poet.song.130000.json','["剡曲稽山是故鄉，人言景物似瀟湘。", "三升花露春壺滿，八尺風漪午枕涼。", "樹合緑陰山鵲閙，盆鐫紫石水梔香。", "回思烏帽京塵客，始覺幽居白日長。"]'),
('7fe4e4b3-e264-4d20-85c3-d66512e282e9','戲詠閑適三首  其三','陸游','宋','宋诗','song-poetry','','[]','涉世心知百不能，閉門懶出病相仍。',64,'全唐诗/poet.song.130000.json','["涉世心知百不能，閉門懶出病相仍。", "簞瓢味美如烹鼎，鄰曲人淳近結繩。", "半顆鴉殘墻外杏，一枝鵲裊澗邊藤。", "蕭然掃盡彈冠興，敢爲詩情望武陵。"]'),
('266261d9-2f48-41a3-8a95-aea03c2ed225','夜與兒子出門閑步','陸游','宋','宋诗','song-poetry','','[]','家住黄花入麥村，閑將稚子出柴門。',64,'全唐诗/poet.song.130000.json','["家住黄花入麥村，閑將稚子出柴門。", "草根螢墮久開闔，雲際月行時吐吞。", "未分悲憂攻齒髮，已將生死付乾坤。", "舊書半蠧猶堪讀，糲飯藜羮莫更論。"]'),
('b0393c79-be46-4846-8966-9d62dda684b9','老景','陸游','宋','宋诗','song-poetry','','[]','老景雖無幾，爲農尚有餘。',48,'全唐诗/poet.song.130000.json','["老景雖無幾，爲農尚有餘。", "曾傳種魚術，新得相牛書。", "黍酒時留客，菱歌或起予。", "平生湖海志，高枕看嚴徐。"]'),
('63ea5eaa-1fb1-4f93-b5c2-994c71393e63','初夏','陸游','宋','宋诗','song-poetry','','[]','筍生遮狹徑，溪漲入疏籬。',48,'全唐诗/poet.song.130000.json','["筍生遮狹徑，溪漲入疏籬。", "漸及分秧候，還當煮繭時。", "雨昏雞共懶，米盡鼠同饑。", "村巷無來客，清羸只自知。"]'),
('fde0c245-bd84-4573-a5de-af0abefea327','晨起','陸游','宋','宋诗','song-poetry','','[]','老病少睡眠，卧見天窗白。',72,'全唐诗/poet.song.130000.json','["老病少睡眠，卧見天窗白。", "棲烏亦己鳴，一一翻去翮。", "我起將何之，且復守書册。", "收斂萬里心，未厭容膝迮。", "吾家讀書法，一字亦當覈。", "勉哉積新功，莫問幾時客。"]'),
('2769cd95-c206-4c78-9772-87ba3cbb75a8','月夜短歌','陸游','宋','宋诗','song-poetry','','[]','老夫倚杖當户立，霜氣青冥月輪濕。',64,'全唐诗/poet.song.130000.json','["老夫倚杖當户立，霜氣青冥月輪濕。", "颼颼短髮冷入頂，更覺衣屨清風襲。", "月落欲盡夜蒼茫，回顧明星已煌煌。", "明星雖高未須喜，三足陽烏生海底。"]'),
('13240ca1-3448-44ec-9119-6dfb8472ba11','小軒','陸游','宋','宋诗','song-poetry','','[]','四面山如碧玉城，小軒聊得愜幽情。',64,'全唐诗/poet.song.130000.json','["四面山如碧玉城，小軒聊得愜幽情。", "乍飛乳燕低無力，自落來禽靜有聲。", "麟筆殘功成水品，蛇圖餘思入棋枰。", "閑中事業吾能了，未恨林廬送此生。"]'),
('8d6db9e6-d1b2-4e84-9557-ff3134302e54','愛閑','陸游','宋','宋诗','song-poetry','','[]','愛閑惟與病相宜，壯歲懷歸老可知。',64,'全唐诗/poet.song.130000.json','["愛閑惟與病相宜，壯歲懷歸老可知。", "睡熟素書横竹架，吟餘犀管閣銅螭。", "水芭蕉潤心抽葉，盆石榴殘子壓枝。", "堪笑放翁頭白盡，坐消長日事兒嬉。"]'),
('733b1a19-c709-40f4-bff0-6b3bd1d2ae8b','靜院','陸游','宋','宋诗','song-poetry','','[]','靜院房櫳雨送涼，熏籠衣幘潤生香。',64,'全唐诗/poet.song.130000.json','["靜院房櫳雨送涼，熏籠衣幘潤生香。", "小屏風疉圖遥碧，古錦囊書榻硬黄。", "己占江湖寬處老，絕知日月靜中長。", "敲門無客妨人睡，更覺餘年樂未央。"]'),
('a71785af-c3ff-46ff-a80c-47f597933da3','雨晴','陸游','宋','宋诗','song-poetry','','[]','閑曵枯笻自在行，曲廊小閣賞新晴。',64,'全唐诗/poet.song.130000.json','["閑曵枯笻自在行，曲廊小閣賞新晴。", "幽禽葉底吟風久，殘雨枝間照日明。", "茶映盞毫新乳上，琴横薦石細泉鳴。", "亦知老健終難恃，且復蕭然得此生。"]'),
('e67527d7-7f17-4211-ba12-ce31131ff5b9','讀史有感','陸游','宋','宋诗','song-poetry','','[]','英雄自古埋秋草，世上兒童共笑狂。',64,'全唐诗/poet.song.130000.json','["英雄自古埋秋草，世上兒童共笑狂。", "射賊曾飛白羽箭，閉門空枕緑沉槍。", "隆中高卧人千載，易水悲歌涙數行。", "讀盡青編窗日晚，一尊聊復吊興亡。"]'),
('6b5779d6-4882-44c1-892d-d765e984c539','暮歸','陸游','宋','宋诗','song-poetry','','[]','意行無所之，偶傍陂頭立。',48,'全唐诗/poet.song.130000.json','["意行無所之，偶傍陂頭立。", "空村犬吠豪，高樹蟬嘒急。", "風塵一身老，海宇萬感集。", "還家日己暮，草露青鞋濕。"]'),
('050eb41e-d7f3-42b1-bf83-5141c33d3fe4','仰首座求鈍庵詩','陸游','宋','宋诗','song-poetry','','[]','鈍庵來問鈍何如，真箇能參鈍也無。',64,'全唐诗/poet.song.130000.json','["鈍庵來問鈍何如，真箇能參鈍也無。", "掘井及泉那用巧，磨磚作鏡未爲愚。", "先師鉢袋當傳後，上座蒲團莫負渠。", "我亦年來念休歇，約君同作鈍工夫。"]'),
('0270c912-86e5-4ade-9e47-a225f4e2b076','壁老求笑庵詩二首  其一','陸游','宋','宋诗','song-poetry','','[]','臺省諸公六出奇，江湖狂客一生癡。',32,'全唐诗/poet.song.130000.json','["臺省諸公六出奇，江湖狂客一生癡。", "無人爲問淨光老，撫掌掀髯端爲誰。"]'),
('4c35275b-a702-4cc1-8028-aef5af4cd3c1','壁老求笑庵詩二首  其二','陸游','宋','宋诗','song-poetry','','[]','車馬往來塵暗天，淨光欣喜接諸賢。',32,'全唐诗/poet.song.130000.json','["車馬往來塵暗天，淨光欣喜接諸賢。", "半甌春茗無多費，且結來生一笑緣。"]'),
('b0ccfa9f-3c0b-4aa3-ba5b-7a88de8850e8','浴罷','陸游','宋','宋诗','song-poetry','','[]','浴罷西軒物色幽，卧看香霧上衣篝。',64,'全唐诗/poet.song.130000.json','["浴罷西軒物色幽，卧看香霧上衣篝。", "半廊月白初侵夜，一葉桐飛忽報秋。", "老覺年光殊衮衮，病知心事斷悠悠。", "碧筩且作池邊醉，玉色新醅手自篘。"]'),
('6beed04c-bb1d-4629-b4aa-aea1d9a7c349','夜坐水次','陸游','宋','宋诗','song-poetry','','[]','房星縱，心星横，北斗高挂南斗傾。',79,'全唐诗/poet.song.130000.json','["房星縱，心星横，北斗高挂南斗傾。", "蓼根熠熠螢火明，葦樷哀哀姑惡聲。", "我倚胡床破三更，溪風吹衣月未生。", "玉門關拂雲城何，時連營插漢旌白。", "頭書生未可輕，不死令君看太平。"]'),
('bd00cc81-cfcb-41fe-9dc4-4a337fd38f7b','六月十四日微雨極凉','陸游','宋','宋诗','song-poetry','','[]','湖上清秋近，齋中白日長。',48,'全唐诗/poet.song.130000.json','["湖上清秋近，齋中白日長。", "雲來樹收影，雨過土生香。", "蓮小紅衣濕，瓜甘碧玉涼。", "晚來幽興極，移榻近方塘。"]'),
('d2b8662b-51b6-4634-a0ec-4342b5b8861e','十五日雲陰凉尤甚再賦長句','陸游','宋','宋诗','song-poetry','','[]','褦襶京塵觸熱行，豈知世有野堂清。',64,'全唐诗/poet.song.130000.json','["褦襶京塵觸熱行，豈知世有野堂清。", "磑茶落雪睡魔退，激水跳珠涼意生。", "亹亹清風隨塵柄，悠悠長日付棋枰。", "小舟先向蘋汀泊，浴罷還須泛月明。"]'),
('054aada5-5608-4e7b-bc5d-ede0b260f4ae','水亭晚眺','陸游','宋','宋诗','song-poetry','','[]','暑雨初晴浦面寬，水亭景物卷簾看。',64,'全唐诗/poet.song.130000.json','["暑雨初晴浦面寬，水亭景物卷簾看。", "聨舟作陣圍魚隊，屈竹成籬護芡盤。", "四海諸公半丘壟，百年幾夕倚闌干。", "日沈未用怱怱去，待挽銀河濯肺肝。"]'),
('462802b6-408d-47dd-927d-dbc714782e38','自詠','陸游','宋','宋诗','song-poetry','','[]','萬事不挂眼，終年常避人。',48,'全唐诗/poet.song.130000.json','["萬事不挂眼，終年常避人。", "荒畦荷鋤晚，環堵結茆新。", "病馬何勞斥，輕鷗未肯馴。", "雖慚市門卒，聊作葛天民。"]'),
('8ce5b1e1-083f-4bc6-889e-6c9438ddeb51','立秋前四日夜泛舟至跨湖橋','陸游','宋','宋诗','song-poetry','','[]','短楫追凉十里來，夜深却御便風回。',64,'全唐诗/poet.song.130000.json','["短楫追凉十里來，夜深却御便風回。", "離離蒲葉先秋老，嫋嫋蘋花带露開。", "陌上歌呼簪稻穗，橋邊燈火賣官醅。", "時平樂事知何限，未嘆流年兩鬢催。"]'),
('95c35c18-6832-493b-ad4e-b59cd41e3284','信筆三首  其一','陸游','宋','宋诗','song-poetry','','[]','爲善得禍吁可悲，顔回短命伯夷饑。',32,'全唐诗/poet.song.130000.json','["爲善得禍吁可悲，顔回短命伯夷饑。", "何人長號血續泪，天自無心君自癡。"]'),
('c9082248-bf5d-434c-8f4f-ab35ddb6997e','信筆三首  其二','陸游','宋','宋诗','song-poetry','','[]','少年醉眼傲王侯，末路悲歌夜飯牛。',32,'全唐诗/poet.song.130000.json','["少年醉眼傲王侯，末路悲歌夜飯牛。", "濟世有時生一念，鏡中白髮勸人休。"]'),
('80752f25-adf7-4a09-bbec-46223bb83599','信筆三首  其三','陸游','宋','宋诗','song-poetry','','[]','急雨初過景物奇，一天雲作細鱗差。',32,'全唐诗/poet.song.130000.json','["急雨初過景物奇，一天雲作細鱗差。", "畫橈弄水三十里，恰是西村烟暝時。"]'),
('26dcdfac-c58b-40d8-a434-a5a78949302b','示兒','陸游','宋','宋诗','song-poetry','','[]','斥逐襆被歸，招喚振衣起。',96,'全唐诗/poet.song.130000.json','["斥逐襆被歸，招喚振衣起。", "此是鄙夫事，學者那得爾。", "前年還東時，指心誓江水。", "亦知食不足，但有餓而死。", "小兒教汝書，不用日十紙。", "字字講聲形，仍要身踐履。", "果能稱善人，便可老鄉里。", "勿言五鼎養，肉食吾所鄙。"]'),
('8540520b-3954-4810-944f-8b56b3543ddc','青山白雲歌','陸游','宋','宋诗','song-poetry','','[]','青山白雲翁，放浪酒中死。',52,'全唐诗/poet.song.130000.json','["青山白雲翁，放浪酒中死。", "埋骨長松根，夜夜聽谿水。", "松老會作薪，骨朽會作塵。", "但留千載狂名在，知我它年自有人。"]'),
('b8e5dac7-9b39-4fdb-ba4e-b319cfd2ec05','小市','陸游','宋','宋诗','song-poetry','','[]','小市狂歌醉墮冠，南山山色跨牛看。',32,'全唐诗/poet.song.130000.json','["小市狂歌醉墮冠，南山山色跨牛看。", "放翁胸次誰能測，萬里秋空未是寬。"]'),
('5a3af7cc-19d5-4363-8d44-91b65ab83a93','蓬萊館午憩','陸游','宋','宋诗','song-poetry','','[]','驛門繫馬聽蟬吟，翻動平生萬里心。',64,'全唐诗/poet.song.130000.json','["驛門繫馬聽蟬吟，翻動平生萬里心。", "橋畔笛聲催日落，城邊草色带烟深。", "關河歴歴功名晚，歲月悠悠老病侵。", "憶戌梁州如昨日，憑闌西望一霑襟。"]'),
('4cb08672-6d79-407d-99e4-058884d7f956','夢遊散關渭水之間','陸游','宋','宋诗','song-poetry','','[]','平生望眼怯天涯，客裏何堪度歲華。',64,'全唐诗/poet.song.130000.json','["平生望眼怯天涯，客裏何堪度歲華。", "但恨征輪無四角，不愁歸路有三义。", "驛窗燈闇傳秋柝，關樹烟深宿暮鴉。", "叱犢老翁頭似雪，羡渠生死不離家。"]'),
('eb437994-af31-420c-88b5-2e1ddb1af52c','秋夜','陸游','宋','宋诗','song-poetry','','[]','清夜不成寐，出門還浩歌。',48,'全唐诗/poet.song.130000.json','["清夜不成寐，出門還浩歌。", "斷雲微翳月，薄露不傾荷。", "絡緯知時早，梧桐奈汝何。", "非關老懷惡，秋物感人多。"]'),
('813d72fc-542b-4ed1-8c11-34d5fe64779d','世事','陸游','宋','宋诗','song-poetry','','[]','世事本難全，吾生已愧天。',48,'全唐诗/poet.song.130000.json','["世事本難全，吾生已愧天。", "借書常稇載，餽酒亦蟬聨。", "饘粥隨時具，湖山此地偏。", "殘年更何慕，未死即神仙。"]'),
('8503580f-a7a3-4414-8e89-17e9e7e017a6','夜半池上作','陸游','宋','宋诗','song-poetry','','[]','夜永空齋睡不成，起扶藤杖傍池行。',64,'全唐诗/poet.song.130000.json','["夜永空齋睡不成，起扶藤杖傍池行。", "露濃雙鵲移枝宿，風急孤螢墮草明。", "斷續更籌傳古戍，縱横河漢接高城。", "寒泉未潄神先爽，静聴銅瓶汲井聲。"]'),
('508db599-3469-4558-b24f-5f9795dda616','秋夜将曉出籬門迎涼有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','迢迢天漢西南落，喔喔鄰雞一再鳴。',32,'全唐诗/poet.song.130000.json','["迢迢天漢西南落，喔喔鄰雞一再鳴。", "壯志病來銷欲盡，出門搔首愴平生。"]'),
('aa25d944-9931-48ae-9190-3ef49618a66c','秋夜将曉出籬門迎涼有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','三萬里河東入海，五千仞嶽上摩天。',32,'全唐诗/poet.song.130000.json','["三萬里河東入海，五千仞嶽上摩天。", "遺民泪盡胡塵裏，南望王師又一年。"]'),
('bafe803d-78d0-462e-bb80-8578967b5278','夏秋之交久不雨方以旱爲憂忽得甘澍澍喜而有作','陸游','宋','宋诗','song-poetry','','[]','亂點灑庭蕪，涼聲集井梧。',48,'全唐诗/poet.song.130000.json','["亂點灑庭蕪，涼聲集井梧。", "緑荷傾作汞，翠蔓綴成珠。", "卧聽病良己，行吟愁欲無。", "天公終老手，談笑活焦枯。"]'),
('6028ec83-7f1b-4e54-bcdf-60fa22decaa8','藥圃','陸游','宋','宋诗','song-poetry','','[]','少年讀爾雅，亦喜騷人語。',120,'全唐诗/poet.song.130000.json','["少年讀爾雅，亦喜騷人語。", "幸兹身少閑，治地開藥圃。", "破荒劚瓦礫，引水灌膏乳。", "玉芝移石帆，金星取天姥。", "申椒蘼蕪輩，一一粲可數。", "次第雨苗滋，參差楓葉舉。", "山僧與野老，言議各有取。", "瓜香躬采曝，泉潔謹炊鬻。", "老夫病若失，稚子喜欲舞。", "餘年有幾何，長鑱真託汝。"]'),
('d1a227bf-af99-4bc2-822e-a0d8ee2878e3','書嘆','陸游','宋','宋诗','song-poetry','','[]','只道才高始不容，無才也墮駭機中。',64,'全唐诗/poet.song.130000.json','["只道才高始不容，無才也墮駭機中。", "市朝回首已陳迹，日月催人成老翁。", "仗馬自貪三品料，雲鵬方駕九天風。", "今朝有喜君知否，揀得烟汀下釣筒。"]'),
('640d0183-b485-48ff-a246-483a2461394e','夜興','陸游','宋','宋诗','song-poetry','','[]','夜出茆堂自撤扃，烏藤與我兩伶俜。',64,'全唐诗/poet.song.130000.json','["夜出茆堂自撤扃，烏藤與我兩伶俜。", "涼蟾吐暈圍千丈，老木移陰可一庭。", "隔浦呼嗚聞宿鳥，傍簷開闔數流螢。", "放翁尚友論千載，不取梁鴻即管寧。"]'),
('71ca5149-35e3-43a2-8f70-cbf0e07ed188','閑中頗自適戲書示客','陸游','宋','宋诗','song-poetry','','[]','髮猶半黑臉常紅，老健應無似放翁。',64,'全唐诗/poet.song.130000.json','["髮猶半黑臉常紅，老健應無似放翁。", "烹野八珍邀父老，燒窮四和伴兒童。", "剪紗新製簪花帽，乞竹寛編養鶴籠。", "巢許夔龍竟誰是，請君下語勿匆匆。"]'),
('343b3e57-e9c4-4f68-b27a-5855d4c0442a','新涼夜坐有作','陸游','宋','宋诗','song-poetry','','[]','老夫任運本騰騰，一念軒裳實未曾。',64,'全唐诗/poet.song.130000.json','["老夫任運本騰騰，一念軒裳實未曾。", "閑似苔磯垂釣叟，淡如村院罷參僧。", "硯屏突兀蓬婆雪，書几青熒蓮勺燈。", "稚子可憐貪夜課，語渠循舊未須增。"]'),
('4c32799e-fce2-4c39-9785-e06525d84c2b','荷花二首  其一','陸游','宋','宋诗','song-poetry','','[]','風露青冥水面涼，旋移野艇受清香。',32,'全唐诗/poet.song.130000.json','["風露青冥水面涼，旋移野艇受清香。", "猶嫌翠蓋紅粧句，何况人言似六郎。"]'),
('82ff20b2-fbbc-4df8-bfae-c9a9818cf1c1','荷花二首  其二','陸游','宋','宋诗','song-poetry','','[]','南浦清秋露冷時，凋紅片片己堪悲。',32,'全唐诗/poet.song.130000.json','["南浦清秋露冷時，凋紅片片己堪悲。", "若教具眼高人看，風折霜枯似更奇。"]'),
('576ea5f7-5c81-464f-99ba-6754f19e41b9','醉中作','陸游','宋','宋诗','song-poetry','','[]','宦遊三十載，舉步亦看人。',48,'全唐诗/poet.song.130000.json','["宦遊三十載，舉步亦看人。", "愛酒官長罵，近花丞相嗔。", "湖山今入手，風月始關身。", "少吐胸中氣，從教白髮新。"]'),
('32826ae7-5af4-452d-9256-a47956ceeacf','題齋壁','陸游','宋','宋诗','song-poetry','','[]','平生喜蕭散，垂老厭奔走。',72,'全唐诗/poet.song.130000.json','["平生喜蕭散，垂老厭奔走。", "三年鏡湖上，樂事未曾有。", "晨開一卷書，暮把一巵酒。", "病除覺身輕，赤脚自蹋藕。", "乃知造物意，亦未棄衰朽。", "今夕月殊佳，出門喚鄰叟。"]'),
('eeaf54e4-9ab4-4d29-bc2e-dcc42cf82aee','老將二首  其一','陸游','宋','宋诗','song-poetry','','[]','憶昔東都有事宜，夜傳帛詔起西師。',32,'全唐诗/poet.song.130000.json','["憶昔東都有事宜，夜傳帛詔起西師。", "功名無分身空在，猶指金創說戰時。"]'),
('09a7af05-bd2f-49b2-86a0-50e306a76cba','老將二首  其二','陸游','宋','宋诗','song-poetry','','[]','百戰西歸變姓名，悲歌擊筑醉湖城。',32,'全唐诗/poet.song.130000.json','["百戰西歸變姓名，悲歌擊筑醉湖城。", "貂裘換得金鵶觜，種藥南山待太平。"]'),
('c64fe3ff-1e0c-402c-a418-75e86eba426f','白髮','陸游','宋','宋诗','song-poetry','','[]','疾病侵壯年，髮恐不及白。',72,'全唐诗/poet.song.130000.json','["疾病侵壯年，髮恐不及白。", "偶賴針石功，寓世成久客。", "行年垂七十，霜雪紛滿幘。", "耳目雖已衰，亦未與人隔。", "濯纓千頃湖，送老五畝宅。", "大布縫長衫，東阡復南陌。"]'),
('54509bea-c973-4f09-bdca-df2fd2b7db4c','小雨','陸游','宋','宋诗','song-poetry','','[]','百穀畏秋陽，常恐膏澤吝。',48,'全唐诗/poet.song.130000.json','["百穀畏秋陽，常恐膏澤吝。", "大哉天公仁，霡霂來有信。", "蘋汀水未長，藥壟土先潤。", "新涼生葛衣，老憊亦小振。"]'),
('a5fdc391-463a-4e35-98f2-27b88219c229','秋日郊居八首  其一','陸游','宋','宋诗','song-poetry','','[]','山雨霏微鴨頭水，溪雲細薄魚鱗天。',32,'全唐诗/poet.song.130000.json','["山雨霏微鴨頭水，溪雲細薄魚鱗天。", "幽尋自笑本無事，羽扇笻枝上釣船。"]'),
('9bb2bf85-f901-4a4f-b346-6505c484c49b','秋日郊居八首  其二','陸游','宋','宋诗','song-poetry','','[]','行歌曳杖到新塘，銀闕瑤臺無此涼。',32,'全唐诗/poet.song.130000.json','["行歌曳杖到新塘，銀闕瑤臺無此涼。", "萬里秋風菰菜老，一川明月稻花香。"]'),
('d5b5e1ce-411b-4dac-a622-b5863cdb9c36','秋日郊居八首  其三','陸游','宋','宋诗','song-poetry','','[]','秋日留連野老家，朱槃鮓臠粲如花。',32,'全唐诗/poet.song.130000.json','["秋日留連野老家，朱槃鮓臠粲如花。", "己炊藟散真珠米，更點丁坑白雪茶。"]'),
('566daed0-a528-4ebd-a327-df6b2d12394c','秋日郊居八首  其四','陸游','宋','宋诗','song-poetry','','[]','車蕩比鄰例饋魚，流涎對此四腮鱸。',32,'全唐诗/poet.song.130000.json','["車蕩比鄰例饋魚，流涎對此四腮鱸。", "北窗雨過涼如水，消得先生一醉無。"]'),
('608fbfac-f09c-448d-91e3-11bc2f0fcf76','秋日郊居八首  其五','陸游','宋','宋诗','song-poetry','','[]','今年斟酌是豐年，社近兒童喜欲顛。',32,'全唐诗/poet.song.130000.json','["今年斟酌是豐年，社近兒童喜欲顛。", "半醉半醒村老子，家家門口掠神錢。"]'),
('2fe0d9e0-73f0-46ce-bc95-4e8b17709bad','秋日郊居八首  其六','陸游','宋','宋诗','song-poetry','','[]','魚鹹滿缶酒新篘，處處吳歌起壟頭。',32,'全唐诗/poet.song.130000.json','["魚鹹滿缶酒新篘，處處吳歌起壟頭。", "上客巳隨新雁到，晚禾猶待薄霜收。"]'),
('96727d72-4781-4568-92af-c20c3ce45fe9','秋日郊居八首  其七','陸游','宋','宋诗','song-poetry','','[]','兒童冬學閙比鄰，據案愚儒却自珍。',32,'全唐诗/poet.song.130000.json','["兒童冬學閙比鄰，據案愚儒却自珍。", "授罷村書閉門睡，終年不著面看人。"]'),
('3316b0d2-140a-4484-a89f-c25e124e3821','秋日郊居八首  其八','陸游','宋','宋诗','song-poetry','','[]','兩翁兒女舊論姻，酒擔羊腔喜色新。',32,'全唐诗/poet.song.130000.json','["兩翁兒女舊論姻，酒擔羊腔喜色新。", "不遣交情隔生死，固應世好等朱陳。"]'),
('ff795da5-8999-463b-a914-85d05faf6cf1','七月十七日大雨極涼','陸游','宋','宋诗','song-poetry','','[]','吳中七月熱未己，渴烏呀呀井無水。',96,'全唐诗/poet.song.130000.json','["吳中七月熱未己，渴烏呀呀井無水。", "炎官護前不少斂，樹頭敢望秋風起。", "天公老手亦豈難，雨來黑雲如壊山。", "瓦溝淙淙萬銀竹，變化只在須臾間。", "老夫挑燈北窗下，山童夜歸泥過踝。", "草根促織有底忙，縑衣未贖還慨慷。"]'),
('1a714c58-8006-4230-a31b-154f5f919fdd','雨中作','陸游','宋','宋诗','song-poetry','','[]','山雨時時急，谿流日日添。',48,'全唐诗/poet.song.130000.json','["山雨時時急，谿流日日添。", "濕苔緣暗壁，腐瓦落頽簷。", "老至那容却，狂來未易砭。", "泥深村路絕，烟樹出青帘。"]'),
('7db724ed-2505-4fb4-9b77-5c1d60fb5fc6','秋興三首  其一','陸游','宋','宋诗','song-poetry','','[]','天遣幽人儘放狂，醉眠無復客爲妨。',64,'全唐诗/poet.song.130000.json','["天遣幽人儘放狂，醉眠無復客爲妨。", "墨蛟飛下剡藤滑，蒼璧碾成官焙香。", "老境雖深身更健，清秋欲半日猶長。", "閉門莫道都無事，又了移花一段忙。"]'),
('5980817c-48f5-4cbc-bc81-c071e3d1d021','秋興三首  其二','陸游','宋','宋诗','song-poetry','','[]','蓬蒿門巷絕經過，清夜何人與晤歌。',64,'全唐诗/poet.song.130000.json','["蓬蒿門巷絕經過，清夜何人與晤歌。", "蟋蟀獨知秋令早，芭蕉正得雨聲多。", "傳家産業遺書富，玩世神通醉臉酡。", "如許癡頑君會否，一毫不遣損天和。"]'),
('af8777bc-132e-41c8-adf6-56a8f478ebb8','秋興三首  其三','陸游','宋','宋诗','song-poetry','','[]','老子雖貧未易量，風流猶在小茆堂。',64,'全唐诗/poet.song.130000.json','["老子雖貧未易量，風流猶在小茆堂。", "葡萄錦覆桐孫古，鸚鵡螺斟玉瀣香。", "千點荷聲先報雨，一林竹影剩分涼。", "秋來便有欣然處，新種蓴絲己滿塘。"]'),
('59720a8b-b042-43cc-a595-a09c7e6b3a5c','雨夜南堂獨坐','陸游','宋','宋诗','song-poetry','','[]','老夫眼暗牙齒疏，七十未滿六十餘。',64,'全唐诗/poet.song.130000.json','["老夫眼暗牙齒疏，七十未滿六十餘。", "故人欲盡誰與娛，獨坐黙誦小年書。", "北風日夜吹雨急，空村泥深屋茆濕。", "鳳凰覽德乃下集，可憐飛螢常熠熠。"]'),
('843b2374-b574-475f-aa47-72108111d564','夜不能寐復呼燈起坐戲作','陸游','宋','宋诗','song-poetry','','[]','吳中秋半暑未退，今歲雨多如許涼。',32,'全唐诗/poet.song.130000.json','["吳中秋半暑未退，今歲雨多如許涼。", "藥鼎熒熒伴孤寂，三更袖手聽啼螀。"]'),
('eb543c03-d500-423a-8732-709367155949','喜晴','陸游','宋','宋诗','song-poetry','','[]','久雨群蛙日夜號，樂哉霽色滿江郊。',64,'全唐诗/poet.song.130000.json','["久雨群蛙日夜號，樂哉霽色滿江郊。", "草書己悟屋漏壁，詩句免悲風卷茆。", "喚婦晴鳩鳴廢圃，歸林棲鶻補危巢。", "泥乾我亦思來客，未暇移書廣絕交。"]'),
('a0578c2d-774e-4d30-b7cd-1350b70f68bf','枕上','陸游','宋','宋诗','song-poetry','','[]','守書眼欲闇，投枕乃瞭然。',96,'全唐诗/poet.song.130000.json','["守書眼欲闇，投枕乃瞭然。", "兒曹戒曳履，相語翁正眠。", "豈知擁敗褐，炯如寒魚鰥。", "少時笑老人，其事今好還。", "蕭蕭雙白鬢，忽忽七十年。", "豈惟老態出，已覺衰病纒。", "白晝尚便静，況此清夜闌。", "妙處殆難名，睡與不睡間。"]'),
('a941103b-9d4e-4e43-ad67-ded7f0a2ba2d','新作南門','陸游','宋','宋诗','song-poetry','','[]','翦棘移門不費錢，好山無數碧巉然。',32,'全唐诗/poet.song.130000.json','["翦棘移門不費錢，好山無數碧巉然。", "病夫憒憒真堪笑，反衣狐裘三十年。"]'),
('182f2b7f-124c-49c5-9ab6-11f69c6c0807','寄成漢卿將軍','陸游','宋','宋诗','song-poetry','','[]','燕頷將軍萬里遊，谿山好處即遲留。',64,'全唐诗/poet.song.130000.json','["燕頷將軍萬里遊，谿山好處即遲留。", "頗聞南岳度殘夏，寧憶北平防盛秋。", "君巳飛騰丹換骨，我方衰病雪蒙頭。", "禪龕也有新勲業，百萬魔軍一戰收。"]'),
('ee1c1c3c-e18d-456e-b275-08470e9f5726','病卧','陸游','宋','宋诗','song-poetry','','[]','病卧東齋怕攬衣，年來真與世相違。',64,'全唐诗/poet.song.130000.json','["病卧東齋怕攬衣，年來真與世相違。", "横林蠧葉秋先覺，别浦驕雲暝不歸。", "歲月惟須付樽酒，江山竟是屬漁磯。", "鄰翁一夕成今古，愈信人生七十稀。"]'),
('34da8440-aea9-49a8-9744-6f8f03c947c8','晚晴','陸游','宋','宋诗','song-poetry','','[]','今年秋多陰，殊未決豐歉。',72,'全唐诗/poet.song.130000.json','["今年秋多陰，殊未決豐歉。", "時時雲一片，復作雨數點。", "晚來晴頗牢，天宇碧如染。", "微風過林梢，斜日在山崦。", "農家築場罷，竭作事收斂。", "貪睡吾可慚，齋扉晝長掩。"]'),
('051b47dd-fda5-42c2-8c50-f424e0be702b','秋雨初晴有感','陸游','宋','宋诗','song-poetry','','[]','炎曦赫赫尚餘威，冷雨蕭蕭故解圍。',64,'全唐诗/poet.song.130000.json','["炎曦赫赫尚餘威，冷雨蕭蕭故解圍。", "號野百蟲如自訴，辭柯萬葉竟安歸。", "芼羮菰米珍無價，上釣魴魚健欲飛。", "散吏何功霑一飽，高眠仍聽擣秋衣。"]'),
('8c2d1cff-f29f-4034-ae2e-c0f9cf59ef74','獨飲','陸游','宋','宋诗','song-poetry','','[]','怪怪奇奇不自懲，晚途猶復氣横膺。',32,'全唐诗/poet.song.130000.json','["怪怪奇奇不自懲，晚途猶復氣横膺。", "觥船那待清歌勸，酒到愁邊量自增。"]'),
('27e395c1-5748-46b8-bbdf-d4527a24aa9c','小築','陸游','宋','宋诗','song-poetry','','[]','小築湖邊避俗囂，幾年于此寓簞瓢。',64,'全唐诗/poet.song.130000.json','["小築湖邊避俗囂，幾年于此寓簞瓢。", "雖非隠士子午谷，寧愧詩人丁夘橋。", "羅雀門庭無俗駕，緣雲磴路有歸樵。", "詩情酒興常相屬，堪笑傍人說寂寥。"]'),
('861ac4ba-b006-45ab-978a-f9e7f9ce0c69','示兒','陸游','宋','宋诗','song-poetry','','[]','文能換骨餘無法，學但窮源自不疑。',32,'全唐诗/poet.song.130000.json','["文能換骨餘無法，學但窮源自不疑。", "齒豁頭童方悟此，乃翁見事可憐遲。"]'),
('2404cbbd-a59f-41e6-abf6-cda693eab667','新晴','陸游','宋','宋诗','song-poetry','','[]','積雨已凄冷，新晴還少和。',48,'全唐诗/poet.song.130000.json','["積雨已凄冷，新晴還少和。", "稼收平野濶，木落遠山多。", "土潤朝畦菜，機鳴夜擲梭。", "時清年歲好，吾敢嘆蹉跎。"]'),
('4e6ee590-e920-4a0c-80cd-1be6e61c391d','晨起坐南堂書觸目','陸游','宋','宋诗','song-poetry','','[]','林塘天與占深幽，一把茆輕萬户侯。',64,'全唐诗/poet.song.130000.json','["林塘天與占深幽，一把茆輕萬户侯。", "漠漠斷雲開復合，纎纎微雨落還收。", "奇峰角立千螺曉，遠水平鋪疋練秋。", "詩料滿前吾老矣，筆端無力固宜休。"]'),
('8a008236-def1-43b0-92a3-e27bc1085c53','壬子八月癸夘大風雨拔木飄瓦通夕不能寐','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我昔浮江坐貪快，六十幅蒲船尾挂。',160,'全唐诗/poet.song.130000.json','["我昔浮江坐貪快，六十幅蒲船尾挂。", "惡風吹到馬當祠，出沒蜿蜒舞澎湃。", "舟人失色急倒檣，共上蘆灣望祠拜。", "風雲晝晦性命憂，更復何心問薪菜。", "顛危僅免葬魚腹，至今常抱垂堂戒。", "豈知風雨有兹夕，屋破窗鳴紛百怪。", "直疑屋外即長江，九轉得生那可再。", "正襟黙坐徐自思，忠信固可當喪敗。", "鬼神雖惡技有窮，卷地破山真一噫。", "明朝倚杖看晴雲，兹夕驚心復何在。"]'),
('820dbefb-90a1-4b45-a231-5a8f5062ecd9','秋雨不止排悶','陸游','宋','宋诗','song-poetry','','[]','放翁愁坐茆齋裏，泥潦連村不得行。',64,'全唐诗/poet.song.130000.json','["放翁愁坐茆齋裏，泥潦連村不得行。", "夜夜濕星占雨候，時時老木送秋聲。", "小詩旋録兼行草，薄酒新篘任濁清。", "身世正如萍在水，略無根柢也能生。"]'),
('9d3927c9-3255-4128-801c-28f061dce937','用短','陸游','宋','宋诗','song-poetry','','[]','用短定非癡，愛閑真復奇。',48,'全唐诗/poet.song.130000.json','["用短定非癡，愛閑真復奇。", "飯香貧始覺，睡味老偏知。", "畦地閑栽藥，留僧静對棋。", "餘年猶有幾，捨此欲何之。"]'),
('dfcd890a-0e21-4b1e-8550-32374733cff9','覽鏡有感','陸游','宋','宋诗','song-poetry','','[]','齒如敗屐鬢成絲，七十之年敢自期。',64,'全唐诗/poet.song.130000.json','["齒如敗屐鬢成絲，七十之年敢自期。", "閱世久應書鬼録，強顔那復乞山資。", "緋衫蔭子踰初望，下澤還鄉負聖時。", "回首墮溝元有命，不須深計巧丸兒。"]'),
('040d2a57-49d9-474f-94db-32b96a82c410','哭徑山策老','陸游','宋','宋诗','song-poetry','','[]','岌岌龍門萬衲傾，翩翩隻履又西行。',64,'全唐诗/poet.song.130000.json','["岌岌龍門萬衲傾，翩翩隻履又西行。", "塵侵白拂繩床冷，露滴青松石塔成。", "遙想再來非四入，尚應相見話三生。", "放翁大欠修行力，未免人間愴别情。"]'),
('06f2a91c-bfb2-43fe-9cea-a5e7cb06b2a2','松風','陸游','宋','宋诗','song-poetry','','[]','半嶺松風破睡時，起看山月倚笻枝。',32,'全唐诗/poet.song.130000.json','["半嶺松風破睡時，起看山月倚笻枝。", "縱横滿地髯龍影，盡是當年手自移。"]'),
('96d5faad-4713-4ace-9e25-5264472eb7f5','醉歌','陸游','宋','宋诗','song-poetry','','[]','佛如優曇時一出，老姥何爲憎見佛。',96,'全唐诗/poet.song.130000.json','["佛如優曇時一出，老姥何爲憎見佛。", "山從古在天地間，愚公可笑欲移山。", "火其書，廬其居，佛亦何曾可掃除。", "子有孫，孫有子，山竟嵳峨汝何喜。", "床頭有酒敵霜風，詩成老氣尚如虹。", "八萬四千顛倒想，與君同付醉眠中。"]'),
('88154631-b09c-4d0c-b7ea-fecf1dc28817','秋夜讀書有感','陸游','宋','宋诗','song-poetry','','[]','鬢毛焦禿齒牙疏，老病燈前未廢書。',64,'全唐诗/poet.song.130000.json','["鬢毛焦禿齒牙疏，老病燈前未廢書。", "卷裏光陰能屬我，人間聲利久忘渠。", "窮山藏拙猶嫌淺，糲飯支羸不願餘。", "雨露安能澤枯朽，故人枉是費吹嘘。"]'),
('d6e28c1d-e02e-4f80-b60f-60c2d626ecf4','瀘州亂','陸游','宋','宋诗','song-poetry','','[]','高寺坡前火照天，南定樓下血成川。',96,'全唐诗/poet.song.130000.json','["高寺坡前火照天，南定樓下血成川。", "從事横屍太守死，處處巷陌森戈鋋。", "此州雄跨西南邊，平安烽火夜夜傳。", "豈知癰疽潰在內，漫倚築城如鐵堅。", "從來守邊要人望，縱有奸謀氣先喪。", "即今死者端爲誰，姓名至死無人知。"]'),
('2fd01c8a-f7db-42c5-a6ed-46861a546bc5','東鄰築舍與兒輩訪之爲小留','陸游','宋','宋诗','song-poetry','','[]','甲第潭潭莫羨渠，窮人從昔愛吾廬。',64,'全唐诗/poet.song.130000.json','["甲第潭潭莫羨渠，窮人從昔愛吾廬。", "茆茨新潔嗟何欠，鄰里追隨故不疏。", "甕醤芬香盤早兔，臼韲珍釅膾寒魚。", "年豐日有攜尊興，家乘從今不一書。"]'),
('8575a2c1-29f0-459f-a827-718a71ed5cc0','夜坐','陸游','宋','宋诗','song-poetry','','[]','瘦骨倚蒲團，燈前影自看。',48,'全唐诗/poet.song.130000.json','["瘦骨倚蒲團，燈前影自看。", "心清便獨夜，酒盡怯新寒。", "病虎減精采，饑鴻摧羽翰。", "晚途堪笑閔，猶擬乞祠官。"]'),
('14eb4d72-449f-4802-9c02-9c2c50b7a385','西鄰亦葺所居復與兒曹過之','陸游','宋','宋诗','song-poetry','','[]','竹屋茆檐烟火微，長歌相應負禾歸。',64,'全唐诗/poet.song.130000.json','["竹屋茆檐烟火微，長歌相應負禾歸。", "窮居幸可支朝夕，世事何曾有是非。", "新茁畦蔬經宿雨，半開籬槿弄斜暉。", "老翁略與吾年等，眷眷遮留莫苦違。"]'),
('7f9a0aee-2e5b-4f88-82d6-ec0ea85b3a21','有術士過門謂余壽及九十','陸游','宋','宋诗','song-poetry','','[]','形骸鶴瘦復松枯，況是新霜滿鬢鬚。',64,'全唐诗/poet.song.130000.json','["形骸鶴瘦復松枯，況是新霜滿鬢鬚。", "醉似在家狂道士，愚于識字老耕夫。", "敢言萬里封侯事，但問縱文入口無。", "許我年如伏生比，逢時猶解誦唐虞。"]'),
('f5056034-d720-4b7b-9f28-8b4abbe349b6','晚眺','陸游','宋','宋诗','song-poetry','','[]','秋晚閑愁抵酒濃，試尋高處倚枯笻。',64,'全唐诗/poet.song.130000.json','["秋晚閑愁抵酒濃，試尋高處倚枯笻。", "雲歸時带雨數點，木落又添山一峰。", "鳴雁沙邊驚客櫓，行僧烟際認樓鐘。", "箇中詩思來無盡，十手傳抄畏不供。"]'),
('5f689715-c042-4127-8895-01b64f54b702','秋日焚香讀書戲作','陸游','宋','宋诗','song-poetry','','[]','世事無端自糾紛，放翁隠几對爐熏。',64,'全唐诗/poet.song.130000.json','["世事無端自糾紛，放翁隠几對爐熏。", "好官何恨輸玄保，奇字猶須屬子雲。", "婆律一銖能敵國，水沈盈握有兼斤。", "閉門莫怪常終日，不是高人不遣聞。"]'),
('55baa34b-5162-40bd-8684-27503b869be0','九月一日夜讀詩稿有感走筆作歌','陸游','宋','宋诗','song-poetry','','[]','我昔學詩未有得，殘餘未免從人乞。',160,'全唐诗/poet.song.130000.json','["我昔學詩未有得，殘餘未免從人乞。", "力孱氣餒心自知，妄取虚名有慚色。", "四十從戎駐南鄭，酣宴軍中夜連日。", "打毬築場一千步，閱馬列廄三萬疋。", "華燈縱博聲滿樓，寶釵豔舞光照席。", "琵琶絃急冰雹亂，羯鼓手勻風雨疾。", "詩家三昧忽見前，屈賈在眼元曆曆。", "天機雲錦用在我，剪裁妙處非刀尺。", "世間才傑固不乏，秋毫未合天地隔。", "放翁老死何足論，廣陵散絕還堪惜。"]'),
('ea8a0f23-7175-4284-b2f8-c007cb7f1f56','上書乞再任沖佑','陸游','宋','宋诗','song-poetry','','[]','虬枝六尺藤，方屋九寸帽。',96,'全唐诗/poet.song.130000.json','["虬枝六尺藤，方屋九寸帽。", "人間無處著，山水歸寄傲。", "耳中聞淵明，自我髮未燥。", "高標不可揖，七十忽已到。", "明窗置經龕，奥室養丹竈。", "雖云迫遲暮，要足平昔好。", "悠然萬念空，快若河卷掃。", "寄聲幔亭雲，行拜散人號。"]'),
('460da6b0-769f-456f-80da-16af439406f2','秋晚歲登戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','水落沙痕出，天高野氣嚴。',48,'全唐诗/poet.song.130000.json','["水落沙痕出，天高野氣嚴。", "餅香油乍壓，韲美韭新醃。", "裘褐風霜逼，衡茆醉夢兼。", "菊花香滿把，聊得擬陶潛。"]'),
('3b737557-91f8-49e2-926f-b8541ce2dc22','秋晚歲登戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','漫漫蕎鋪白，纍纍橘弄黄。',48,'全唐诗/poet.song.130000.json','["漫漫蕎鋪白，纍纍橘弄黄。", "未論癡腹飽，已覺醉魂香。", "曳杖行歌裏，抛書倦枕傍。", "軒車雖已矣，終愧食官倉。"]'),
('40b81d99-d674-4046-8e6a-e0c9d159fe0f','舟中望禹祠蘭亭諸山','陸游','宋','宋诗','song-poetry','','[]','櫓枝謳軋出烟津，醉倚船篷岸幅巾。',64,'全唐诗/poet.song.130000.json','["櫓枝謳軋出烟津，醉倚船篷岸幅巾。", "禹穴探書慚舊學，塗山執玉記前身。", "雲低野澤號新雁，露濕芳洲老白蘋。", "逸少亡來欲千載，眼中髣髴見清真。"]'),
('b2ba3133-e180-4033-bd5e-5b9723d2d8ae','夜觀嚴光祠碑有感','陸游','宋','宋诗','song-poetry','','[]','我昔過釣臺，峭石插江渌。',96,'全唐诗/poet.song.130000.json','["我昔過釣臺，峭石插江渌。", "登堂拜嚴子，挹水薦秋菊。", "君看此眉宇，何地著榮辱。", "雒陽逢故人，醉脚加其腹。", "書生常事爾，乃復駭世俗。", "正令爲少留，要非昔文叔。", "平生陋范曄，瑣瑣何足録。", "安得太史公，妙語寫高躅。"]'),
('ffd13c1b-42e8-44ab-86fb-d2435c29f1e3','閑趣','陸游','宋','宋诗','song-poetry','','[]','濯罷銅駞陌上塵，此生長作水雲人。',64,'全唐诗/poet.song.130000.json','["濯罷銅駞陌上塵，此生長作水雲人。", "更貧家業猶供酒，未死年光盡屬身。", "閉户棋聲聞腷膊，卷簾山色對嶙峋。", "貴公漫說林間事，東路何人岸角巾。"]'),
('0585705f-daef-42d3-8312-567d1b074fea','壬子九日登山小酌','陸游','宋','宋诗','song-poetry','','[]','老懷多感驚佳節，病骨宜寒喜薄霜。',64,'全唐诗/poet.song.130000.json','["老懷多感驚佳節，病骨宜寒喜薄霜。", "玉膾韲中橙尚綠，彩猫餻上菊花黄。", "幾年虛負登高興，何許重尋落帽狂。", "淺酌易醒歸薄暮，又成支枕獨焚香。"]'),
('4be16009-8fa6-4a20-87af-091fc22e179d','舍北望水鄉風物戲作絕句','陸游','宋','宋诗','song-poetry','','[]','西風沙際矯輕鷗，落日橋邉繫釣舟。',32,'全唐诗/poet.song.130000.json','["西風沙際矯輕鷗，落日橋邉繫釣舟。", "乞與畫工團扇本，青林紅樹一川秋。"]'),
('7065da84-d7b6-4c1e-b3f2-51658ec53e1e','新黏竹隔作暖閣','陸游','宋','宋诗','song-poetry','','[]','骨相元作臞儒酸，況復疾豎乘衰殘。',96,'全唐诗/poet.song.130000.json','["骨相元作臞儒酸，況復疾豎乘衰殘。", "鵓姑聲急雨方作，烏桕葉丹天已寒。", "封姨青女交作戹，竹君禇生却憐客。", "小兒但喜夜爐紅，老夫更愛晨窗白。", "蝸牛負廬亦自容，是豈不足支窮冬。", "已勝展鉢三椽下，莫羨苴茆萬户封。"]'),
('f402b8db-1dd9-49a0-86df-5867345ea230','禹跡寺南有沈氏小園四十年前嘗題小闋壁間偶復一到而園已易主刻小闋于石讀之悵然','陸游','宋','宋诗','song-poetry','','[]','楓葉初丹槲葉黄，河陽愁鬢怯新霜。',64,'全唐诗/poet.song.130000.json','["楓葉初丹槲葉黄，河陽愁鬢怯新霜。", "林亭感舊空回首，泉路憑誰說斷腸。", "壊壁醉題塵漠漠，斷雲幽夢事茫茫。", "年來妄念消除盡，回向禪龕一炷香。"]'),
('bfd60510-e0c7-4c75-a789-822e4d482c68','贈鏡中隠者','陸游','宋','宋诗','song-poetry','','[]','小築林間避世紛，不妨野叟是知聞。',64,'全唐诗/poet.song.130000.json','["小築林間避世紛，不妨野叟是知聞。", "來遊喜有檝迎我，歸卧豈無雲贈君。", "得鹿夢回初了了，吠獒聲惡尚狺狺。", "從今雪夜頻相過，紙帳蒲團要策勲。"]'),
('c1521762-0e57-469b-bb1f-f6baac3ec78f','月夜作','陸游','宋','宋诗','song-poetry','','[]','江風吹微雲，長空散魚鱗。',120,'全唐诗/poet.song.130000.json','["江風吹微雲，長空散魚鱗。", "秋露洗明月，青山湧冰輪。", "我病適良已，欣然岸綸巾。", "索酒惱諸兒，哦詩驚四鄰。", "頗覺胸次空，未嘆白髮新。", "庭菊卧殘枝，奇香猶絕塵。", "園梅雖未花，瘦影已可人。", "方池湛奫淪，醜石立嶙峋。", "幸無千金費，亦足終吾身。", "樂哉何所恨，擊壤從堯民。"]'),
('6a92e4a9-063e-4b47-801b-56bdd662b6b4','記夢','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我夢結束遊何邦，小憩野館臨幽窗。',64,'全唐诗/poet.song.130000.json','["我夢結束遊何邦，小憩野館臨幽窗。", "千峰廬山錦繡谷，一水蜀道玻瓈江。", "春耕叱犢翁眉厖，曉汲負盎女髻雙。", "忽然夢斷已雞唱，擁衾坐待鄰鐘撞。"]'),
('4c1a10ef-9b4a-41bf-9878-2b877d0bff8d','感舊','陸游','宋','宋诗','song-poetry','','[]','當年書劍揖三公，談舌如雲氣吐虹。',64,'全唐诗/poet.song.130000.json','["當年書劍揖三公，談舌如雲氣吐虹。", "十丈戰塵孤壮志，一簪華髮醉秋風。", "夢回松漠榆關外，身老桑村麥野中。", "奇士久埋巴硤骨，燈前慷慨與誰同。"]'),
('00051dfb-3501-4f52-bb11-37b99c377ba7','小園','陸游','宋','宋诗','song-poetry','','[]','窄窄柴門短短籬，山家隨分有園池。',64,'全唐诗/poet.song.130000.json','["窄窄柴門短短籬，山家隨分有園池。", "客因問字來攜酒，僧趁分題就賦詩。", "晨露每看花藟坼，夕陽頻見樹陰移。", "拂衣司諫猶忙在，此趣淵明却少知。"]'),
('90bea713-2705-4669-a803-effce86dcfd7','初冬','陸游','宋','宋诗','song-poetry','','[]','已罷彈冠欲挂冠，一庵天遣養衰殘。',64,'全唐诗/poet.song.130000.json','["已罷彈冠欲挂冠，一庵天遣養衰殘。", "雨荒園菊枝枝瘦，霜染江楓葉葉丹。", "羮釡带鱗烹白小，蓬門和蔓繫黄團。", "夕陽更動閑遊興，十月吳中未苦寒。"]'),
('9d55c905-ab7e-42d4-b666-73fdb91a49d0','閑中樂事二首  其一','陸游','宋','宋诗','song-poetry','','[]','轉老轉迂疏，胸中一物無。',48,'全唐诗/poet.song.130000.json','["轉老轉迂疏，胸中一物無。", "放言誇酒聖，著論笑錢愚。", "掃地收松粉，全巢買鶴雛。", "登臨未應倦，天給短笻扶。"]'),
('ecc9c873-dc6c-4a3d-a66b-78000408b177','閑中樂事二首  其二','陸游','宋','宋诗','song-poetry','','[]','得喪略相當，幽居氣味長。',48,'全唐诗/poet.song.130000.json','["得喪略相當，幽居氣味長。", "五窮雖偃蹇，二豎已奔忙。", "出甑桃花輭，傾瓢竹葉香。", "語君真富貴，不是傲羲皇。"]'),
('0a1a58b9-6fbf-4606-998d-f94590911383','小舟','陸游','宋','宋诗','song-poetry','','[]','小舟無定處，隨意泊江村。',48,'全唐诗/poet.song.130000.json','["小舟無定處，隨意泊江村。", "雲氣分山疊，沙汀蹙浪痕。", "宦途危虎尾，閑味美熊蹯。", "高詠淵明句，吾將起九原。"]'),
('19159b72-6806-4219-9ec6-a140ac60caad','九月二十三夜小兒方讀書而油盡口占此詩示之','陸游','宋','宋诗','song-poetry','','[]','徹骨貧來累始輕，孤村月上正三更。',64,'全唐诗/poet.song.130000.json','["徹骨貧來累始輕，孤村月上正三更。", "汝因油盡眠差早，我亦尊空醉不成。", "南陌金羈良自苦，北邙麟冡半無名。", "書生事業期千載，得喪從來未易評。"]'),
('1b2f9973-1ac7-4a10-b302-730e9f5e5d1b','今年立冬後菊方盛開小飲','陸游','宋','宋诗','song-poetry','','[]','胡床移就菊花畦，飲具酸寒手自攜。',64,'全唐诗/poet.song.130000.json','["胡床移就菊花畦，飲具酸寒手自攜。", "野實似丹仍似漆，村醪如蜜復如韲。", "傳芳那解烹羊脚，破戒猶慚擘蠏臍。", "一醉又驅黄犢出，冬晴正要飽畊犂。"]'),
('d39c4df1-d0f7-4ff2-9bd8-ac8d4e68d504','行飯暮歸','陸游','宋','宋诗','song-poetry','','[]','宿疾去如掃，出門芒屨輕。',48,'全唐诗/poet.song.130000.json','["宿疾去如掃，出門芒屨輕。", "菊叢寒蝶閙，楓葉夕陽明。", "結陣看鴉集，衘衣喜犬迎。", "踟蹰搔白首，詩句入經營。"]'),
('9f847096-f746-4d64-a147-59c556c1d93f','晝眠','陸游','宋','宋诗','song-poetry','','[]','困睫瞢騰老孝先，粗氈布被早霜天。',32,'全唐诗/poet.song.130000.json','["困睫瞢騰老孝先，粗氈布被早霜天。", "珥貂碧落應無分，且向人間作睡仙。"]'),
('8f8fbd5a-9960-47e4-a2c3-dc6cbe8d9089','睡覺聞兒子讀書','陸游','宋','宋诗','song-poetry','','[]','夢回聞汝讀書聲，如聽簫韶奏九成。',64,'全唐诗/poet.song.130000.json','["夢回聞汝讀書聲，如聽簫韶奏九成。", "且要沈酣向文史，未須辛苦慕功名。", "人人本性初何欠，字字微言要力行。", "老病自憐難預此，夜窗常負短燈檠。"]'),
('635c5671-d87b-424f-a952-786c7055dd28','余得木杖于秦望山中今三十年矣隴蜀萬里未嘗相捨戲賦長句贈之','陸游','宋','宋诗','song-poetry','','[]','提攜到處覺身輕，楚澤秦關不計程。',64,'全唐诗/poet.song.130000.json','["提攜到處覺身輕，楚澤秦關不計程。", "只道維摩無侍者，誰知上座是同行。", "青鞵白拂真相稱，湘竹谿藤誤得名。", "珍重從今常倚壁，住庵吾欲過浮生。"]'),
('55d1d7f4-d85e-4efc-aa7f-3da7123cedaf','步至近村','陸游','宋','宋诗','song-poetry','','[]','藥物扶持疾漸平，布裘絮帽出柴荆。',64,'全唐诗/poet.song.130000.json','["藥物扶持疾漸平，布裘絮帽出柴荆。", "荒堤經雨多牛跡，村舍無人有碓聲。", "數蝶弄香寒菊晚，萬鴉回陣夕楓明。", "老翁隨意閑成句，不似劉侯要取名。"]'),
('e4752977-460d-4ed0-bd2f-8f180a28eb9c','五鼓不得眠起酌一杯復就枕','陸游','宋','宋诗','song-poetry','','[]','栖冷雞聲咽，窗深燭焰明。',48,'全唐诗/poet.song.130000.json','["栖冷雞聲咽，窗深燭焰明。", "流年容易過，華髮等閑生。", "濁挹連醅酒，香搓带葉橙。", "殘骸付螻蟻，汗簡更須名。"]'),
('acb2d813-7616-4a55-92d4-b09d4a68b15c','醉倒歌','陸游','宋','宋诗','song-poetry','','[]','曩時對酒不敢飲，側睨旁觀皆貝錦。',96,'全唐诗/poet.song.130000.json','["曩時對酒不敢飲，側睨旁觀皆貝錦。", "狂言欲發畏客傳，一笑未成憂禍稔。", "如今醉倒官道邊，插花不怕顛狂甚。", "行人喚起更嵬昻，牧豎扶歸猶踔踸。", "始知人生元自樂，誤計作官常懍懍。", "秋毫得喪何足論，萬古興亡一酣枕。"]'),
('71b62414-a6cd-4448-938f-b04c55e2bc2a','冬夜','陸游','宋','宋诗','song-poetry','','[]','新醅引睡睡味濃，有如猩脣薦駞峰。',96,'全唐诗/poet.song.130000.json','["新醅引睡睡味濃，有如猩脣薦駞峰。", "屏深氊暖衾裯重，鼻端雷起驚兒童。", "床頭蘭釭綴玉蟲，雙瓶湯熱爐正紅。", "夢回起坐夜未中，憑几困睫猶瞢瞢。", "霜風凋盡玉井桐，月落翠霧棲房櫳。", "一杯甖粟蠻奴供，莊周蝴蝶兩俱空。"]'),
('9621b983-ac28-4da5-9683-fe6a78e1be61','黙坐','陸游','宋','宋诗','song-poetry','','[]','巧說安能敵拙修，焚香黙坐一窗幽。',64,'全唐诗/poet.song.130000.json','["巧說安能敵拙修，焚香黙坐一窗幽。", "煌煌炎火常下照，浩浩黄河方逆流。", "氣住神仙端可學，心虚造物本同遊。", "絕知此事不相負，荆棘剪除梨栗秋。"]'),
('649d45c2-ff55-42b4-a301-01dca63f7d1b','日暮','陸游','宋','宋诗','song-poetry','','[]','淅淅風吹葉，凄凄雨作泥。',48,'全唐诗/poet.song.130000.json','["淅淅風吹葉，凄凄雨作泥。", "鵲寒猶遶樹，雞晚自歸棲。", "老病心知有，榮枯理本齊。", "端居嫌太懶，拾瓦傍蔬畦。"]'),
('cbcd7151-1387-4f54-a050-fb1bb588ba13','遣興','陸游','宋','宋诗','song-poetry','','[]','勲業如今莫繫懷，開單日日學僧齋。',64,'全唐诗/poet.song.130000.json','["勲業如今莫繫懷，開單日日學僧齋。", "讒深只有天堪問，憂極渾無地可埋。", "看鏡已成雙白鬢，登山猶費幾青鞵。", "晚來詩興誰能那，雀噪空囷葉擁堦。"]'),
('33949049-ab13-459f-aedb-6c9ce1ff2f0d','泛舟','陸游','宋','宋诗','song-poetry','','[]','去去泛輕舠，飄然興自豪。',48,'全唐诗/poet.song.130000.json','["去去泛輕舠，飄然興自豪。", "葉凋山寺出，溪瘦石橋高。", "草徑牛羊下，烟村鸛鶴號。", "還家一杯酒，未畏暮風饕。"]'),
('b9d1cb0f-2213-4012-a4da-b287f90a26dc','夜讀范至能攬轡録言中原父老見使者多揮涕感其事作絕句','陸游','宋','宋诗','song-poetry','','[]','公卿有黨排宗澤，帷幄無人用岳飛。',32,'全唐诗/poet.song.130000.json','["公卿有黨排宗澤，帷幄無人用岳飛。", "遺老不應知此恨，亦逢漢節解沾衣。"]'),
('9c4d2455-fff6-4a01-96e3-6039d5abfa72','初冬掃東山之麓置數石於喬松巨竹間以眺西山甚自適也','陸游','宋','宋诗','song-poetry','','[]','護霜天氣半晴陰，小嶺蒼寒蘚徑深。',64,'全唐诗/poet.song.130000.json','["護霜天氣半晴陰，小嶺蒼寒蘚徑深。", "翠靄欲成孤鳳舞，青松先作老龍吟。", "漁歌浦口生高興，騎吹邊頭負壮心。", "兒報東村早梅發，杖藜與汝共幽尋。"]'),
('a6a25774-712a-41b1-9488-ad45ae662336','南堂脊記乃已三十年偶讀之悵然有感','陸游','宋','宋诗','song-poetry','','[]','一住三山三十載，交親漸覺眼前稀。',64,'全唐诗/poet.song.130000.json','["一住三山三十載，交親漸覺眼前稀。", "長松鬱鬱偃高蓋，新竹森森添舊圍。", "沙徑雨餘留鳥迹，柴門日落鎖烟扉。", "放翁正倚蒲團穏，遼海從渠萬事非。"]'),
('51f41072-5981-4a33-b6ad-d5c172e550ae','醉卧松下短歌','陸游','宋','宋诗','song-poetry','','[]','披鹿裘，枕白石，醉卧松陰當月夕。',64,'全唐诗/poet.song.130000.json','["披鹿裘，枕白石，醉卧松陰當月夕。", "寒藤夭矯學草書，天風蕭森入詩律。", "忽然夢上百尺顛，緑毛邂逅巢雲仙。", "相攜大笑咸陽市，俯仰塵世三千年。"]'),
('f65d4155-3bfb-41ae-b180-e933a76215d8','霜草','陸游','宋','宋诗','song-poetry','','[]','入冬已兩旬，澤國霜始霣。',72,'全唐诗/poet.song.130000.json','["入冬已兩旬，澤國霜始霣。", "可憐青青草，一夕生意盡。", "嗟予蒲柳姿，去日若飛隼。", "草衰有復榮，我髮寧再鬒。", "微官雖置散，束带終自憫。", "漸退用婦言，千載付一哂。"]'),
('ca70a10a-85dd-4db1-8b63-4c0ab35772d5','冬夜','陸游','宋','宋诗','song-poetry','','[]','百錢買菅席，錦茵亦何加。',72,'全唐诗/poet.song.130000.json','["百錢買菅席，錦茵亦何加。", "疋布縫粗裘，安用狐腋奢。", "昨者南山僧，松肪寄一車。", "可以照讀書，堅坐待朝霞。", "顧影爲發笑，山童雙髻丫。", "一掬琴高魚，聊用薦夜茶。"]'),
('12323f49-c11e-45d9-b063-e9972550cd9d','村東','陸游','宋','宋诗','song-poetry','','[]','村西行藥到村東，沙路溪流曲折通。',32,'全唐诗/poet.song.130000.json','["村西行藥到村東，沙路溪流曲折通。", "莫問梅花開早晚，杖藜到處即春風。"]'),
('bec695df-56b4-456b-811c-19d8919fdf0b','小園','陸游','宋','宋诗','song-poetry','','[]','新作小溪園，牽藤迮縛門。',48,'全唐诗/poet.song.130000.json','["新作小溪園，牽藤迮縛門。", "釣船横北渚，樵路接東村。", "静坐依林樾，慵眠傍竹根。", "還家日已夕，棲雀閙黄昏。"]'),
('3a3966f0-dcbf-4251-a0af-628f1d4ffafa','書適二首  其一','陸游','宋','宋诗','song-poetry','','[]','老翁垂七十，其實似童兒。',48,'全唐诗/poet.song.130000.json','["老翁垂七十，其實似童兒。", "山果啼呼覓，鄉儺喜笑隨。", "群嬉累瓦塔，獨立照盆池。", "更挾殘書讀，渾如上學時。"]'),
('caf4ace3-0a22-494f-baf8-fb04eb290278','書適二首  其二','陸游','宋','宋诗','song-poetry','','[]','家食身無役，耆年力未衰。',48,'全唐诗/poet.song.130000.json','["家食身無役，耆年力未衰。", "寓歡那待酒，隨意或成詩。", "窮達元非我，寃親竟是誰。", "惟嗟見事晚，枉却鬢邊絲。"]'),
('409567c9-7d67-41f2-a140-b2a7f93fd2d8','狂夫','陸游','宋','宋诗','song-poetry','','[]','狂夫與世本難諧，醉傲王侯亦壮哉。',64,'全唐诗/poet.song.130000.json','["狂夫與世本難諧，醉傲王侯亦壮哉。", "奕奕方收巖際電，酣酣已起枕間雷。", "回天力在人終嘆，入月星來敵自摧。", "千載鬼雄皆國士，直令窮死未須哀。"]'),
('5f943a98-2ba1-4d54-8325-56e282ed4248','白髮','陸游','宋','宋诗','song-poetry','','[]','白髮今年一倍增，閉門養此老無能。',64,'全唐诗/poet.song.130000.json','["白髮今年一倍增，閉門養此老無能。", "牛羊被野霜天晚，禾稼連雲歲事登。", "未午舂炊餘脱粟，乍寒包裹有粗繒。", "自憐未廢詩書業，父子蓬窗共一燈。"]'),
('ba5ed41f-a474-4fed-8807-3a2862c982c8','檢舊詩偶見在蜀日江瀆池醉歸之篇悵然有感','陸游','宋','宋诗','song-poetry','','[]','江瀆池頭爛醉歸，青旗日晚插城扉。',64,'全唐诗/poet.song.130000.json','["江瀆池頭爛醉歸，青旗日晚插城扉。", "正馳玉勒衝紅雨，又挾金丸伺翠衣。", "老境漸侵歡意盡，舊遊欲說故人稀。", "憑高三嘆君知否，倦鷁無風亦退飛。"]'),
('1b88fd6b-4fc2-4cde-ba54-faa747efa44b','十一月四日風雨大作二首  其一','陸游','宋','宋诗','song-poetry','','[]','風卷江湖雨闇村，四山聲作海濤翻。',32,'全唐诗/poet.song.130000.json','["風卷江湖雨闇村，四山聲作海濤翻。", "溪柴火輭蠻氊暖，我與狸奴不出門。"]'),
('c1a3f241-6cdd-41f9-a6c2-e4eb4a153c9e','十一月四日風雨大作二首  其二','陸游','宋','宋诗','song-poetry','','[]','僵卧孤村不自哀，尚思爲國戍輪臺。',32,'全唐诗/poet.song.130000.json','["僵卧孤村不自哀，尚思爲國戍輪臺。", "夜闌卧聴風吹雨，鐵馬冰河入夢來。"]'),
('2f1a4e1d-486c-4325-ab06-1189e022179d','冬日觀漁獵者','陸游','宋','宋诗','song-poetry','','[]','人間漁獵各相從，南陌東阡處處逢。',64,'全唐诗/poet.song.130000.json','["人間漁獵各相從，南陌東阡處處逢。", "繡羽觸機餘耿介，錦鱗出網尚噞喁。", "傍觀扶杖常移日，就買還家足御冬。", "更待風霜都過盡，却從春野看春農。"]'),
('979cf4c8-6a04-47a6-9c4d-32789d37a8d5','雨晴','陸游','宋','宋诗','song-poetry','','[]','山川炳煥似闢國，風雨退收如解嚴。',32,'全唐诗/poet.song.130000.json','["山川炳煥似闢國，風雨退收如解嚴。", "老子真成無一事，抱孫負日坐茆簷。"]'),
('2980f841-4b5a-4be6-9d4f-ec612a0f17f8','病起','陸游','宋','宋诗','song-poetry','','[]','少年射虎南山下，惡馬強弓看似無。',32,'全唐诗/poet.song.130000.json','["少年射虎南山下，惡馬強弓看似無。", "老病即今那可說，出門十步要人扶。"]'),
('6622eed4-4420-4769-9cd1-ee8bfd3a0d8a','奉祠','陸游','宋','宋诗','song-poetry','','[]','明窗松日供琴薦，小鼎山泉煮藥苗。',32,'全唐诗/poet.song.130000.json','["明窗松日供琴薦，小鼎山泉煮藥苗。", "乞得奉祠還自愧，猶将名姓到中朝。"]'),
('52ba874f-9203-4eca-ac62-594937c36f04','假寐見海山異甚作小詩記之','陸游','宋','宋诗','song-poetry','','[]','海如黛色深，浪作雪點濺。',48,'全唐诗/poet.song.130000.json','["海如黛色深，浪作雪點濺。", "數峰黄金山，巉絕出水面。", "此非想與因，了了目中見。", "何時真往遊，浮世付掣電。"]'),
('0120239c-a62d-4392-9d6a-aee0055bb213','松下縱筆四首  其一','陸游','宋','宋诗','song-poetry','','[]','自掃松陰寄醉眠，龍吟虎嘯滿霜天。',32,'全唐诗/poet.song.130000.json','["自掃松陰寄醉眠，龍吟虎嘯滿霜天。", "却思初到人間世，似是唐堯丙子年。"]'),
('cf8ef050-4434-4805-9d81-2d4ec7c2cee9','松下縱筆四首  其二','陸游','宋','宋诗','song-poetry','','[]','老不能閑莫笑予，五千言豈世間書。',32,'全唐诗/poet.song.130000.json','["老不能閑莫笑予，五千言豈世間書。", "青松折取當麈尾，爲子試談天地初。"]'),
('c5e3bb63-c0ad-451d-a106-0796c5d647ff','松下縱筆四首  其三','陸游','宋','宋诗','song-poetry','','[]','種玉餐芝術不傳，金丹下手更茫然。',32,'全唐诗/poet.song.130000.json','["種玉餐芝術不傳，金丹下手更茫然。", "陶公妙訣吾曾受，但聽松風自得仙。"]'),
('e98f94df-2068-426c-ab38-e5f790d652c8','松下縱筆四首  其四','陸游','宋','宋诗','song-poetry','','[]','髯龍夭矯欲飛去，百尺蒼藤羅絡之。',32,'全唐诗/poet.song.130000.json','["髯龍夭矯欲飛去，百尺蒼藤羅絡之。", "應笑此翁才不進，故將老氣起吾詩。"]'),
('35ec4b3e-1b47-46c9-bb81-10e0c802bdb6','拜勅口號二首  其一','陸游','宋','宋诗','song-poetry','','[]','黄紙如鴉字，今朝下九天。',48,'全唐诗/poet.song.130000.json','["黄紙如鴉字，今朝下九天。", "身居鏡湖曲，銜带武夷仙。", "日絕絲毫事，年請百萬錢。", "恭惟優老政，千古照青編。"]'),
('46c35846-bfe9-46bf-8e77-7830ed3335b8','拜勅口號二首  其二','陸游','宋','宋诗','song-poetry','','[]','扶病中庭拜，君恩抵海深。',48,'全唐诗/poet.song.130000.json','["扶病中庭拜，君恩抵海深。", "頓增新禄格，暫拂舊朝簪。", "心欲先營酒，兒言且贖琴。", "人生奉祠貴，喜色動山林。"]'),
('0f1c111e-8a04-40c7-a872-67f189dfc5de','閑居','陸游','宋','宋诗','song-poetry','','[]','土鐺茶七椀，瓦甑稷三升。',48,'全唐诗/poet.song.130000.json','["土鐺茶七椀，瓦甑稷三升。", "兀兀能言石，騰騰有髮僧。", "淨巾裁白㲲，拄杖采紅藤。", "尚喜冬來健，逢山得遍登。"]'),
('0fd304b5-80a3-4c53-a86f-feb90f125576','十一月十八日蒙恩再領沖佑鄰里來賀謝以長句','陸游','宋','宋诗','song-poetry','','[]','緑章封事徹虚皇，黄紙除書降野堂。',64,'全唐诗/poet.song.130000.json','["緑章封事徹虚皇，黄紙除書降野堂。", "海上春常探先到，壺中日已不勝長。", "冰衘再署仙班貴，鶴料重支玉粒香。", "便挂朝冠亦良易，金銅茶籠本相忘。"]'),
('11924484-ebf0-45af-8af9-dec424aa9576','題老學庵壁','陸游','宋','宋诗','song-poetry','','[]','此生生計愈蕭然，架竹苫茆只數椽。',64,'全唐诗/poet.song.130000.json','["此生生計愈蕭然，架竹苫茆只數椽。", "萬卷古今消永日，一窗昏曉送流年。", "太平民樂無愁嘆，衰老形枯少睡眠。", "喚得南村跛童子，煎茶掃地亦隨緣。"]'),
('1c67306c-1c2c-4269-a7a1-6d5fe5e92794','冬晴日得閑遊偶作','陸游','宋','宋诗','song-poetry','','[]','不用清歌素與蠻，閑愁已自解連環。',64,'全唐诗/poet.song.130000.json','["不用清歌素與蠻，閑愁已自解連環。", "閏年春近梅差早，澤國風和雪尚慳。", "詩思長橋蹇驢上，棋聲流水古松間。", "牋天有事君知否，正乞柴荆到死閑。"]'),
('c4b85f51-97b5-45bb-be39-41c7db4558c3','示元禮','陸游','宋','宋诗','song-poetry','','[]','燕居侍立出扶行，見汝成童我眼明。',32,'全唐诗/poet.song.130000.json','["燕居侍立出扶行，見汝成童我眼明。", "但使鄉閭稱善士，布衣未必愧公卿。"]'),
('69c7df6f-27e6-400b-9130-87d802568ba8','書巢冬夜待旦','陸游','宋','宋诗','song-poetry','','[]','掃葉擁堦寒犬行，編茆護柵老雞鳴。',64,'全唐诗/poet.song.130000.json','["掃葉擁堦寒犬行，編茆護柵老雞鳴。", "風霜漸逼歲時晚，形影相依燈火明。", "史策千年愧豪傑，關河萬里愴功名。", "固應死抱無窮恨，老病何由更請纓。"]'),
('56aded15-35f6-45ff-badd-eec152b2c0d8','醉後莊門望西南諸山','陸游','宋','宋诗','song-poetry','','[]','身是咸陽舊酒徒，龍鍾猶復泥村酤。',64,'全唐诗/poet.song.130000.json','["身是咸陽舊酒徒，龍鍾猶復泥村酤。", "百年略似夢長短，一醉且隨家有無。", "登覽未應慚脚力，功名正爾嘆頭顱。", "夕陽又凭闌干立，誰畫三山岸幘圖。"]'),
('a47f939f-8e8d-43b5-871d-cdd7f39d06af','著書','陸游','宋','宋诗','song-poetry','','[]','平生著書汗馬牛，一事不施今白頭。',64,'全唐诗/poet.song.130000.json','["平生著書汗馬牛，一事不施今白頭。", "河洛未清非我責，山林高卧復何求。", "愚公可笑金堆屋，老子唯須糟築邱。", "華表無人識歸鶴，烟波底處有馴鷗。"]'),
('91d3ed05-ee77-4eed-9c07-5424a0df0802','探梅','陸游','宋','宋诗','song-poetry','','[]','我遊東村衝暮烟，斷橋流水鳴濺濺。',128,'全唐诗/poet.song.130000.json','["我遊東村衝暮烟，斷橋流水鳴濺濺。", "欲尋梅花作一笑，數枝忽到拄杖邊。", "高標元合著山澤，絕豔豈復施丹鉛。", "定知曾授餐玉法，不爾恐是凌波仙。", "錦江賦詩忽萬里，蓬山把酒今三年。", "相逢風味宛如昨，人生何者非前緣。", "頗思取醉極清賞，杖頭幸有百許錢。", "但判插破烏紗帽，莫記吹落黄金船。"]'),
('10cabcda-e4b9-4b54-ba6f-55c7eca6cfb8','歲暮風雨二首  其一','陸游','宋','宋诗','song-poetry','','[]','驕風起海澨，浩蕩東北來。',96,'全唐诗/poet.song.130000.json','["驕風起海澨，浩蕩東北來。", "鐵騎掠陣過，秋濤觸山回。", "老夫北窗下，坐守寒爐灰。", "處世困憂患，萬事學低摧。", "便欲滅燈睡，門閉不敢開。", "並海固多風，汝孱良可哀。", "念昔少年日，從戎何壯哉。", "獨騎洮河馬，涉渭夜衘枚。"]'),
('62adc603-bfd5-4e34-904c-1b74dfa0488e','歲暮風雨二首  其二','陸游','宋','宋诗','song-poetry','','[]','一冬少雨雪，人意常昏昏。',96,'全唐诗/poet.song.130000.json','["一冬少雨雪，人意常昏昏。", "夜半有奇事，雨聲卷江村。", "陸子真老農，破屋依頽垣。", "扶持衰病身，收召譴逐魂。", "手烹牆陰薺，美若乳下豚。", "聽雨取一醉，不厭村酒渾。", "眼眚燈生暈，衣弊蝨可捫。", "父子幸相守，萬事何足論。"]'),
('95985342-1c0c-4d02-8a38-b64b427afacd','自夏秋匱甚慨然有感','陸游','宋','宋诗','song-poetry','','[]','萬卷縱横眼欲枯，老猶閉户誦唐虞。',64,'全唐诗/poet.song.130000.json','["萬卷縱横眼欲枯，老猶閉户誦唐虞。", "故人誰復訪生死，鄰父幸能通有無。", "雲子翻匙新稻飯，天吳坼繡舊衣襦。", "時平得掩松根骨，也勝王孫泣路隅。"]'),
('51de0800-d2db-4019-816d-b5bb854a61cb','題四仙像四首  其一','陸游','宋','宋诗','song-poetry','','[]','反虜鯨鯢世共讎，漢公勲業過伊周。',32,'全唐诗/poet.song.130000.json','["反虜鯨鯢世共讎，漢公勲業過伊周。", "市門灑泪塵埃裏，誰與朝廷植委裘。"]'),
('c309b18a-7633-4f92-adb4-d734aef37129','題四仙像四首  其二','陸游','宋','宋诗','song-poetry','','[]','世上年光東逝波，咸陽銅狄幾摩挲。',32,'全唐诗/poet.song.130000.json','["世上年光東逝波，咸陽銅狄幾摩挲。", "神仙不死成何事，只向秋風感慨多。"]'),
('ffae033a-668e-4abf-8281-5be8e94ab513','題四仙像四首  其三','陸游','宋','宋诗','song-poetry','','[]','曾看四嶽薦虞鰥，閱歲三千一瞬間。',32,'全唐诗/poet.song.130000.json','["曾看四嶽薦虞鰥，閱歲三千一瞬間。", "歸卧青山孤絕處，白驢常伴白雲閑。"]'),
('1c7ef830-314e-4ecb-9e34-5ddb1af08d3f','題四仙像四首  其四','陸游','宋','宋诗','song-poetry','','[]','蓮花峰下張超谷，此老何曾有死生。',32,'全唐诗/poet.song.130000.json','["蓮花峰下張超谷，此老何曾有死生。", "聞道清風明月夜，至今鼻息亂松聲。"]'),
('1e3478d5-4140-4ee2-a7a2-1cb13a8a5d05','自責','陸游','宋','宋诗','song-poetry','','[]','窮途敢恃舌猶存，小築城西十里村。',64,'全唐诗/poet.song.130000.json','["窮途敢恃舌猶存，小築城西十里村。", "未挂衣冠慚士節，免輸薪粲荷君恩。", "文章跌宕忘繩墨，學問荒唐失本原。", "仕宦一生成底事，子孫世世記吾言。"]'),
('5ff46590-6d25-449c-9a26-78675c66ddbd','自解','陸游','宋','宋诗','song-poetry','','[]','四十頭顱已可知，殘年至此復何爲。',64,'全唐诗/poet.song.130000.json','["四十頭顱已可知，殘年至此復何爲。", "著書不直一杯水，看鏡空添千縷絲。", "達宦獨驕儒作戲，後生速化吏爲師。", "有冠當挂無餘說，但恨衰翁見事遲。"]'),
('63eff181-2957-4179-95bc-835014636c67','午睡起消搖園中因登山麓薄暮乃歸','陸游','宋','宋诗','song-poetry','','[]','老病攻百骸，徽纆困束縛。',96,'全唐诗/poet.song.130000.json','["老病攻百骸，徽纆困束縛。", "頽然一孰睡，如獲萬金藥。", "窗明竹影亂，林暖鳥聲樂。", "灰深香欲上，火活湯正作。", "亳甌羞茗荈，銅洗供盥濯。", "整巾出庭户，曳杖曆巖壑。", "遙岑見木杪，細水齧籬脚。", "踟躇遂忘歸，清嘯送日落。"]'),
('fde6b9f5-afb6-4cf9-b76d-7b417cace510','群兒','陸游','宋','宋诗','song-poetry','','[]','野行遇群兒，呼笑運甓忙。',120,'全唐诗/poet.song.130000.json','["野行遇群兒，呼笑運甓忙。", "共爲小浮圖，嶙峋當道旁。", "蜆殻以注燈，椀足以焚香。", "須臾一鬨散，無益亦何傷。", "古來富貴人，峨冠登廟堂。", "謀謨一悖謬，縣宇失太康。", "坐令安業民，血喋而屍僵。", "傳呼一朝寵，遺患日月長。", "均爲兒戲爾，禍機孰深藏。", "我作群兒詩，特用砭世盲。"]'),
('9fefe912-a52c-4756-8ccb-d3cef0ab1670','久疾灼艾小愈晚出門外','陸游','宋','宋诗','song-poetry','','[]','老境侵凌病滿軀，火攻下策得枝梧。',64,'全唐诗/poet.song.130000.json','["老境侵凌病滿軀，火攻下策得枝梧。", "沽來村酒初判醉，叱去山童不遣扶。", "霜重木凋鴉可數，溪清魚見鸛相呼。", "興闌却掩齋扉卧，閑看青燈照藥爐。"]'),
('f2e60955-6189-4d50-91fb-0d9fa82ca7f8','夙興弄筆偶書','陸游','宋','宋诗','song-poetry','','[]','憂患熏心少睡眠，雞號窗白一欣然。',64,'全唐诗/poet.song.130000.json','["憂患熏心少睡眠，雞號窗白一欣然。", "道旁歲晚貂裘弊，燈下書成鐵硯穿。", "杜老慣聽兒索飯，鄭公何啻客無氈。", "春風不解嫌貧病，尚擬花前醉放顛。"]'),
('a73d115e-3061-486d-8dd7-6b84da716137','縱筆','陸游','宋','宋诗','song-poetry','','[]','山合水将窮，真宜著放翁。',48,'全唐诗/poet.song.130000.json','["山合水将窮，真宜著放翁。", "醉嫌天地迮，老覺歲時公。", "偃蹇松逃世，翩仙鶴駕風。", "舊交零落盡，一笑與誰同。"]'),
('8b7de1cc-e1d8-463d-a6b8-4861300b53da','冬晴閑步東村由故塘還舍作二首  其一','陸游','宋','宋诗','song-poetry','','[]','故園三徑可婆娑，遇興遵塗負杖歌。',64,'全唐诗/poet.song.130000.json','["故園三徑可婆娑，遇興遵塗負杖歌。", "霜重天寒山色淡，草枯野曠獵徒多。", "解刀尚可謀黄犢，揮帖無由致白鵝。", "自計長閑何所恨，一生心事在烟波。"]'),
('04b60f8b-b27c-4375-98db-d9d0d0fd20aa','冬晴閑步東村由故塘還舍作二首  其二','陸游','宋','宋诗','song-poetry','','[]','紅藤拄杖獨相羊，路遶東村小嶺傍。',64,'全唐诗/poet.song.130000.json','["紅藤拄杖獨相羊，路遶東村小嶺傍。", "水落枯萍黏蟹椵，雲間寒日上魚梁。", "洛陽二頃言良是，光範三書計本狂。", "曆盡危機識天意，要令閑健返耕桑。"]'),
('a98971b2-eb13-4fe8-9d66-264937459e0e','十二月八日步至西村','陸游','宋','宋诗','song-poetry','','[]','臘月風和意已春，時因散策過吾鄰。',64,'全唐诗/poet.song.130000.json','["臘月風和意已春，時因散策過吾鄰。", "草烟漠漠柴門裏，牛跡重重野水濱。", "多病所須唯藥物，差科未動是閑人。", "今朝佛粥更相餽，更覺江村節物新。"]'),
('58e1c72f-585b-4883-ae68-3591e9f6c667','夜聞湖中漁歌','陸游','宋','宋诗','song-poetry','','[]','夢回一燈翳復明，卧聞湖上漁歌聲。',128,'全唐诗/poet.song.130000.json','["夢回一燈翳復明，卧聞湖上漁歌聲。", "嗚嗚乍低忽更起，嫋嫋欲斷還微縈。", "初隨缺月墮烟浦，已和殘角吹江城。", "悲傷似擊漸離筑，忠憤如撫桓伊筝。", "放臣萬里憂國泪，戍客白首懷鄉情。", "峽猿失侣方獨宿，沙雁垂翅猶遐征。", "巴巫竹枝短亭晚，瀟湘欸乃孤舟横。", "世間此恨故相似，使我百感何由平。"]'),
('527f6b21-4f45-4c70-942f-cb1803a6f412','忽得京書有感','陸游','宋','宋诗','song-poetry','','[]','白髮蒼顔七十翁，朽株枯木略相同。',64,'全唐诗/poet.song.130000.json','["白髮蒼顔七十翁，朽株枯木略相同。", "如山儲藥難醫拙，齊斗堆金不換窮。", "昨夢已抛空劫外，殘年全付醉眠中。", "故人苦未知心事，一紙空煩寄斷鴻。"]'),
('8b9f34ca-044c-4268-a243-24751279b692','晚步門外書觸目','陸游','宋','宋诗','song-poetry','','[]','數椽茆屋鏡湖旁，喬木蒼烟一徑長。',64,'全唐诗/poet.song.130000.json','["數椽茆屋鏡湖旁，喬木蒼烟一徑長。", "酒賤過門多醉叟，天寒棲畝有餘糧。", "歌呼草市知人樂，簫鼓叢祠喜歲穰。", "只道老來詩思盡，未妨擊壤頌時康。"]'),
('c3e787b5-b16a-4141-a61a-48d5c14d6ac4','親舊書來多問近況以詩荅之','陸游','宋','宋诗','song-poetry','','[]','耐辱推頽百不能，居然老病住庵僧。',64,'全唐诗/poet.song.130000.json','["耐辱推頽百不能，居然老病住庵僧。", "流年速似一彈指，更事多於三折肱。", "庭樹影中聞夜汲，鄰機聲裏對寒燈。", "沈詩任筆俱忘盡，酒户新來却少增。"]'),
('08330185-a1b4-4b88-be1b-71f005a9768c','開書篋見韓无咎書有感','陸游','宋','宋诗','song-poetry','','[]','老覺人間萬事非，幽棲幸已脱塵鞿。',64,'全唐诗/poet.song.130000.json','["老覺人間萬事非，幽棲幸已脱塵鞿。", "殘年得飽不啻足，舊友半空誰與歸。", "開眼不妨成一夢，翦翎何至羨群飛。", "龍圖老子今安在，把卷燈前泪滿衣。"]'),
('312ade6f-b065-47f4-a06b-483ac4ad470c','夜大雪歌','陸游','宋','宋诗','song-poetry','','[]','朔風吹雪飛萬里，三更蔌蔌鳴窗紙。',132,'全唐诗/poet.song.130000.json','["朔風吹雪飛萬里，三更蔌蔌鳴窗紙。", "初疑天女下散花，復恐麻姑行擲米。", "異哉凍硯已生冰，信矣重衾如潑水。", "山中卧澗松竹折，庭前蔽地烏鳶死。", "昨日之燠殊昏昏，桃李欲坼春滿園。", "陰陽錯謬世或有，物窮則變古所言。", "雖云明年幸一麥，凍餒溝壑知誰存。", "嗚呼今夕之雪未足論，所憂明日𡾰嵼高塞門。"]'),
('027f8a3f-d798-496e-81a7-596ca6cc13a8','寄宇文成州','陸游','宋','宋诗','song-poetry','','[]','成州太守比何如，夢裏依然把臂初。',64,'全唐诗/poet.song.130000.json','["成州太守比何如，夢裏依然把臂初。", "復起卿當用卿法，長閑吾實愛吾廬。", "五湖風雨孤舟夜，萬里關山一紙書。", "正使兩翁長隔濶，子孫他日莫相疏。"]'),
('2719b56d-fc3d-4618-9eaa-6cb7a93b20a2','示子聿','陸游','宋','宋诗','song-poetry','','[]','我鑽故紙似癡蠅，汝復孳孳不少懲。',32,'全唐诗/poet.song.130000.json','["我鑽故紙似癡蠅，汝復孳孳不少懲。", "父子更兼師友分，夜深常共短檠燈。"]'),
('6ce987e6-959a-4c84-a7e7-68b54766997d','雪','陸游','宋','宋诗','song-poetry','','[]','平郊漫漫覺天低，況復寒雲結慘悽。',64,'全唐诗/poet.song.130000.json','["平郊漫漫覺天低，況復寒雲結慘悽。", "老子方驚飛蛺蝶，群兒已說聚狻猊。", "中宵鳶墮頻摧木，徹旦雞瘖重壓棲。", "只待新晴梅塢去，青鞵未怯踏春泥。"]'),
('21ed3638-f35a-4997-8ae3-f711ad4e81b8','夜坐','陸游','宋','宋诗','song-poetry','','[]','耿耿殘燈夜未央，負牆閑對篆盤香。',64,'全唐诗/poet.song.130000.json','["耿耿殘燈夜未央，負牆閑對篆盤香。", "風號東北河冰合，月落西南竹影長。", "孤鵲欲棲頻繞樹，寒龜無息穏搘床。", "頽然坐睡那知曉，推户朝曦已滿廊。"]'),
('fc0f4bc8-e1c1-440b-9eb4-fd7f32b4b248','春雨','陸游','宋','宋诗','song-poetry','','[]','午夜聽春雨，發生端及期。',48,'全唐诗/poet.song.130000.json','["午夜聽春雨，發生端及期。", "世憂殊未艾，天意固難知。", "士節承平日，人材南渡時。", "後生聞見狹，撫枕嘆吾衰。"]'),
('a10b9a5e-f9c3-4fa4-bbfb-9b0fd19759ee','夢與數客劇飲或請賦詩予已大醉縱筆書一絕覺而録之','陸游','宋','宋诗','song-poetry','','[]','高談雄辯憑陵酒，豪竹哀絲蹴蹋春。',32,'全唐诗/poet.song.130000.json','["高談雄辯憑陵酒，豪竹哀絲蹴蹋春。", "占斷名園排日醉，不教虚作太平人。"]'),
('8b320232-b919-4189-98b9-43d6816f9738','世事','陸游','宋','宋诗','song-poetry','','[]','世事說來猶可厭，宦情夢裏亦應無。',64,'全唐诗/poet.song.130000.json','["世事說來猶可厭，宦情夢裏亦應無。", "山林已結三生願，朝市誰非九折途。", "醉舞杯盤無藉在，狂吟風月不枝梧。", "何人今擅丹青藝，爲畫蘇門長嘯圖。"]'),
('0600513e-9927-440c-8c3c-84fb28af7892','二子','陸游','宋','宋诗','song-poetry','','[]','兩楹夢後少真儒，毁譽徒勞豈識渠。',64,'全唐诗/poet.song.130000.json','["兩楹夢後少真儒，毁譽徒勞豈識渠。", "孟子無功如管仲，揚雄有賦似相如。", "敬王事業知誰繼，準易工夫故不疏。", "孤學背時空絕嘆，白頭窮巷抱遺書。"]'),
('2d5b3683-de62-4292-8744-e85489868fcc','謝郭希吕送石洞酒','陸游','宋','宋诗','song-poetry','','[]','從事今朝真到齊，春和盎盎却秋凄。',64,'全唐诗/poet.song.130000.json','["從事今朝真到齊，春和盎盎却秋凄。", "色如夷甫玉麈尾，價敵茂陵金褭蹏。", "瑞露頗疑名太過，槖泉猶恨韵差低。", "山園雪後梅花動，一榼常須手自攜。"]'),
('855b3090-6c5a-4fc5-a3a9-cdc2cafa1736','飲酒','陸游','宋','宋诗','song-poetry','','[]','六十四民安在哉，千八百國俱烟埃。',128,'全唐诗/poet.song.130000.json','["六十四民安在哉，千八百國俱烟埃。", "世人一漚寄巨海，對酒不醉吁可哀。", "平生清狂今白首，芒屨布裘稱野叟。", "晨興窗几網蛛絲，石洞書來餉名酒。", "看月直到月無時，尋花直到花片飛。", "醉中往往花壓帽，鄰里聚看湖邊歸。", "先生兩耳不須洗，利名不到先生耳。", "狂歌起舞君勿嘲，青山白雲終醉死。"]'),
('2a2b8e9c-2954-4c6a-8cc1-0857e65f3ff2','無題','陸游','宋','宋诗','song-poetry','','[]','金鞭朱彈憶春遊，萬里橋東罨畫樓。',64,'全唐诗/poet.song.130000.json','["金鞭朱彈憶春遊，萬里橋東罨畫樓。", "夢倩曉風吹不去，書憑春雁寄無由。", "鏡中顔鬢今如此，幙下朋儔好在不。", "篋有吳牋三萬箇，擬將細字寫新愁。"]'),
('b6fd028b-7666-4d39-b83e-74999cb8b39d','雨雪兼旬有賦','陸游','宋','宋诗','song-poetry','','[]','冬温思雨雪，稍久已復厭。',72,'全唐诗/poet.song.130000.json','["冬温思雨雪，稍久已復厭。", "祁寒人怨咨，千載語猶驗。", "人心自無常，天命本不僭。", "積陰勢已極，浮雲會當斂。", "山花紅酣酣，溪水緑灩灩。", "短篷倘可具，與子東入剡。"]'),
('efd2a21e-56a5-417f-a8be-c2e8ddd162bc','北窗睡起','陸游','宋','宋诗','song-poetry','','[]','違物離人不計年，萬金難買北窗眠。',64,'全唐诗/poet.song.130000.json','["違物離人不計年，萬金難買北窗眠。", "高懷元在羲皇上，大事已明空劫前。", "樵路細盤雲外嶺，釣筒倒插水中天。", "此時消息君知否，千載巢由未足賢。"]'),
('31e2a6c9-d839-44ee-a295-1c82936b9de5','立春','陸游','宋','宋诗','song-poetry','','[]','紹煕又見四番春，春日春盤節物新。',64,'全唐诗/poet.song.130000.json','["紹煕又見四番春，春日春盤節物新。", "獨酌三杯愁對影，例添一歲老催人。", "菊芽冒土如爭出，柳色搖村已漸勻。", "身是蘭亭山下客，未容逸少擅清真。"]'),
('d0592813-3ea2-4110-a04f-d325672739f2','曉枕','陸游','宋','宋诗','song-poetry','','[]','殘漏鼕鼕急，明星磊磊高。',48,'全唐诗/poet.song.130000.json','["殘漏鼕鼕急，明星磊磊高。", "一從安枕卧，無復攬衣勞。", "熨斗生晨火，熏籠覆緼袍。", "一杯山藥酒，紅日滿亭皋。"]'),
('480f7a83-d29f-458d-be0d-ba65a50bebd1','落梅二首  其一','陸游','宋','宋诗','song-poetry','','[]','雪虐風饕愈凜然，花中氣節最高堅。',32,'全唐诗/poet.song.130000.json','["雪虐風饕愈凜然，花中氣節最高堅。", "過時自合飄零去，恥向東君更乞憐。"]'),
('c76225b1-ffab-4293-86f8-5c138482111f','落梅二首  其二','陸游','宋','宋诗','song-poetry','','[]','醉折殘梅一兩枝，不妨桃李自逢時。',32,'全唐诗/poet.song.130000.json','["醉折殘梅一兩枝，不妨桃李自逢時。", "向來冰雪嚴凝地，力斡春回竟是誰。"]'),
('7311ea07-0805-468b-a3a1-427a62453fcd','閑居無客所與度日筆硯紙墨而已戲作長句','陸游','宋','宋诗','song-poetry','','[]','水複山重客到稀，文房四士獨相依。',64,'全唐诗/poet.song.130000.json','["水複山重客到稀，文房四士獨相依。", "黄金那得與齊價，白首自應同告歸。", "韞玉面凹觀墨聚，浣花理膩覺豪飛。", "興闌却欲燒香睡，閑聽松聲晝掩扉。"]'),
('0f125cbc-acd3-43a7-bb5f-a9906f58311b','壬子除夕','陸游','宋','宋诗','song-poetry','','[]','前村後村燎火明，東家西家爆竹聲。',144,'全唐诗/poet.song.130000.json','["前村後村燎火明，東家西家爆竹聲。", "老逢新正幸強健，却視徂歲何崢嶸。", "兒時祝身願事主，談笑可使中原清。", "豈知一出踐憂患，斂縮豈復希功名。", "雪霜滿鬢覺死近，節物到眼空嘆驚。", "蠶官社公正暖熱，春盤儺鼓爭施行。", "蓬門車馬所不至，山僧野叟相逢迎。", "嗚呼吾曹見事晚，古俗實在蚩蚩氓。", "茆簷一笑語兒子，明當滿奉屠蘇觥。"]'),
('88249a7f-298e-4222-949c-b2c71f082bcd','癸丑正月二日二首  其一','陸游','宋','宋诗','song-poetry','','[]','朱顔不老畫中人，綠酒追歡夢裏身。',32,'全唐诗/poet.song.130000.json','["朱顔不老畫中人，綠酒追歡夢裏身。", "堪笑三山衰病叟，閉門寂寂過新春。"]'),
('7566c775-9d85-4055-89fb-745584dc1eaf','癸丑正月二日二首  其二','陸游','宋','宋诗','song-poetry','','[]','菊叢抽緑滿枯荄，繞舍梅花已遍開。',32,'全唐诗/poet.song.130000.json','["菊叢抽緑滿枯荄，繞舍梅花已遍開。", "須信今春春事早，江鄉開歲有奔雷。"]'),
('bb085d25-105c-4948-b49e-e3ed7a585f5e','避世行','陸游','宋','宋诗','song-poetry','','[]','君渴未嘗飲鴆羽，君饑未嘗食烏喙。',108,'全唐诗/poet.song.130000.json','["君渴未嘗飲鴆羽，君饑未嘗食烏喙。", "惟其知之審，取捨不待議。", "有眼看青天，對客實少味。", "有口啖松柏，火食太多事。", "作官蓄妻孥，陷穽安所避。", "刀鋸與鼎鑊，孰匪君自致。", "欲求人迹不到處，忘形麋鹿與俱逝。", "杳杳白雲青嶂間，千歲巢居常避世。"]'),
('190e80e6-0d37-47f5-afbb-a2dd37fe20f4','稽山農','陸游','宋','宋诗','song-poetry','','[]','華胥氏之國，可以卜吾居。',138,'全唐诗/poet.song.130000.json','["華胥氏之國，可以卜吾居。", "無懷氏之民，可以爲吾友。", "眼如巖電不看人，腹似鴟夷惟貯酒。", "周公禮樂寂不傳，司馬兵法亡亦久。", "賴有神農之學存至今，扶犂近可師野叟。", "粗繒大布以禦冬，黄粱黑黍身自舂。", "園畦剪韭勝肉美，社瓮撥醅如粥醲。", "安得天下常年豐，老死不見傳邊烽。", "利名畫斷莫挂口，子孫世作稽山農。"]'),
('0cd38bca-68e9-4ee0-93c0-d3e3a2786a85','牧牛兒','陸游','宋','宋诗','song-poetry','','[]','南村牧牛兒，赤脚踏牛立。',48,'全唐诗/poet.song.130000.json','["南村牧牛兒，赤脚踏牛立。", "衣穿江風冷，笠敗山雨急。", "長陂望若遠，隘巷忽相及。", "兒歸牛入欄，烟火茆簷濕。"]'),
('dd0ca98b-e7f2-4882-9023-a098c5846675','讀書未終卷而睡有感','陸游','宋','宋诗','song-poetry','','[]','暮年緣一懶，百事俱棄置。',96,'全唐诗/poet.song.130000.json','["暮年緣一懶，百事俱棄置。", "今遂懶到書，把卷輒坐睡。", "其餘懶則已，感此獨歔欷。", "念昔少壯時，日夜痛磨礪。", "誓言死爲期，身在敢暴棄。", "寜知未死前，殆欲負此志。", "顔回稱好學，揚雄乃識字。", "勉哉慕前修，自畫聖所諱。"]'),
('62dbecab-ce19-4064-937a-f1ae11757bfc','早春新晴','陸游','宋','宋诗','song-poetry','','[]','柳弄春柔拂小潭，山横霽色卷浮嵐。',64,'全唐诗/poet.song.130000.json','["柳弄春柔拂小潭，山横霽色卷浮嵐。", "飛揚旛脚擲東北，零落梅花餘二三。", "村店疏燈新賣酒，神祠疊鼓正祈蠶。", "幽人睡起東園去，芹茁萱芽又滿籃。"]'),
('a9d098f1-5a75-4135-9d36-2fa25e8023d8','枕上聞禽聲','陸游','宋','宋诗','song-poetry','','[]','屏掩輕寒酒半消，斷香殘夢兩無憀。',32,'全唐诗/poet.song.130000.json','["屏掩輕寒酒半消，斷香殘夢兩無憀。", "開年春意遽如許，破曉一聲婆餅焦。"]'),
('f9f852d4-2c03-45fc-b6a0-c06d0a05943b','感舊','陸游','宋','宋诗','song-poetry','','[]','憶從南鄭入成都，氣俗豪華海內無。',64,'全唐诗/poet.song.130000.json','["憶從南鄭入成都，氣俗豪華海內無。", "故苑燕開車載酒，名姬舞罷斗量珠。", "浣花江路青螭舫，槎柳毬場白雪駒。", "回首壯遊真昨夢，一竿風月老南湖。"]'),
('f266cf4a-5d9d-4209-bbc8-d7104de55159','夜雨三首  其一','陸游','宋','宋诗','song-poetry','','[]','澤國寒多雨，畸人夜少眠。',48,'全唐诗/poet.song.130000.json','["澤國寒多雨，畸人夜少眠。", "不緣酲作病，只合醉終年。", "庭草已爭茁，園梅空自憐。", "重雲不難抉，無劍倚青天。"]'),
('d9efe519-447e-49fb-ae9e-ad7caa7bb67f','夜雨三首  其二','陸游','宋','宋诗','song-poetry','','[]','寒雨連三夕，幽居只數椽。',48,'全唐诗/poet.song.130000.json','["寒雨連三夕，幽居只數椽。", "家貧輕過節，身老怯增年。", "日月悲歌裏，關山泪眼邊。", "梅花自開落，嘆息爲誰妍。"]'),
('9d434843-c57a-4065-accd-745718bdd55f','夜雨三首  其三','陸游','宋','宋诗','song-poetry','','[]','人日春猶淺，雞晨夜向闌。',48,'全唐诗/poet.song.130000.json','["人日春猶淺，雞晨夜向闌。", "殘缸燈暈小，單枕雨聲寒。", "難補皇天漏，空思后土乾。", "山家尊酒薄，懷抱若爲寛。"]'),
('135a8544-8862-42fc-9ae5-1a161c815e1e','初晴野步','陸游','宋','宋诗','song-poetry','','[]','入市路三义，緣山港半斜。',48,'全唐诗/poet.song.130000.json','["入市路三义，緣山港半斜。", "疏簾带殘雪，幽竇瀉湍沙。", "好鳥晴相語，芳蘭暖欲芽。", "病餘無脚力，隨處憩人家。"]');
